const stateNameToken = (value?: string | null) => (value ?? "").trim().toLowerCase().replace(/[^a-z]/g, "");
const stateNameAliasesByToken: Record<string, string> = {
  fct: "FCT Abuja",
  abuja: "FCT Abuja",
  fctabuja: "FCT Abuja",
  federalcapitalterritory: "FCT Abuja",
  federalcapitalterritoryabuja: "FCT Abuja",
  lagosisland: "Lagos",
  island: "Lagos",
  mainland: "Lagos",
  lagosmainland: "Lagos",
  lekki: "Lagos",
  ikeja: "Lagos",
  ajah: "Lagos",
  yaba: "Lagos",
  surulere: "Lagos",
  victoriaisland: "Lagos",
  vi: "Lagos",
  portharcourt: "Rivers",
  portharcourtrivers: "Rivers",
  ph: "Rivers",
  phc: "Rivers",
  calabar: "Cross River",
  uyo: "Akwa Ibom",
  ibadan: "Oyo",
  owerri: "Imo",
  benincity: "Edo",
  warri: "Delta",
  asaba: "Delta",
  ilorin: "Kwara",
  abeokuta: "Ogun",
  akure: "Ondo",
  osogbo: "Osun",
  oshogbo: "Osun",
  onitsha: "Anambra",
  awka: "Anambra"
};
const canonicalNigeriaStateByToken = new Map(nigeriaStates.map((state) => [stateNameToken(state), state]));

const normalizeStateName = (value?: string) => {
  const raw = (value ?? "").trim();
  const token = stateNameToken(raw);
  if (!token) return "";
  const stripStateSuffix = (candidate: string) => {
    let next = candidate;
    let previous = "";
    while (next !== previous) {
      previous = next;
      next = next.replace(/(state|hub|base|warehouse|depot|branch|office)$/g, "");
    }
    return next;
  };
  const candidates = Array.from(new Set([token, stripStateSuffix(token)])).filter(Boolean);
  for (const candidate of candidates) {
    const alias = stateNameAliasesByToken[candidate];
    if (alias) return alias;
    const canonical = canonicalNigeriaStateByToken.get(candidate);
    if (canonical) return canonical;
  }
  if (token.includes("federalcapital")) return "FCT Abuja";
  if (token.includes("portharcourt")) return "Rivers";
  if (token.includes("abuja")) return "FCT Abuja";
  const containedState = [...canonicalNigeriaStateByToken.entries()]
    .sort((a, b) => b[0].length - a[0].length)
    .find(([stateToken]) => token.startsWith(stateToken) || token.endsWith(stateToken));
  if (containedState) return containedState[1];
  return raw;
};

