const productBonusConfig = (product?: Product | null): ProductBonusConfig => product?.bonusConfig ?? defaultBonusConfig();
const makeSku = (name: string) => {
  const cleanParts = name
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 3)
    .map((part) => part.slice(0, 3).toUpperCase());
  return `${cleanParts.join("-") || "PRD"}-${Math.floor(100 + Math.random() * 900)}`;
};

const formatProductMoney = (amount: number, code: ProductCurrencyCode) =>
  new Intl.NumberFormat(productCurrencies[code].locale, {
    style: "currency",
    currency: productCurrencies[code].currency,
    maximumFractionDigits: 0
  }).format(amount || 0);
const formatFlexibleMoney = (amount: number, code?: string) => {
  const normalized = (code || "NGN").toUpperCase();
  if (normalized in productCurrencies) {
    return formatProductMoney(amount, normalized as ProductCurrencyCode);
  }
  try {
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: normalized,
      maximumFractionDigits: 0
    }).format(amount || 0);
  } catch {
    return `${normalized} ${Math.round(amount || 0).toLocaleString()}`;
  }
};

const remittanceVarianceReasons = [
  { value: "waybill_logistics", label: "Waybill / logistics fee" },
  { value: "extra_delivery_fee", label: "Extra delivery fee" },
  { value: "customer_paid_less", label: "Customer paid less / discount" },
  { value: "partial_cash", label: "Partial cash received" },
  { value: "agent_shortage", label: "Agent shortage / missing cash" },
  { value: "excess_cash", label: "Excess cash / overpayment" },
  { value: "customer_overpaid", label: "Customer overpaid" },
  { value: "repaid_shortage", label: "Repaid an earlier shortage" },
  { value: "rounding_extra", label: "Rounding / extra" },
  { value: "correction", label: "Correction / other" }
] as const;
// Short-cash explains MISSING cash; excess explains EXTRA cash — each picker shows only
// its own reasons (+ the shared "Correction / other"), never the other side's.
const SHORT_CASH_REASON_VALUES = new Set(["waybill_logistics", "extra_delivery_fee", "customer_paid_less", "partial_cash", "agent_shortage", "correction"]);
const EXCESS_CASH_REASON_VALUES = new Set(["excess_cash", "customer_overpaid", "repaid_shortage", "rounding_extra", "correction"]);
const remittanceShortCashReasons = remittanceVarianceReasons.filter((reason) => SHORT_CASH_REASON_VALUES.has(reason.value));
const remittanceExcessCashReasons = remittanceVarianceReasons.filter((reason) => EXCESS_CASH_REASON_VALUES.has(reason.value));
const remittanceVarianceReasonLabel = (value: string) =>
  remittanceVarianceReasons.find((reason) => reason.value === value)?.label ?? "";

const normalizeAgentState = (value?: string | null) => normalizeStateName(value ?? undefined);
const normalizeAgentCity = (value?: string | null) => (value ?? "").trim();

const agentPrimaryBaseState = (agent: Pick<DeliveryAgentRecord, "primaryBaseState" | "zone">) =>
  normalizeAgentState(agent.primaryBaseState) || normalizeAgentState(agent.zone);

const agentCoverageRows = (agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone">): DeliveryAgentCoverage[] => {
  const rows = Array.isArray(agent.coverage)
    ? agent.coverage
        .map((row) => ({
          ...row,
          state: normalizeAgentState(row.state),
          city: normalizeAgentCity(row.city),
          active: row.active !== false,
          priority: Number.isFinite(row.priority) ? row.priority : 100,
          slaDays: Number.isFinite(row.slaDays) ? row.slaDays : 1
        }))
        .filter((row) => row.state)
    : [];
  if (rows.length > 0) return rows;
  const fallback = agentPrimaryBaseState(agent);
  return fallback
    ? [{ state: fallback, city: "", coverageType: "local_delivery", priority: 100, active: true, slaDays: 1 }]
    : [];
};

const agentCoverageStates = (agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone">) =>
  Array.from(new Set(agentCoverageRows(agent).filter((row) => row.active !== false).map((row) => row.state))).sort((a, b) => a.localeCompare(b));

const agentCoverageSummary = (agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone">) => {
  const states = agentCoverageStates(agent);
  if (states.length === 0) return "No active coverage";
  if (states.length === 1) return states[0];
  return `${states[0]} +${states.length - 1} more`;
};

const agentCoverageLabel = (agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone">) => {
  const base = agentPrimaryBaseState(agent);
  const states = agentCoverageStates(agent);
  if (states.length === 0) return base || "No active coverage";
  if (states.length === 1 && states[0].toLowerCase() === base.toLowerCase()) return base || states[0];
  if (!base) return `Serves ${states.join(", ")}`;
  return `${base} base · serves ${states.join(", ")}`;
};

const agentCoverageCompactLabel = (agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone">) => {
  const base = agentPrimaryBaseState(agent);
  const summary = agentCoverageSummary(agent);
  if (!base) return summary;
  if (summary.toLowerCase() === base.toLowerCase()) return base;
  return `${base} base · ${summary}`;
};

const agentLocationRows = (agent?: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | null): DeliveryAgentLocation[] => {
  if (!agent) return [];
  const rows = Array.isArray(agent.locations)
    ? agent.locations
        .map((location) => ({
          ...location,
          name: (location.name ?? "").trim(),
          state: normalizeAgentState(location.state),
          city: normalizeAgentCity(location.city),
          active: location.active !== false,
          isPrimary: location.isPrimary === true,
          stock: Array.isArray(location.stock)
            ? location.stock.map((row) => ({
                productId: String(row.productId ?? ""),
                quantity: Number(row.quantity ?? 0),
                defective: Number(row.defective ?? 0),
                missing: Number(row.missing ?? 0)
              }))
            : []
        }))
        .filter((location) => location.state)
    : [];
  if (rows.length > 0) return rows;
  const fallbackState = agentPrimaryBaseState(agent);
  return fallbackState ? [{
    id: "",
    name: `${fallbackState} Hub`,
    state: fallbackState,
    city: "",
    active: true,
    isPrimary: true,
    address: agent.address ?? "",
    stock: []
  }] : [];
};

const primaryAgentLocation = (agent?: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | null) =>
  agentLocationRows(agent).find((location) => location.isPrimary) ?? agentLocationRows(agent)[0] ?? null;

const findAgentLocation = (agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null, locationId?: string | null) =>
  locationId ? agentLocationRows(agent).find((location) => location.id === locationId) ?? null : null;

const agentLocationLabel = (location?: Pick<DeliveryAgentLocation, "name" | "state" | "city" | "isPrimary"> | null) => {
  if (!location) return "";
  const state = normalizeAgentState(location.state);
  const city = normalizeAgentCity(location.city);
  if (location.name?.trim()) return city ? `${location.name} (${city}, ${state})` : location.name;
  return city ? `${city}, ${state}` : `${state}${location.isPrimary ? " Hub" : ""}`;
};

const agentLocationStockQuantity = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null,
  locationId: string | null | undefined,
  productId: string | null | undefined
) => {
  if (!locationId || !productId) return 0;
  const location = findAgentLocation(agent, locationId);
  if (!location) return 0;
  return location.stock.find((row) => row.productId === productId)?.quantity ?? 0;
};

const agentLocationStockRowsWithQuantity = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null,
  locationId: string | null | undefined
) => {
  if (!locationId) return [] as DeliveryAgentLocationStock[];
  const location = findAgentLocation(agent, locationId);
  if (!location) return [] as DeliveryAgentLocationStock[];
  return location.stock.filter((row) => Number(row.quantity ?? 0) > 0);
};

const activeAgentLocationRows = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null
) => {
  const rows = agentLocationRows(agent);
  const activeRows = rows.filter((location) => location.active !== false);
  return activeRows.length > 0 ? activeRows : rows;
};

const agentLocationProductStockQuantity = (
  location: Pick<DeliveryAgentLocation, "stock"> | null | undefined,
  productId: string | null | undefined
) => {
  if (!location || !productId) return 0;
  return location.stock.reduce((sum, row) => (
    row.productId === productId ? sum + Math.max(0, Number(row.quantity ?? 0)) : sum
  ), 0);
};

const locationHasPositiveStock = (location: Pick<DeliveryAgentLocation, "stock"> | null | undefined) =>
  Boolean(location?.stock.some((row) => Number(row.quantity ?? 0) > 0));

const reportableAgentLocations = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null
) => {
  const rows = activeAgentLocationRows(agent);
  const stockedRows = rows.filter((location) => locationHasPositiveStock(location));
  const primary = rows.find((location) => location.isPrimary) ?? rows[0] ?? null;
  if (stockedRows.length > 0) {
    if (!primary || stockedRows.some((location) => location.id === primary.id)) return stockedRows;
    return [primary, ...stockedRows];
  }
  return primary ? [primary] : [];
};

const agentCoversState = (
  agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone"> | undefined | null,
  state?: string | null
) => {
  const wantedState = normalizeAgentState(state);
  if (!wantedState || !agent) return false;
  return agentCoverageStates(agent).some((coveredState) => coveredState.toLowerCase() === wantedState.toLowerCase());
};

const preferredReconcileLocation = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null
) => agentLocationRows(agent).find((location) => (location.stock ?? []).some((row) => Number(row.quantity ?? 0) > 0))
  ?? primaryAgentLocation(agent);

const totalAgentProductStock = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null,
  productId: string | null | undefined
) => {
  if (!productId) return 0;
  return agentLocationRows(agent).reduce(
    (sum, location) => sum + Number(location.stock.find((row) => row.productId === productId)?.quantity ?? 0),
    0
  );
};

const agentLocationInventory = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address"> | undefined | null,
  products: Product[]
) =>
  agentLocationRows(agent).map((location) => {
    const items = location.stock
      .filter((row) => Number(row.quantity ?? 0) > 0 || Number(row.defective ?? 0) > 0 || Number(row.missing ?? 0) > 0)
      .map((row) => {
        const product = products.find((item) => item.id === row.productId);
        const pricing = product ? primaryPricing(product) : undefined;
        return {
          productId: row.productId,
          productName: product?.name ?? "Unknown product",
          quantity: Number(row.quantity ?? 0),
          defective: Number(row.defective ?? 0),
          missing: Number(row.missing ?? 0),
          value: Number(row.quantity ?? 0) * Number(pricing?.sellingPrice ?? 0),
          currency: pricing?.currency ?? "NGN"
        };
      })
      .sort((a, b) => b.quantity - a.quantity || a.productName.localeCompare(b.productName));

    return {
      ...location,
      items,
      totalUnits: items.reduce((sum, item) => sum + item.quantity, 0),
      totalDefective: items.reduce((sum, item) => sum + item.defective, 0),
      totalMissing: items.reduce((sum, item) => sum + item.missing, 0),
      totalValue: items.reduce((sum, item) => sum + item.value, 0)
    };
  });

const bestAgentFulfillmentLocationMatch = (
  agent: Pick<DeliveryAgentRecord, "locations" | "primaryBaseState" | "zone" | "address">,
  state?: string | null,
  city?: string | null,
  productId?: string | null
) => {
  const wantedState = normalizeAgentState(state).toLowerCase();
  const wantedCity = normalizeAgentCity(city).toLowerCase();
  const locations = activeAgentLocationRows(agent);
  if (locations.length === 0) return null;
  // STRICT STATE ROUTING — mirrors the backend resolveAgentLocationForOrder():
  // only hubs in the order's state are candidates. If the agent has no hub in
  // that state, return null (no out-of-state fallback) so the badge matches
  // what the backend will actually do.
  let candidates = locations;
  if (wantedState) {
    const stateHubs = locations.filter((location) => normalizeAgentState(location.state).toLowerCase() === wantedState);
    if (stateHubs.length === 0) return null;
    candidates = stateHubs;
  }
  const sorted = candidates.slice().sort((a, b) => {
    const aStock = agentLocationProductStockQuantity(a, productId);
    const bStock = agentLocationProductStockQuantity(b, productId);
    if ((aStock > 0 ? 1 : 0) !== (bStock > 0 ? 1 : 0)) return (bStock > 0 ? 1 : 0) - (aStock > 0 ? 1 : 0);
    if (aStock !== bStock) return bStock - aStock;
    if ((a.isPrimary ? 1 : 0) !== (b.isPrimary ? 1 : 0)) return (b.isPrimary ? 1 : 0) - (a.isPrimary ? 1 : 0);
    const aCityMatch = wantedCity && normalizeAgentCity(a.city).toLowerCase() === wantedCity ? 1 : 0;
    const bCityMatch = wantedCity && normalizeAgentCity(b.city).toLowerCase() === wantedCity ? 1 : 0;
    if (aCityMatch !== bCityMatch) return bCityMatch - aCityMatch;
    return agentLocationLabel(a).localeCompare(agentLocationLabel(b));
  });
  return sorted[0] ?? null;
};

const bestAgentLocationMatch = (
  agent: Pick<DeliveryAgentRecord, "locations" | "coverage" | "primaryBaseState" | "zone" | "address">,
  state?: string | null,
  city?: string | null,
  productId?: string | null
) => {
  const wantedState = normalizeAgentState(state).toLowerCase();
  const wantedCity = normalizeAgentCity(city).toLowerCase();
  const locations = agentLocationRows(agent).filter((location) => location.active !== false);
  if (locations.length === 0) return null;
  const sorted = locations.slice().sort((a, b) => {
    const aStateMatch = wantedState && normalizeAgentState(a.state).toLowerCase() === wantedState ? 1 : 0;
    const bStateMatch = wantedState && normalizeAgentState(b.state).toLowerCase() === wantedState ? 1 : 0;
    if (aStateMatch !== bStateMatch) return bStateMatch - aStateMatch;
    const aCityMatch = wantedCity && normalizeAgentCity(a.city).toLowerCase() === wantedCity ? 1 : 0;
    const bCityMatch = wantedCity && normalizeAgentCity(b.city).toLowerCase() === wantedCity ? 1 : 0;
    if (aCityMatch !== bCityMatch) return bCityMatch - aCityMatch;
    const aStock = productId ? agentLocationStockQuantity(agent, a.id, productId) : 0;
    const bStock = productId ? agentLocationStockQuantity(agent, b.id, productId) : 0;
    if ((aStock > 0 ? 1 : 0) !== (bStock > 0 ? 1 : 0)) return (bStock > 0 ? 1 : 0) - (aStock > 0 ? 1 : 0);
    if ((a.isPrimary ? 1 : 0) !== (b.isPrimary ? 1 : 0)) return (b.isPrimary ? 1 : 0) - (a.isPrimary ? 1 : 0);
    return agentLocationLabel(a).localeCompare(agentLocationLabel(b));
  });
  return sorted[0] ?? null;
};

const bestAgentCoverageMatch = (
  agent: Pick<DeliveryAgentRecord, "coverage" | "primaryBaseState" | "zone">,
  state?: string | null,
  city?: string | null
) => {
  const wantedState = normalizeAgentState(state).toLowerCase();
  const wantedCity = normalizeAgentCity(city).toLowerCase();
  const rows = agentCoverageRows(agent).filter((row) => row.active !== false);
  if (rows.length === 0) return null;

  const stateMatches = wantedState
    ? rows.filter((row) => normalizeAgentState(row.state).toLowerCase() === wantedState)
    : [];
  const candidates = (stateMatches.length > 0 ? stateMatches : rows).slice().sort((a, b) => {
    const aCityMatch = wantedCity && normalizeAgentCity(a.city).toLowerCase() === wantedCity ? 1 : 0;
    const bCityMatch = wantedCity && normalizeAgentCity(b.city).toLowerCase() === wantedCity ? 1 : 0;
    if (aCityMatch !== bCityMatch) return bCityMatch - aCityMatch;
    const aLocal = a.coverageType === "local_delivery" ? 1 : 0;
    const bLocal = b.coverageType === "local_delivery" ? 1 : 0;
    if (aLocal !== bLocal) return bLocal - aLocal;
    if (a.priority !== b.priority) return a.priority - b.priority;
    return a.slaDays - b.slaDays;
  });

  return candidates[0] ?? null;
};

const agentOptionLabel = (
  agent: Pick<DeliveryAgentRecord, "name" | "coverage" | "primaryBaseState" | "zone">,
  state?: string | null,
  city?: string | null
) => {
  const base = agentPrimaryBaseState(agent);
  const match = bestAgentCoverageMatch(agent, state, city);
  const matchedState = normalizeAgentState(match?.state);
  if (matchedState && base && matchedState.toLowerCase() !== base.toLowerCase()) {
    return `${agent.name} · serves ${matchedState} (base ${base})`;
  }
  return `${agent.name} · ${matchedState || base || agentCoverageSummary(agent)}`;
};

type AgentOrderMatch = {
  agent: DeliveryAgentRecord;
  coverageMatch: DeliveryAgentCoverage | null;
  locationMatch: DeliveryAgentLocation | null;
  stockQty: number;
  sameState: boolean;
  sameCity: boolean;
};

const buildAgentOrderMatch = (
  agent: DeliveryAgentRecord,
  state?: string | null,
  city?: string | null,
  productId?: string | null
): AgentOrderMatch => {
  const wantedState = normalizeAgentState(state).toLowerCase();
  const wantedCity = normalizeAgentCity(city).toLowerCase();
  const coverageMatch = bestAgentCoverageMatch(agent, state, city);
  const locationMatch = bestAgentFulfillmentLocationMatch(agent, state, city, productId);
  const matchedState = normalizeAgentState(coverageMatch?.state).toLowerCase();
  const matchedCity = normalizeAgentCity(coverageMatch?.city).toLowerCase();
  const stockQty = productId
    ? locationMatch?.id
      ? agentLocationStockQuantity(agent, locationMatch.id, productId)
      : totalAgentProductStock(agent, productId)
    : 0;
  return {
    agent,
    coverageMatch,
    locationMatch,
    stockQty,
    sameState: Boolean(wantedState) && matchedState === wantedState,
    sameCity: Boolean(wantedCity) && matchedCity === wantedCity
  };
};

const compareAgentOrderMatches = (requiredQty: number) =>
  (a: AgentOrderMatch, b: AgentOrderMatch) => {
    if ((a.sameState ? 1 : 0) !== (b.sameState ? 1 : 0)) return (b.sameState ? 1 : 0) - (a.sameState ? 1 : 0);
    if ((a.sameCity ? 1 : 0) !== (b.sameCity ? 1 : 0)) return (b.sameCity ? 1 : 0) - (a.sameCity ? 1 : 0);
    const aEnough = a.stockQty >= requiredQty ? 1 : 0;
    const bEnough = b.stockQty >= requiredQty ? 1 : 0;
    if (aEnough !== bEnough) return bEnough - aEnough;
    if (a.stockQty !== b.stockQty) return b.stockQty - a.stockQty;
    if ((a.locationMatch?.isPrimary ? 1 : 0) !== (b.locationMatch?.isPrimary ? 1 : 0)) {
      return (b.locationMatch?.isPrimary ? 1 : 0) - (a.locationMatch?.isPrimary ? 1 : 0);
    }
    return a.agent.name.localeCompare(b.agent.name);
  };

const agentCoverageDraftStates = (primaryBaseState: string, servedStates: string[]) =>
  Array.from(
    new Set(
      [primaryBaseState, ...servedStates]
        .map((state) => normalizeAgentState(state))
        .filter(Boolean)
    )
  );

const hydrateAgentFromApi = (saved: any, fallback?: DeliveryAgentRecord): DeliveryAgentRecord => {
  const primaryBaseState = saved.primaryBaseState ?? saved.primary_base_state ?? saved.zone ?? fallback?.primaryBaseState ?? fallback?.zone ?? "";
  const coverage = Array.isArray(saved.coverage)
    ? saved.coverage.map((row: any) => ({
        id: row.id,
        state: row.state ?? "",
        city: row.city ?? "",
        coverageType: row.coverageType ?? row.coverage_type ?? "local_delivery",
        priority: Number(row.priority ?? 100),
        active: row.active !== false,
        slaDays: Number(row.slaDays ?? row.sla_days ?? 1),
        deliveryFeeRule: row.deliveryFeeRule ?? row.delivery_fee_rule ?? undefined,
        notes: row.notes ?? undefined
      }))
    : (fallback?.coverage ?? []);
  const locations = Array.isArray(saved.locations)
    ? saved.locations.map((location: any) => ({
        id: location.id,
        name: location.name ?? "",
        state: location.state ?? "",
        city: location.city ?? "",
        active: location.active !== false,
        isPrimary: location.isPrimary === true || location.is_primary === true,
        address: location.address ?? "",
        phoneOverride: location.phoneOverride ?? location.phone_override ?? undefined,
        notes: location.notes ?? undefined,
        stock: Array.isArray(location.stock)
          ? location.stock.map((row: any) => ({
              productId: row.productId ?? row.product_id ?? "",
              quantity: Number(row.quantity ?? 0),
              defective: Number(row.defective ?? 0),
              missing: Number(row.missing ?? 0)
            }))
          : []
      }))
    : (fallback?.locations ?? []);
  return {
    ...(fallback ?? {
      id: saved.id ?? makeAgentId(),
      name: saved.name ?? "",
      phone: saved.phone ?? "",
      zone: primaryBaseState,
      created: saved.created ?? saved.createdAt ?? saved.created_at ?? nowIso(),
      active: true
    }),
    id: saved.id ?? fallback?.id ?? makeAgentId(),
    name: saved.name ?? fallback?.name ?? "",
    phone: saved.phone ?? fallback?.phone ?? "",
    whatsappPhone: saved.whatsappPhone ?? saved.whatsapp_phone ?? fallback?.whatsappPhone ?? undefined,
    zone: primaryBaseState,
    primaryBaseState,
    coverage,
    locations,
    address: saved.address ?? fallback?.address ?? "",
    active: typeof saved.active === "boolean" ? saved.active : (saved.status ?? (fallback?.active ? "Active" : "Inactive")) === "Active",
    stockCapacity: Number(saved.stockCapacity ?? saved.stock_capacity ?? fallback?.stockCapacity ?? 1000),
    created: saved.created ?? saved.createdAt ?? saved.created_at ?? fallback?.created ?? nowIso()
  };
};

const primaryPricing = (product: Product) =>
  // Prefer the row marked primary. Tolerate both `primary` (legacy) and
  // `isPrimary` (new snake→camel API shape from is_primary). Fall back to
  // first pricing so products with one currency still value correctly.
  product.pricings.find((pricing) => (pricing as any).primary || (pricing as any).isPrimary)
  ?? product.pricings[0];
const totalProductStock = (product: Product) => product.warehouseStock + product.agentStock;
const activeProductPackages = (product: Product) => product.packages.filter((item) => item.active).sort((a, b) => a.displayOrder - b.displayOrder);
const persistedActiveProductPackages = <T extends { id: string; active: boolean; displayOrder: number }>(product: { packages: T[] }) =>
  product.packages.filter((item) => item.active && !isTemporaryPackageId(item.id)).sort((a, b) => a.displayOrder - b.displayOrder);
const orderSourceFromUtm = (source: string): Exclude<OrderSource, "All Sources"> => {
  const normalized = (source ?? "").toLowerCase().trim();

  // Recognise the Meta/ad ecosystem codes + full names so orders aren't all
  // collapsed into "Website". Mirrors the Ad Tracking source codes
  // (fb/ig/an/th/ms/wa/tt). Exact short codes are matched first, then names.
  if (normalized === "tt" || normalized.includes("tiktok")) return "TikTok";
  if (normalized === "ig" || normalized.includes("instagram") || normalized.includes("insta")) return "Instagram";
  if (normalized === "an" || normalized.includes("audience network")) return "Audience Network";
  if (normalized === "ms" || normalized.includes("messenger")) return "Messenger";
  if (normalized === "th" || normalized.includes("threads")) return "Threads";
  if (normalized === "wa" || normalized.includes("whatsapp")) return "WhatsApp";
  if (normalized === "fb" || normalized.includes("facebook") || normalized.includes("meta")) return "Facebook";
  if (normalized.includes("web") || normalized.includes("organic") || normalized.includes("embed")) return "Website";
  if (!normalized || normalized === "direct" || normalized === "none") return "Direct";
  return "Website";
};
const AD_TRACKING_SOURCE_PRIORITY = ["fb", "ig", "an", "th", "ms", "wa", "tt"];
const normalizeAdTrackingSource = (value?: string | null) => {
  const normalized = (value ?? "")
    .trim()
    .toLowerCase()
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ");

  if (!normalized || normalized === "direct") return "";
  if (normalized === "fb" || normalized.includes("facebook") || normalized.includes("meta")) return "fb";
  if (normalized === "ig" || normalized.includes("instagram") || normalized.includes("insta")) return "ig";
  if (normalized === "an" || normalized.includes("audience network")) return "an";
  if (normalized === "th" || normalized.includes("threads")) return "th";
  if (normalized === "ms" || normalized.includes("messenger")) return "ms";
  if (normalized === "wa" || normalized.includes("whatsapp")) return "wa";
  if (normalized === "tt" || normalized.includes("tiktok") || normalized.includes("tik tok")) return "tt";
  return normalized.replace(/\s+/g, "-");
};
const adTrackingSourceLabel = (key: string) => {
  switch (key) {
    case "fb":
      return "Fb";
    case "ig":
      return "Ig";
    case "an":
      return "An";
    case "th":
      return "Th";
    case "ms":
      return "Ms";
    case "wa":
      return "Wa";
    case "tt":
      return "Tt";
    default:
      return key
        .split("-")
        .filter(Boolean)
        .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
        .join(" ");
  }
};
const orderDisplaySourceLabelFromKey = (key: string) => {
  switch (key) {
    case "fb":
      return "Facebook";
    case "ig":
      return "Instagram";
    case "an":
      return "Audience Network";
    case "th":
      return "Threads";
    case "ms":
      return "Messenger";
    case "wa":
      return "WhatsApp";
    case "tt":
      return "TikTok";
    case "website":
      return "Website";
    default:
      return key
        .split("-")
        .filter(Boolean)
        .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
        .join(" ");
  }
};
const orderDisplaySourceFor = (order: Pick<TrackedOrder, "source" | "utmSource">) => {
  const utmKey = normalizeAdTrackingSource(order.utmSource);
  if (utmKey) {
    return {
      key: utmKey,
      label: orderDisplaySourceLabelFromKey(utmKey)
    };
  }

  const storedSource = order.source?.trim() ?? "";
  const storedKey = normalizeAdTrackingSource(storedSource);
  if (storedKey) {
    return {
      key: storedKey,
      label: orderDisplaySourceLabelFromKey(storedKey)
    };
  }

  const fallbackLabel = storedSource || orderSourceFromUtm(order.utmSource);
  return {
    key: fallbackLabel ? fallbackLabel.toLowerCase().replace(/\s+/g, "-") : "website",
    label: fallbackLabel || "Website"
  };
};
const adTrackingSourceSortIndex = (key: string) => {
  const idx = AD_TRACKING_SOURCE_PRIORITY.indexOf(key);
  return idx === -1 ? Number.MAX_SAFE_INTEGER : idx;
};
const adTrackingSourceBreakdown = (values: Array<string | undefined | null>): AdTrackingSourceStat[] => {
  const counts = new Map<string, number>();
  values.forEach((value) => {
    const key = normalizeAdTrackingSource(value);
    if (!key) return;
    counts.set(key, (counts.get(key) ?? 0) + 1);
  });
  return Array.from(counts, ([key, count]) => ({
    key,
    label: adTrackingSourceLabel(key),
    count
  })).sort((a, b) => b.count - a.count || adTrackingSourceSortIndex(a.key) - adTrackingSourceSortIndex(b.key) || a.label.localeCompare(b.label));
};
const orderLocationFromFields = (city: string, state: string) => {
  const rawLocation = `${city} ${state}`.trim();
  const matchedLocation = orderLocations.find(
    (location) => location !== "All Locations" && rawLocation.toLowerCase().includes(location.toLowerCase())
  );

  return matchedLocation || city.trim() || state.trim() || "Lagos";
};

const statusBadgeBaseClasses =
  "border shadow-[0_1px_0_rgba(255,255,255,0.82)_inset,0_8px_18px_rgba(15,23,42,0.08)] dark:shadow-[0_1px_0_rgba(255,255,255,0.05)_inset,0_12px_28px_rgba(2,6,23,0.34)]";
const outcomeBadgeBaseClasses =
  "border shadow-[0_1px_0_rgba(255,255,255,0.88)_inset,0_6px_14px_rgba(15,23,42,0.06)] dark:shadow-[0_1px_0_rgba(255,255,255,0.04)_inset,0_10px_22px_rgba(2,6,23,0.26)]";

const statusBadgeClasses = (status: string): string => {
  const map: Record<string, string> = {
    "New": `${statusBadgeBaseClasses} bg-sky-50 text-sky-800 border-sky-200 dark:bg-sky-400/22 dark:text-sky-50 dark:border-sky-300/38`,
    "Confirmed": `${statusBadgeBaseClasses} bg-amber-50 text-amber-900 border-amber-200 dark:bg-amber-400/22 dark:text-amber-50 dark:border-amber-300/38`,
    "In Process": `${statusBadgeBaseClasses} bg-orange-50 text-orange-900 border-orange-200 dark:bg-orange-400/22 dark:text-orange-50 dark:border-orange-300/38`,
    "Dispatched": `${statusBadgeBaseClasses} bg-violet-50 text-violet-800 border-violet-200 dark:bg-violet-400/22 dark:text-violet-50 dark:border-violet-300/38`,
    "Delivered": `${statusBadgeBaseClasses} bg-emerald-50 text-emerald-800 border-emerald-200 dark:bg-emerald-400/22 dark:text-emerald-50 dark:border-emerald-300/38`,
    "Cancelled": `${statusBadgeBaseClasses} bg-rose-50 text-rose-800 border-rose-200 dark:bg-rose-400/22 dark:text-rose-50 dark:border-rose-300/38`,
    "Postponed": `${statusBadgeBaseClasses} bg-blue-50 text-blue-800 border-blue-200 dark:bg-blue-400/24 dark:text-blue-50 dark:border-blue-300/40`,
    "Failed": `${statusBadgeBaseClasses} bg-red-50 text-red-800 border-red-200 dark:bg-red-400/22 dark:text-red-50 dark:border-red-300/38`,
  };
  return map[status] ?? `${statusBadgeBaseClasses} bg-slate-50 text-slate-700 border-slate-200 dark:bg-slate-400/12 dark:text-slate-100 dark:border-slate-300/24`;
};
const outcomeBadgeClasses = (outcome: string, status?: string): string => {
  const normalized = outcome.trim().toLowerCase();

  if (["confirmed", "recovered delivery"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-emerald-50/95 text-emerald-800 border-emerald-200 dark:bg-emerald-950/85 dark:text-emerald-200 dark:border-emerald-500/42`;
  }
  if (["refused", "wrong number"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-rose-50/95 text-rose-800 border-rose-200 dark:bg-rose-950/85 dark:text-rose-200 dark:border-rose-500/42`;
  }
  if (["no answer", "not picking", "not reached", "line busy", "number not going", "switched off", "not available"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-slate-100/95 text-slate-700 border-slate-200 dark:bg-slate-900/85 dark:text-slate-200 dark:border-slate-500/38`;
  }
  if (["will call back", "scheduled callback", "not ready", "travelled", "we should call back", "will get back to us", "have questions to ask", "seat at home", "rescheduled", "pending", "ready"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-blue-50/95 text-blue-800 border-blue-200 dark:bg-sky-950/85 dark:text-sky-200 dark:border-sky-500/42`;
  }
  if (["awaiting payment"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-violet-50/95 text-violet-800 border-violet-200 dark:bg-violet-950/85 dark:text-violet-200 dark:border-violet-500/42`;
  }
  if (["out of stock"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-orange-50/95 text-orange-900 border-orange-200 dark:bg-orange-950/85 dark:text-orange-200 dark:border-orange-500/42`;
  }
  if (["out of coverage"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-cyan-50/95 text-cyan-800 border-cyan-200 dark:bg-cyan-950/85 dark:text-cyan-200 dark:border-cyan-500/42`;
  }
  if (["waybill"].includes(normalized)) {
    return `${outcomeBadgeBaseClasses} bg-amber-50/95 text-amber-900 border-amber-200 dark:bg-amber-950/85 dark:text-amber-200 dark:border-amber-500/42`;
  }

  return `${outcomeBadgeBaseClasses} bg-white/95 text-slate-700 border-slate-200 dark:bg-slate-900/90 dark:text-slate-100 dark:border-slate-600/45`;
};
