  const [batchTierConfig, setBatchTierConfig] = useState<{ tiers: any[]; statusMap: any[] } | null>(null);
  const [batchBusy, setBatchBusy] = useState(false);
  const [newBatchLabel, setNewBatchLabel] = useState("");
  const [batchAssignFrom, setBatchAssignFrom] = useState("");
  const [batchAssignTo, setBatchAssignTo] = useState("");
  const [batchAssignProductId, setBatchAssignProductId] = useState("");
  const [batchAssignAllTime, setBatchAssignAllTime] = useState(false);
  const [showBatchTierConfig, setShowBatchTierConfig] = useState(false);
  const [batchAutofillMeta, setBatchAutofillMeta] = useState<any | null>(null);
  const autofilledBatches = useRef<Set<string>>(new Set());
  const loadBatchEconomics = async (id: string) => {
    try {
      const econ = await batchesApi.economics(id);
      setBatchEconomics(econ);
      // Auto-load costs from data the first time a batch with orders is opened while its
      // three cost inputs are still ₦0 — only when ALL are unset, so a number you typed is
      // never overwritten. (Re-pull/refresh stays manual via the "Pull from my data" button.)
      const b = econ?.batch;
      const totalOrders = econ?.economics?.worstCase?.totalOrders ?? 0;
      const unset = b && Number(b.adSpend) === 0 && Number(b.productCostPerSet) === 0 && Number(b.deliveryCostPerOrder) === 0;
      if (unset && totalOrders > 0 && !autofilledBatches.current.has(id)) {
        autofilledBatches.current.add(id);
        const r = await batchesApi.autofill(id);
        setBatchAutofillMeta(r?.meta ?? null);
        const s = r?.suggestions ?? {};
        if (Object.keys(s).length > 0) {
          await batchesApi.update(id, s);
          setBatchEconomics(await batchesApi.economics(id));
          await loadBatches();
        }
      }
    } catch { setBatchEconomics(null); }
  };
  const loadBatches = async () => {
    try {
      const [list, config] = await Promise.all([batchesApi.list(), batchesApi.getConfig()]);
      setBatches(Array.isArray(list) ? list : []);
      setBatchTierConfig(config);
      setSelectedBatchId((cur) => cur ?? ((Array.isArray(list) && list[0]) ? list[0].id : null));
    } catch (err: any) { showToast(`Failed to load batches: ${err?.message ?? err}`); }
  };
  useEffect(() => {
    if (activePage === "Finance & Accounting" && financeTab === "Profitability") void loadBatches();
  }, [activePage, financeTab]);
  useEffect(() => {
    setBatchAutofillMeta(null);
    if (selectedBatchId) void loadBatchEconomics(selectedBatchId);
    else setBatchEconomics(null);
  }, [selectedBatchId]);
  const createBatch = async () => {
    setBatchBusy(true);
    try {
      const b = await batchesApi.create({ label: newBatchLabel.trim() || "Untitled batch" });
      setNewBatchLabel("");
      await loadBatches();
      setSelectedBatchId(b.id);
    } catch (err: any) { showToast(`Create failed: ${err?.message ?? err}`); }
    finally { setBatchBusy(false); }
  };
  const patchBatch = async (patch: any) => {
    if (!selectedBatchId) return;
    setBatchBusy(true);
    try {
      await batchesApi.update(selectedBatchId, patch);
      await loadBatchEconomics(selectedBatchId);
      await loadBatches();
    } catch (err: any) { showToast(`Update failed: ${err?.message ?? err}`); }
    finally { setBatchBusy(false); }
  };
  const assignBatchOrders = async () => {
    if (!selectedBatchId) return;
    if (batchAssignAllTime) {
      if (!batchAssignProductId) { showToast("Pick a product to pull its full history."); return; }
    } else if (!batchAssignFrom || !batchAssignTo) {
      showToast("Pick a from + to date, or switch on full history."); return;
    }
    setBatchBusy(true);
    try {
      const body: any = batchAssignProductId ? { productIds: [batchAssignProductId] } : {};
      if (!batchAssignAllTime) { body.dateFrom = batchAssignFrom; body.dateTo = batchAssignTo; }
      const r = await batchesApi.assignOrders(selectedBatchId, body);
      const scope = batchAssignProductId ? (products.find((p) => p.id === batchAssignProductId)?.name ?? "that product") : "all products";
      const when = batchAssignAllTime ? "all-time" : "placed in that range";
      showToast(`Linked ${r.assigned} ${scope} order(s) ${when} to this batch.`);
      await loadBatchEconomics(selectedBatchId);
      await loadBatches();
    } catch (err: any) { showToast(`Assign failed: ${err?.message ?? err}`); }
    finally { setBatchBusy(false); }
  };
  const saveBatchTierConfig = async (tiers: any[], statusMap: any[]) => {
    setBatchBusy(true);
    try {
      const cfg = await batchesApi.updateConfig({ tiers, statusMap });
      setBatchTierConfig(cfg);
      if (selectedBatchId) await loadBatchEconomics(selectedBatchId);
    } catch (err: any) { showToast(`Tier save failed: ${err?.message ?? err}`); }
    finally { setBatchBusy(false); }
  };
  const pullBatchCostsFromData = async () => {
    if (!selectedBatchId) return;
    setBatchBusy(true);
    try {
      const r = await batchesApi.autofill(selectedBatchId);
      setBatchAutofillMeta(r?.meta ?? null);
      const s: Record<string, number> = r?.suggestions ?? {};
      const keys = Object.keys(s);
      if (keys.length === 0) {
        showToast(r?.meta?.note ?? "No values could be pulled — check the note under each field for what's missing.");
      } else {
        const cur = batchEconomics?.batch ?? {};
        const fieldLabel = (k: string) => k === "adSpend" ? "Ad spend" : k === "productCostPerSet" ? "Product cost / set" : "Delivery / order";
        // Don't silently overwrite a number the owner already typed — only auto-fill
        // empty/zero fields; for real conflicts, ask before replacing.
        const conflicts = keys.filter((k) => Number(cur[k]) > 0 && Number(cur[k]) !== Number(s[k]));
        let applyKeys = keys;
        if (conflicts.length > 0) {
          const lines = conflicts.map((k) => `• ${fieldLabel(k)}: ₦${Number(cur[k]).toLocaleString()} → ₦${Number(s[k]).toLocaleString()}`).join("\n");
          const ok = window.confirm(`Replace value(s) you already have?\n\n${lines}\n\nOK = use the pulled numbers · Cancel = keep yours (still fills any empty fields).`);
          if (!ok) applyKeys = keys.filter((k) => !conflicts.includes(k));
        }
        const merge: Record<string, number> = {};
        for (const k of applyKeys) merge[k] = s[k];
        if (Object.keys(merge).length > 0) {
          setBatchEconomics((p: any) => p ? { ...p, batch: { ...p.batch, ...merge } } : p);
          showToast(`Pulled ${Object.keys(merge).length} value(s) — review, then Save to recalculate.`);
        } else {
          showToast("Kept your typed values. Suggested numbers are noted under each field.");
        }
      }
    } catch (err: any) { showToast(`Pull failed: ${err?.message ?? err}`); }
    finally { setBatchBusy(false); }
  };
  // Weekly Accounting (Sun→Sat). Default to the Sunday of the current week.
