    const key = slugify(hiddenBuyer || sourceKey || raw) || "unattributed";
    const label = hiddenBuyer ? marketingPrettyLabel(hiddenBuyer) : sourceKey ? adTrackingSourceLabel(sourceKey) : marketingPrettyLabel(raw);
