      const current = acc[key] ?? { id: key, name: order.customer, phone: order.phone, orders: 0, totalSpend: 0, lastOrder: order.date };
      current.orders += 1;
      current.totalSpend += (order.status ?? "New") === "Delivered" ? order.amount : 0;
      current.lastOrder = order.date;
      acc[key] = current;
      return acc;
