  const exportInventoryCsv = () => {
    const rows: (string | number)[][] = [
      ["Inventory Report"],
      csvWorkspaceRow(),
      csvGeneratedRow(),
      ["Currency", selectedCurrency.label],
      ["Search", inventorySearch || "All"],
      ["Total Products", String(products.length)],
      ["Total Inventory Value", formatMoney(inventoryValue)],
      ["Total Units", String(totalInventoryUnits)],
      [],
      ["Product", "SKU", "Unit Cost", "Selling Price", "Warehouse Stock", "Agent Stock", "Total Stock", "Reorder Point", "Low Stock?", "Stock Value", "Units Sold", "Status"],
      ...products.map((product) => {
        const pricing = primaryPricing(product);
        const agentStock = productAgentStockSum(product.id);
        const totalStock = product.warehouseStock + agentStock;
        const unitCost = pricing?.unitCost ?? 0;
        const stockValue = totalStock * unitCost;
        const lowStock = product.warehouseStock <= (product.reorderPoint || 0);
        return [
          product.name,
          product.sku,
          formatProductMoney(unitCost, pricing?.currency ?? "NGN"),
          formatProductMoney(pricing?.sellingPrice ?? 0, pricing?.currency ?? "NGN"),
          String(product.warehouseStock),
          String(agentStock),
          String(totalStock),
          String(product.reorderPoint ?? 0),
          lowStock ? "YES" : "No",
          formatProductMoney(stockValue, pricing?.currency ?? "NGN"),
          String(productUnitsSoldLive(product.id)),
          product.active ? "Active" : "Inactive"
        ];
      }),
      [
        "TOTAL", "", "", "",
        String(products.reduce((s, p) => s + p.warehouseStock, 0)),
        String(products.reduce((s, p) => s + productAgentStockSum(p.id), 0)),
        String(products.reduce((s, p) => s + p.warehouseStock + productAgentStockSum(p.id), 0)),
        "",
        String(products.filter((p) => p.warehouseStock <= (p.reorderPoint || 0)).length) + " low",
        formatMoney(inventoryValue),
        String(products.reduce((s, p) => s + productUnitsSoldLive(p.id), 0)),
        ""
      ]
    ];
    triggerCsvDownload("inventory", rows, "Inventory exported as CSV.");
  };

  const printWaybill = (w: WaybillRecord) => {
    const win = window.open("", "_blank", "width=800,height=600");
    if (!win) return;
    // Notes and product/state names are user-editable; escape every interpolation.
    const esc = (v: unknown) => String(v ?? "")
      .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;").replace(/'/g, "&#39;");
    win.document.write(`<!DOCTYPE html><html><head><title>Waybill ${esc(w.id)}</title>
<style>body{font-family:Arial,sans-serif;margin:40px;color:#111}h1{font-size:20px;margin-bottom:4px}h2{font-size:14px;font-weight:normal;color:#555;margin:0 0 24px}table{width:100%;border-collapse:collapse;margin-top:16px}th,td{border:1px solid #ddd;padding:8px 12px;text-align:left;font-size:13px}th{background:#f5f5f5;font-weight:600}.badge{display:inline-block;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600}.status-transit{background:#dbeafe;color:#1d4ed8}.status-received{background:#dcfce7;color:#15803d}.status-returned{background:#fef3c7;color:#92400e}.status-cancelled{background:#f3f4f6;color:#6b7280}@media print{button{display:none}}</style></head>
<body>
<h1>ProtoHub CRM — Waybill</h1>
<h2>${esc(w.id)} · Printed ${new Date().toLocaleDateString("en-GB")}</h2>
<table>
${waybillLineItems(w).length > 1
  ? `<tr><th>Items</th><td colspan="3">${waybillLineItems(w).map((it) => `${String(it.quantity)} × ${esc(it.productName)}`).join("<br/>")}</td></tr>`
  : `<tr><th>Product</th><td>${esc(w.productName)}</td><th>Quantity</th><td>${esc(String(w.quantity))} units</td></tr>`}
<tr><th>From</th><td>${esc(w.sendingState)}</td><th>To</th><td>${esc(w.receivingState)}</td></tr>
<tr><th>Logistics Partner</th><td>${esc(w.logisticsPartner || "—")}</td><th>Waybill Fee</th><td>${w.waybillFee > 0 ? "₦" + w.waybillFee.toLocaleString() : "—"}</td></tr>
<tr><th>Date Sent</th><td>${esc(w.dateSent)}</td><th>Date Received</th><td>${esc(w.dateReceived || "—")}</td></tr>
<tr><th>Status</th><td><span class="badge status-${w.status === "In Transit" ? "transit" : w.status === "Received" ? "received" : w.status === "Returned" ? "returned" : "cancelled"}">${esc(w.status)}</span></td><th>Notes</th><td>${esc(w.note || "—")}</td></tr>
</table>
<br/><button onclick="window.print()" style="padding:8px 20px;background:#1F8FE0;color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:14px">Print</button>
</body></html>`);
    win.document.close();
  };

  const exportFinancialReport = () => {
    const header: string[][] = [
      ["Financial Report"],
      csvWorkspaceRow(),
      csvGeneratedRow(),
      ["Tab", financeTab],
      ["Period", selectedFinancePeriodLabel],
      ["Currency", selectedCurrency.label],
      []
    ];
    let tabRows: string[][] = [];
    if (financeTab === "Sales Rep Finance") {
      tabRows = [
        ["Sales Rep", "Revenue", "Delivered", "Contribution", "Commission", "ROI %"],
        ...filteredFinanceRepRows.map((r) => [r.user.name, formatMoney(r.revenue), String(r.delivered), formatMoney(r.contribution), formatMoney(r.commission), `${r.roi}%`])
      ];
    } else if (financeTab === "Agent Costs") {
      tabRows = [
        ["Agent", "Zone", "Deliveries", "Success Rate", "Stock Value", "Profit Contribution"],
        ...financeAgentRows.map((r) => [r.agent.name, r.agent.zone, String(r.deliveries), `${r.successRate}%`, formatMoney(r.stockValue), formatMoney(r.profitContribution)])
      ];
    } else if (financeTab === "Remittance") {
      tabRows = [
        ["Partner", "Orders", "Revenue", "Logistics Fees", "Expected", "Received", "Outstanding", "% Paid"],
        ...filteredRemittanceRows.map((r) => { const pct = r.expected === 0 ? 0 : Math.round((r.remitted / r.expected) * 100); return [r.partnerName, String(r.orderCount), formatMoney(r.revenue), formatMoney(r.logisticsCost), formatMoney(r.expected), formatMoney(r.remitted), formatMoney(r.outstanding), `${pct}%`]; })
      ];
    } else if (financeTab === "Profit & Loss") {
      tabRows = [
        ["Account", "Current Period"],
        ["Revenue", formatMoney(financeRevenue)],
        ["COGS", formatMoney(financeCogs)],
        ["Logistics / Delivery Fees", formatMoney(financeLogisticsCost)],
        ["Gross Profit", formatMoney(financeGrossProfit)],
        ["Operating Expenses", formatMoney(financeOpex)],
        ["Net Profit", formatMoney(financeNetProfit)]
      ];
    } else {
      tabRows = [
        ["Revenue", formatMoney(financeRevenue)],
        ["COGS", formatMoney(financeCogs)],
        ["Gross Profit", formatMoney(financeGrossProfit)],
        ["Gross Margin", `${financeGrossMargin}%`],
        ["Total Expenses", formatMoney(financeExpenseTotal)],
        ["Net Profit", formatMoney(financeNetProfit)],
        ["Net Margin", `${financeNetMargin}%`],
        ["Delivered Orders", String(financeDeliveredCount)]
      ];
    }
    const rows = [...header, ...tabRows];
    triggerCsvDownload(`financial-report-${slugify(financeTab)}`, rows, `${financeTab} report exported.`);
  };

  const handleNavClick = (label: string) => {
    setMobileMenuOpen(false);
    if (hashRoute.startsWith("#/order-form/embed")) {
      window.history.replaceState(null, "", `${window.location.pathname}${window.location.search}#`);
      setHashRoute("#");
    }

    const adminHashByLabel: Record<string, string> = {
      Dashboard: "#/dashboard/admin",
      Orders: "#/dashboard/admin/orders",
      "Follow-up Queue": "#/dashboard/admin/follow-up-queue",
      "Closed Orders": "#/dashboard/admin/closed-orders",
      "Abandoned Carts": "#/dashboard/admin/abandoned-carts",
      "Scheduled Deliveries": "#/dashboard/admin/scheduled-deliveries",
      Deliveries: "#/dashboard/admin/deliveries",
      Inventory: "#/dashboard/admin/inventory",
      "Sales Reps": "#/dashboard/admin/sales-reps",
      "Sales Teams": "#/dashboard/admin/sales-teams",
      "Weekend Stock Summary": "#/dashboard/admin/weekend-stock-summary",
      Agents: "#/dashboard/admin/agents",
      Waybill: "#/dashboard/admin/waybill",
      Payroll: "#/dashboard/admin/payroll",
      Customers: "#/dashboard/admin/customers",
      Expenses: "#/dashboard/admin/expenses",
      "Finance & Accounting": "#/dashboard/admin/reports",
      "Ad Tracking": "#/dashboard/admin/utm-tracking",
      Marketing: "#/dashboard/admin/marketing",
      "User Management": "#/dashboard/admin/users",
      "Round-Robin": "#/dashboard/admin/round-robin",
      "Embed Form": "#/dashboard/admin/embed",
      Notifications: "#/dashboard/admin/notifications",
      "Call Rep Console": "#/dashboard/admin/call-rep-console",
      Settings: "#/dashboard/admin/settings"
    };
    const syncAdminHash = (nextLabel: string) => {
      const nextHash = adminHashByLabel[nextLabel];
      if (nextHash) {
        window.history.replaceState(null, "", `${window.location.pathname}${window.location.search}${nextHash}`);
        setHashRoute(nextHash);
      }
    };

    if (label === "Dashboard") {
      syncAdminHash(label);
      setActivePage("Dashboard");
      window.scrollTo({ top: 0, behavior: "smooth" });
      return;
    }

    if (label === "Orders" || label === "Follow-up Queue" || label === "Closed Orders") {
      syncAdminHash(label);
      setActivePage(label as ActivePage);
      window.scrollTo({ top: 0, behavior: "smooth" });
      return;
    }

    if (label === "Abandoned Carts") {
      syncAdminHash(label);
      setActivePage("Abandoned Carts");
      window.scrollTo({ top: 0, behavior: "smooth" });
      return;
    }

    if (label === "Scheduled Deliveries" || label === "Deliveries" || label === "Inventory" || label === "Sales Reps" || label === "Sales Teams" || label === "Sales Rep Workspace" || label === "Call Rep Console" || label === "Weekend Stock Summary" || label === "Agents" || label === "Waybill" || label === "Payroll" || label === "Customers" || label === "Expenses" || label === "Finance & Accounting" || label === "Ad Tracking" || label === "Marketing" || label === "User Management" || label === "Round-Robin" || label === "Embed Form" || label === "AI Agent" || label === "AI Sandbox" || label === "AI/SMS Tokens" || label === "Notifications" || label === "Settings") {
      if (label === "Inventory") {
        setInventoryView("dashboard");
      }
      if (label === "Call Rep Console") {
        setCallQueueIndex(0);
        setCallQueueNote("");
      }
      if (label === "Sales Rep Workspace") {
        setRepConsoleTab("Dashboard");
        setRepOrderDetailId("");
        const nextHash = repTabRoute("Dashboard");
        window.history.replaceState(null, "", `${window.location.pathname}${window.location.search}${nextHash}`);
        setHashRoute(nextHash);
      } else {
        syncAdminHash(label);
      }
      setActivePage(label as ActivePage);
      window.scrollTo({ top: 0, behavior: "smooth" });
      return;
    }

    showToast(`${label} is a future module. Dashboard stays open for now.`);
  };

  const resetProductForm = () => {
    setProductName("");
    setProductDescription("");
    setProductSku("");
    setProductCatalogType("standard");
    setSkuManuallyEdited(false);
    setSkuSuffix(String(Math.floor(100 + Math.random() * 900)));
    setProductActive(true);
    setUnitCost("0");
    setSellingPrice("0");
    setOpeningStock("0");
    setReorderPoint("0");
  };

  const openAddProductModal = () => {
    resetProductForm();
    setModal("addProduct");
  };

  const openAddComboModal = () => {
    resetProductForm();
    setProductCatalogType("combo_only");
    setModal("addProduct");
  };

  const createProduct = () => {
    const isComboOnly = productCatalogType === "combo_only";
    if (!productName.trim()) {
      showToast(isComboOnly ? "Combo name is required." : "Product name is required.");
      return;
    }
    if (!isComboOnly && Number(sellingPrice) <= 0) {
      showToast("Selling price must be greater than zero.");
      return;
    }

    const id = makeProductId();
    const stock = isComboOnly ? 0 : Math.max(0, Number(openingStock) || 0);
    const product: Product = {
      id,
      name: productName.trim(),
      description: productDescription.trim(),
      sku: productSku.trim() || makeSku(productName),
      catalogType: productCatalogType,
      active: productActive,
      reorderPoint: isComboOnly ? 0 : Math.max(0, Number(reorderPoint) || 0),
      warehouseStock: stock,
      agentStock: 0,
      unitsSold: 0,
      pricings: isComboOnly ? [] : [
        {
          currency: (currency as ProductCurrencyCode) ?? "NGN",
          sellingPrice: Math.max(0, Number(sellingPrice) || 0),
          unitCost: Math.max(0, Number(unitCost) || 0),
          primary: true
        }
      ],
      packages: [],
      packageDescription: "",
      createdAt: nowIso()
    };

    setProducts((value) => [...value, product]);
    setSelectedProductId(id);
    setStockProductId(id);
    if (stock > 0) {
      setStockMovements((value) => [
        {
          id: makeMovementId(),
          date: new Date().toISOString(),
          productId: id,
          productName: product.name,
          type: "Stock Added",
          qty: stock,
          balanceAfter: stock,
          by: ownerName,
          note: "Opening stock"
        },
        ...value
      ]);
    }
    resetProductForm();
    if (isComboOnly) {
      setPackageDescriptionDraft("");
      setInventoryView("packages");
      setModal("addPackage");
      syncHashRoute(`#/dashboard/admin/inventory/packages/${id}/new`);
      showToast(`Combo "${product.name}" created. Add the first bundle now.`);
    } else {
      closeModal();
      showToast(`Product "${product.name}" created.`);
    }
    productsApi.create({ name: product.name, sku: product.sku, description: product.description, reorderPoint: product.reorderPoint, active: product.active, catalogType: product.catalogType ?? "standard" })
      .then((saved: any) => {
        replaceTemporaryProductId(id, saved.id);
        // Persist the initial pricing the admin entered on the create form.
        // Pre-fix this never reached the DB — productsApi.create only
        // creates the product row, and product_pricings stayed empty until
        // someone manually used "Add Currency" later (which itself was
        // also broken due to a snake_case → camelCase mismatch).
        const initial = product.pricings[0];
        if (initial) {
          productsApi.createPricing(saved.id, {
            currency:     initial.currency,
            sellingPrice: initial.sellingPrice,
            unitCost:     initial.unitCost,
            isPrimary:    true
          }).catch((err: any) => {
            showToast(`Initial pricing for ${product.name} not synced: ${err?.message ?? "open Pricing to retry."}`);
          });
        }
        if (stock > 0) {
          // Opening stock failure leaves the product created with 0 in DB
          // and the right number locally — surface that so the admin can retry.
          stockApi.update({ productId: saved.id, change: stock, note: "Opening stock" }).catch((err: any) => {
            showToast(`Opening stock for ${product.name} not synced: ${err?.message ?? "please retry from Inventory."}`);
          });
        }
      })
      .catch((err: any) => {
        // Roll back: remove the locally-created product + its opening movement.
        setProducts((prev) => prev.filter((p) => p.id !== id));
        if (stock > 0) setStockMovements((prev) => prev.filter((m) => m.productId !== id));
        if (isComboOnly) {
          setInventoryView("combos");
          setModal(null);
          syncHashRoute("#/dashboard/admin/inventory/combos");
        }
        showToast(`Failed to create ${product.name}: ${err?.message ?? "please retry"}.`);
      });
  };

  const submitStockUpdate = () => {
    const product = products.find((item) => item.id === stockProductId);
    const quantity = Number(stockChange) || 0;
    const adjustmentNote = stockAdjustmentNote.trim();

    if (!product) {
      showToast("Choose a product first.");
      return;
    }
    if (isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }

    if (quantity === 0) {
      showToast("Enter how many units you want to add or remove.");
      return;
    }

    if (!adjustmentNote) {
      showToast("Add a short reason so the owner can review this warehouse stock change.");
      return;
    }

    const change = stockAdjustmentMode === "remove" ? -Math.abs(quantity) : Math.abs(quantity);

    if (change < 0 && Math.abs(change) > product.warehouseStock) {
      showToast(`You can only remove up to ${product.warehouseStock} unit${product.warehouseStock === 1 ? "" : "s"} currently available in warehouse. Agent-held stock cannot be adjusted here.`);
      return;
    }

    const nextBalance = product.warehouseStock + change;
    const actualChange = change;
    setProducts((value) => value.map((item) => (item.id === product.id ? { ...item, warehouseStock: nextBalance } : item)));
    setStockMovements((value) => [
      {
        id: makeMovementId(),
        date: new Date().toISOString(),
        productId: product.id,
        productName: product.name,
        type: actualChange >= 0 ? "Stock Added" : "Correction",
        qty: actualChange,
        balanceAfter: nextBalance,
        by: ownerName,
        note: adjustmentNote
      },
      ...value
    ]);
    const _suProdId = product.id;
    const productSnapshot = product;
    setStockChange("0");
    setStockAdjustmentNote("");
    setStockAdjustmentMode("add");
    closeModal();
    showToast(`${product.name} stock updated to ${nextBalance}.`);
    // Roll back the optimistic warehouse-stock mutation if the API rejects it.
    // Without this, two reps could each apply +5 locally on a flaky network and
    // only one persists, leaving the warehouse balance off by 5 until reload.
    stockApi.update({ productId: _suProdId, change: actualChange, note: adjustmentNote }).catch((err: any) => {
      setProducts((value) => value.map((item) => item.id === _suProdId ? productSnapshot : item));
      showToast(`Stock change for ${productSnapshot.name} not synced: ${err?.message ?? "please retry"}.`);
    });
  };

  const openProductDetails = (product: Product) => {
    setSelectedProductId(product.id);
    openInventoryProductDetailRoute(product.id);
  };

  const openDeleteProduct = (product: Product) => {
    setSelectedProductId(product.id);
    openInventoryDeleteProductRoute(product.id);
  };

  const deleteSelectedProduct = () => {
    if (!selectedProduct) {
      showToast("Choose a product first.");
      return;
    }
    if (isTemporaryProductId(selectedProduct.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }

    const activeStatuses: TrackedOrder["status"][] = ["New", "Confirmed", "In Process", "Dispatched"];
    const activeOrders = trackedOrders.filter((o) => o.productId === selectedProduct.id && activeStatuses.includes(o.status));
    if (activeOrders.length > 0) {
      showToast(`Complete or cancel ${activeOrders.length} active order${activeOrders.length !== 1 ? "s" : ""} before deleting this product.`);
      return;
    }

    // Remove product, clean up cross-sell/free-gift refs in other products
    setProducts((prev) =>
      prev
        .filter((p) => p.id !== selectedProduct.id)
        .map((p) => ({
          ...p,
          crossSellProductIds: (p.crossSellProductIds ?? []).filter((id) => id !== selectedProduct.id),
          freeGiftProductIds: (p.freeGiftProductIds ?? []).filter((id) => id !== selectedProduct.id),
        }))
    );
    // Snapshot the slice we're about to remove so a server reject can fully
    // restore it (product, its movements, and its agent-stock rows).
    const productSnapshot = selectedProduct;
    const movementsSnapshot = stockMovements.filter((m) => m.productId === selectedProduct.id);
    const agentStockSnapshot = agentStock.filter((s) => s.productId === selectedProduct.id);
    setStockMovements((value) => value.filter((movement) => movement.productId !== selectedProduct.id));
    setAgentStock((value) => value.filter((stock) => stock.productId !== selectedProduct.id));
    const _dpId = selectedProduct.id;
    setSelectedProductId("");
    setInventoryView("dashboard");
    setModal(null);
    syncHashRoute("#/dashboard/admin/inventory");
    showToast(`${selectedProduct.name} deleted.`);
    productsApi.delete(_dpId).catch((err: any) => {
      setProducts((prev) => [productSnapshot, ...prev]);
      setStockMovements((prev) => [...movementsSnapshot, ...prev]);
      setAgentStock((prev) => [...agentStockSnapshot, ...prev]);
      showToast(`Failed to delete ${productSnapshot.name}: ${err?.message ?? "please retry"}.`);
    });
  };

  const duplicateProduct = (source: Product) => {
    if (isTemporaryProductId(source.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    const newId = makeProductId();
    const baseName = `${source.name} (Copy)`;
    let candidateName = baseName;
    let suffix = 2;
    while (products.some((p) => p.name.toLowerCase() === candidateName.toLowerCase())) {
      candidateName = `${baseName} ${suffix}`;
      suffix += 1;
    }
    const clone: Product = {
      ...source,
      id: newId,
      name: candidateName,
      sku: makeSku(candidateName),
      warehouseStock: 0,
      agentStock: 0,
      unitsSold: 0,
      createdAt: nowIso(),
      pricings: source.pricings.map((p) => ({ ...p })),
      packages: source.packages.map((pkg) => ({ ...pkg, id: makePackageId() })),
      availableStates: source.availableStates ? [...source.availableStates] : undefined,
      bonusConfig: source.bonusConfig ? {
        ...source.bonusConfig,
        baseDelivered: source.bonusConfig.baseDelivered.map((r) => ({ ...r, id: makeBonusRuleId() })),
        upgradeBonuses: source.bonusConfig.upgradeBonuses.map((r) => ({ ...r, id: makeBonusRuleId() })),
        manualOrderBonuses: source.bonusConfig.manualOrderBonuses.map((r) => ({ ...r, id: makeBonusRuleId() })),
        aovBonuses: source.bonusConfig.aovBonuses.map((r) => ({ ...r, id: makeBonusRuleId() })),
        deliveryRateBonuses: source.bonusConfig.deliveryRateBonuses.map((r) => ({ ...r, id: makeBonusRuleId() }))
      } : undefined,
      crossSellProductIds: source.crossSellProductIds ? [...source.crossSellProductIds] : undefined,
      freeGiftProductIds: source.freeGiftProductIds ? [...source.freeGiftProductIds] : undefined
    };
    setProducts((prev) => [clone, ...prev]);
    productsApi.create({
      name: clone.name,
      sku: clone.sku,
      description: clone.description,
      reorderPoint: clone.reorderPoint,
      active: clone.active,
      catalogType: clone.catalogType ?? "standard"
    }).then(async (saved: any) => {
      const savedId = saved?.id ?? newId;
      replaceTemporaryProductId(newId, savedId);
      const pricingTasks = clone.pricings.map((pricing) =>
        productsApi.createPricing(savedId, {
          currency: pricing.currency,
          sellingPrice: pricing.sellingPrice,
          unitCost: pricing.unitCost,
          isPrimary: Boolean((pricing as any).primary ?? (pricing as any).isPrimary)
        })
      );
      const packageTasks = clone.packages.map((pkg) =>
        productsApi.createPackage(savedId, {
          name: pkg.name,
          description: pkg.description,
          quantity: pkg.quantity,
          price: pkg.price,
          currency: pkg.currency,
          displayOrder: pkg.displayOrder,
          active: pkg.active,
          stateFilterMode: pkg.stateFilterMode ?? "all",
          stateRestrictions: pkg.stateRestrictions ?? [],
          requiresStateStock: Boolean(pkg.requiresStateStock),
          featuredComboCard: Boolean(pkg.featuredComboCard),
          imageUrl: pkg.imageUrl ?? "",
          imageUrls: pkg.imageUrls ?? [],
          packageComponents: pkg.packageComponents ?? [],
          companionProducts: pkg.companionProducts ?? []
        }).then((savedPackage: any) => ({ tempId: pkg.id, savedPackage: savedPackage as ProductPackage }))
      );
      const settingsPayload = {
        ...productSalesSettingsPayload(clone),
        available_states: clone.availableStates ?? [],
        form_custom_text: clone.formCustomText ?? "",
        package_description: clone.packageDescription ?? ""
      };
      const results = await Promise.allSettled([
        ...pricingTasks,
        ...packageTasks,
        productsApi.update(savedId, settingsPayload)
      ]);
      clone.packages.forEach((pkg, index) => {
        const result = results[pricingTasks.length + index];
        if (result?.status === "fulfilled") {
          replaceTemporaryPackageId(savedId, pkg.id, result.value.savedPackage);
        }
      });
      const hasFailures = results.some((result) => result.status === "rejected");
      if (hasFailures) {
        showToast(`"${candidateName}" duplicated, but some pricing/package settings did not sync. Open the product to verify.`);
        return;
      }
      showToast(`Duplicated as "${candidateName}". Stock reset to 0.`);
    }).catch((err: any) => {
      setProducts((prev) => prev.filter((product) => product.id !== newId));
      showToast(`Failed to duplicate "${source.name}": ${err?.message ?? "please retry"}.`);
    });
  };

  const toggleProductActive = (product: Product) => {
    if (isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    const nextActive = !product.active;
    const productSnapshot = product;
    setProducts((prev) => prev.map((p) => p.id === product.id ? { ...p, active: nextActive } : p));
    showToast(`${product.name} is now ${nextActive ? "active" : "inactive"}.`);
    productsApi.update(product.id, { active: nextActive }).catch((err: any) => {
      setProducts((prev) => prev.map((p) => p.id === product.id ? productSnapshot : p));
      showToast(`Failed to update ${product.name}: ${err?.message ?? "please retry"}.`);
    });
  };

  const previewProductForm = (product: Product) => {
    setGeneratedProductId(product.id);
    setActivePage("Embed Form");
    setEmbedTab("Create Order Form");
    setModal(null);
    window.scrollTo({ top: 0, behavior: "smooth" });
    showToast(`Previewing ${product.name} order form. Scroll to the right panel.`);
  };

  const crossSellPriceFor = (mainProduct: Product, crossSellProduct: Product) => {
    const override = mainProduct.crossSellPriceOverrides?.[crossSellProduct.id];
    if (typeof override === "number" && override >= 0) return override;
    return primaryPricing(crossSellProduct)?.sellingPrice ?? 0;
  };

  // Does this attached cross-sell appear when the customer is in `state`?
  // Order of precedence:
  //  1. Per-attachment override on the main product (most specific) — empty list = available everywhere
  //  2. The cross-sell product's own availableStates
  //  3. No restrictions = available everywhere
  // When `state` is empty we don't filter (form not yet committed to a state).
  const crossSellVisibleInState = (mainProduct: Product, crossSellProduct: Product, state: string) => {
    if (!state) return true;
    const attachmentRule = mainProduct.crossSellStateRestrictions?.[crossSellProduct.id];
    if (attachmentRule && attachmentRule.length > 0) return attachmentRule.includes(state);
    const productRule = crossSellProduct.availableStates;
    if (productRule && productRule.length > 0) return productRule.includes(state);
    return true;
  };

  const freeGiftVisibleInState = (mainProduct: Product, giftProduct: Product, state: string) => {
    if (!state) return true;
    const attachmentRule = mainProduct.freeGiftStateRestrictions?.[giftProduct.id];
    if (attachmentRule && attachmentRule.length > 0) return attachmentRule.includes(state);
    const productRule = giftProduct.availableStates;
    if (productRule && productRule.length > 0) return productRule.includes(state);
    return true;
  };

  const openEditProduct = (product: Product) => {
    setSelectedProductId(product.id);
    setProductName(product.name);
    setProductDescription(product.description);
    setProductSku(product.sku);
    setSkuManuallyEdited(true);
    setProductActive(product.active);
    setReorderPoint(String(product.reorderPoint));
    openInventoryEditProductRoute(product.id);
  };

  const saveEditProduct = () => {
    if (!selectedProduct) return;
    if (!productName.trim()) { showToast("Product name is required."); return; }
    if (isTemporaryProductId(selectedProduct.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    const _epId = selectedProduct.id;
    const productSnapshot = selectedProduct;
    setProducts((prev) => prev.map((p) => p.id === selectedProduct.id ? {
      ...p,
      name: productName.trim(),
      description: productDescription.trim(),
      sku: productSku.trim() || p.sku,
      active: productActive,
      reorderPoint: Number(reorderPoint) || 0
    } : p));
    closeModal();
    showToast(`${productName.trim()} saved.`);
    productsApi.update(_epId, { name: productName.trim(), description: productDescription.trim(), sku: productSku.trim() || selectedProduct.sku, active: productActive, reorder_point: Number(reorderPoint) || 0 }).catch((err: any) => {
      setProducts((prev) => prev.map((p) => p.id === _epId ? productSnapshot : p));
      showToast(`Failed to save ${productSnapshot.name}: ${err?.message ?? "please retry"}.`);
    });
  };

  const openPricingView = (product: Product) => {
    setSelectedProductId(product.id);
    setInventoryView("pricing");
    setActivePage("Inventory");
    syncHashRoute(`#/dashboard/admin/inventory/pricing/${product.id}`);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const openPackagesView = (product: Product) => {
    setSelectedProductId(product.id);
    setPackageDescriptionDraft(product.packageDescription);
    setInventoryView("packages");
    setActivePage("Inventory");
    syncHashRoute(`#/dashboard/admin/inventory/packages/${product.id}`);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const openAddPricing = () => {
    const existingCodes = new Set(selectedProduct?.pricings.map((p) => p.currency) ?? []);
    const nextCurrency = (Object.keys(productCurrencies) as ProductCurrencyCode[]).find((c) => !existingCodes.has(c)) ?? "USD";
    setPricingCurrency(nextCurrency);
    setPricingSellingPrice("0");
    setPricingCost("0");
    if (!selectedProduct) return;
    openInventoryAddPricingRoute(selectedProduct.id);
  };

  const openEditPricing = (pricing: ProductPricing) => {
    setSelectedPricingCurrency(pricing.currency);
    setPricingCurrency(pricing.currency);
    setPricingSellingPrice(String(pricing.sellingPrice));
    setPricingCost(String(pricing.unitCost));
    if (!selectedProduct) return;
    openInventoryEditPricingRoute(selectedProduct.id, pricing.currency);
  };

  const savePricing = () => {
    if (!selectedProduct) {
      showToast("Choose a product first.");
      return;
    }
    if (isTemporaryProductId(selectedProduct.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    if (Number(pricingSellingPrice) <= 0) {
      showToast("Selling price must be greater than zero.");
      return;
    }

    const existingRow = selectedProduct.pricings.find((p) => p.currency === selectedPricingCurrency);
    const existingIsPrimary = Boolean((existingRow as any)?.primary || (existingRow as any)?.isPrimary);
    const nextPricing = {
      currency: modal === "addPricing" ? pricingCurrency : selectedPricingCurrency,
      sellingPrice: Math.max(0, Number(pricingSellingPrice) || 0),
      unitCost: Math.max(0, Number(pricingCost) || 0),
      primary: modal === "editPricing" ? existingIsPrimary : false
    };

    if (modal === "addPricing" && selectedProduct.pricings.some((item) => item.currency === nextPricing.currency)) {
      showToast(`${productCurrencies[nextPricing.currency].label} pricing already exists.`);
      return;
    }

    const _spProdId = selectedProduct.id;
    const productSnapshot = selectedProduct;
    setProducts((value) =>
      value.map((product) =>
        product.id === selectedProduct.id
          ? {
              ...product,
              pricings:
                modal === "addPricing"
                  ? [...product.pricings, nextPricing]
                  : product.pricings.map((item) => (item.currency === selectedPricingCurrency ? { ...item, ...nextPricing, primary: item.primary } : item))
            }
          : product
      )
    );
    closeModal();
    showToast(`${productCurrencies[nextPricing.currency].label} pricing saved.`);
    // Backend zod schema expects camelCase: { currency, sellingPrice, unitCost, isPrimary }.
    // Pre-fix this call sent snake_case keys, the schema rejected them with 400,
    // and the silent rollback meant pricing never persisted — which is why
    // product_pricings was empty in production despite admins using the UI.
    // Both add and edit paths now persist; the upsert on the backend handles
    // the (product_id, currency) unique key and clears other primaries when
    // isPrimary=true.
    productsApi.createPricing(_spProdId, {
      currency:     nextPricing.currency,
      sellingPrice: nextPricing.sellingPrice,
      unitCost:     nextPricing.unitCost,
      isPrimary:    Boolean((nextPricing as any).primary ?? (nextPricing as any).isPrimary)
    }).catch((err: any) => {
      setProducts((prev) => prev.map((p) => p.id === _spProdId ? productSnapshot : p));
      showToast(`Failed to save ${productCurrencies[nextPricing.currency].label} pricing: ${err?.message ?? "please retry"}.`);
    });
  };

  const deletePricing = (code: ProductCurrencyCode) => {
    if (!selectedProduct) {
      return;
    }
    if (isTemporaryProductId(selectedProduct.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }

    const pricing = selectedProduct.pricings.find((p) => p.currency === code);
    if (Boolean((pricing as any)?.primary || (pricing as any)?.isPrimary)) {
      showToast("Primary pricing cannot be deleted. Set another currency as primary first.");
      return;
    }

    const productSnapshot = selectedProduct;
    setProducts((value) =>
      value.map((product) =>
        product.id === selectedProduct.id ? { ...product, pricings: product.pricings.filter((pricing) => pricing.currency !== code) } : product
      )
    );
    showToast(`${productCurrencies[code].label} pricing removed.`);
    productsApi.deletePricing(selectedProduct.id, code).catch((err: any) => {
      setProducts((prev) => prev.map((product) => product.id === selectedProduct.id ? productSnapshot : product));
      showToast(`Failed to remove ${productCurrencies[code].label} pricing: ${err?.message ?? "please retry"}.`);
    });
  };

  const resetPackageForm = () => {
    setPackageName("");
    setPackageDescription("");
    setPackageQuantity("1");
    setPackageUnitSingular("");
    setPackageUnitPlural("");
    setPackagePrice("0");
    setPackageCurrency("NGN");
    setPackageDisplayOrder("1");
    setPackageActive(false);
    setPackageComponents([]);
    setPackageCompanions([]);
    setPackageStateFilterMode("all");
    setPackageStateRestrictions([]);
    setPackageRequiresStateStock(false);
    setPackageFeaturedComboCard(false);
    setPackageAttributionProductId(null);
    packageImageUploadTokenRef.current += 1;
    setPackageImageUrls([]);
    setPackageImageUrlDraft("");
    setPackageSaving(false);
    setPackageImageUploading(0);
    setPackageImageSyncToTiers(false);
    setPackageFreeGiftSyncToTiers(false);
    setSelectedPackageId("");
  };

  const openAddPackage = () => {
    resetPackageForm();
    if (!selectedProduct) return;
    openInventoryAddPackageRoute(selectedProduct.id);
  };

  const openEditPackage = (item: ProductPackage, sourceProductId?: string) => {
    const productId = sourceProductId ?? selectedProduct?.id;
    if (productId) {
      setSelectedProductId(productId);
    }
    setSelectedPackageId(item.id);
    setPackageName(item.name);
    setPackageDescription(item.description);
    setPackageQuantity(String(item.quantity));
    setPackageUnitSingular(item.unitSingular ?? "");
    setPackageUnitPlural(item.unitPlural ?? "");
    setPackagePrice(String(item.price));
    setPackageCurrency(item.currency);
    setPackageDisplayOrder(String(item.displayOrder));
    setPackageActive(item.active !== false);
    setPackageComponents((item.packageComponents ?? []).map(normalisePackageComponent));
    setPackageCompanions((item.companionProducts ?? []).map(normalisePackageCompanion));
    setPackageStateFilterMode(normalisePackageStateFilterMode(item.stateFilterMode));
    setPackageStateRestrictions(Array.isArray(item.stateRestrictions) ? item.stateRestrictions : []);
    setPackageRequiresStateStock(Boolean(item.requiresStateStock));
    setPackageFeaturedComboCard(Boolean(item.featuredComboCard));
    setPackageAttributionProductId(item.attributionProductId ?? null);
    packageImageUploadTokenRef.current += 1;
    setPackageImageUrls(packageCarouselImages(item));
    setPackageImageUrlDraft("");
    setPackageImageUploading(0);
    setPackageImageSyncToTiers(false);
    setPackageFreeGiftSyncToTiers(false);
    if (!productId) return;
    openInventoryEditPackageRoute(productId, item.id);
  };

  const replaceTemporaryPackageId = (productId: string, tempId: string, savedPackage: ProductPackage) => {
    setProducts((prev) =>
      prev.map((product) =>
        product.id !== productId
          ? product
          : {
              ...product,
              packages: product.packages.map((pkg) => {
                if (pkg.id !== tempId) return pkg;
                const savedImages = savedPackageCarouselImagePatch(savedPackage, pkg);
                return {
                      ...pkg,
                      ...savedPackage,
                      packageComponents: savedPackage.packageComponents ?? pkg.packageComponents ?? [],
                      companionProducts: savedPackage.companionProducts ?? pkg.companionProducts ?? [],
                      stateFilterMode: savedPackage.stateFilterMode ?? pkg.stateFilterMode ?? "all",
                      stateRestrictions: savedPackage.stateRestrictions ?? pkg.stateRestrictions ?? [],
                      requiresStateStock: savedPackage.requiresStateStock ?? pkg.requiresStateStock ?? false,
                      featuredComboCard: savedPackage.featuredComboCard ?? pkg.featuredComboCard ?? false,
                      imageUrl: savedImages.imageUrl,
                      imageUrls: savedImages.imageUrls
                    };
              })
            }
      )
    );
    setSelectedPackageId((current) => (current === tempId ? savedPackage.id : current));
  };

  const syncPackageGalleryToSiblingTiers = async (
    productId: string,
    sourcePackageId: string,
    imageUrls: string[],
    productSnapshot: Product
  ) => {
    const targetPackageIds = productSnapshot.packages
      .filter((pkg) => pkg.id !== sourcePackageId && isComboLikePackage(pkg) && !isTemporaryPackageId(pkg.id))
      .map((pkg) => pkg.id);
    if (targetPackageIds.length === 0) return 0;

    const galleryPatch = {
      imageUrl: imageUrls[0] ?? "",
      imageUrls
    };
    const savedSiblings = await Promise.all(
      targetPackageIds.map((pkgId) => productsApi.updatePackage(productId, pkgId, galleryPatch))
    );
    const savedById = new Map(savedSiblings.map((pkg: ProductPackage) => [pkg.id, pkg]));
    const targetIdSet = new Set(targetPackageIds);
    setProducts((prev) =>
      prev.map((product) =>
        product.id !== productId
          ? product
          : {
              ...product,
              packages: product.packages.map((pkg) => {
                if (!targetIdSet.has(pkg.id)) return pkg;
                const savedPackage = savedById.get(pkg.id);
                if (!savedPackage) return { ...pkg, ...galleryPatch };
                const savedImages = savedPackageCarouselImagePatch(savedPackage, { ...pkg, ...galleryPatch });
                return {
                  ...pkg,
                  ...savedPackage,
                  packageComponents: savedPackage.packageComponents ?? pkg.packageComponents,
                  companionProducts: savedPackage.companionProducts ?? pkg.companionProducts,
                  stateFilterMode: savedPackage.stateFilterMode ?? pkg.stateFilterMode,
                  stateRestrictions: savedPackage.stateRestrictions ?? pkg.stateRestrictions,
                  requiresStateStock: savedPackage.requiresStateStock ?? pkg.requiresStateStock,
                  featuredComboCard: savedPackage.featuredComboCard ?? pkg.featuredComboCard,
                  imageUrl: savedImages.imageUrl,
                  imageUrls: savedImages.imageUrls
                };
              })
            }
      )
    );
    return targetPackageIds.length;
  };

  const syncPackageFreeGiftsToSiblingTiers = async (
    productId: string,
    sourcePackageId: string,
    freeGiftComponents: PackageComponent[],
    productSnapshot: Product
  ) => {
    const sourceGiftComponents = freeGiftComponents.filter((component) => component.productId && component.isFreeGift);
    if (sourceGiftComponents.length === 0) return 0;

    const targetPackages = productSnapshot.packages.filter(
      (pkg) => pkg.id !== sourcePackageId && isComboLikePackage(pkg) && !isTemporaryPackageId(pkg.id)
    );
    if (targetPackages.length === 0) return 0;

    const componentPatchByPackageId = new Map(
      targetPackages.map((pkg) => [
        pkg.id,
        replacePackageFreeGiftComponents(pkg.packageComponents, sourceGiftComponents)
      ])
    );
    const savedSiblings = await Promise.all(
      targetPackages.map((pkg) =>
        productsApi.updatePackage(productId, pkg.id, {
          packageComponents: componentPatchByPackageId.get(pkg.id) ?? []
        })
      )
    );
    const savedById = new Map(savedSiblings.map((pkg: ProductPackage) => [pkg.id, pkg]));
    const targetIdSet = new Set(targetPackages.map((pkg) => pkg.id));
    setProducts((prev) =>
      prev.map((product) =>
        product.id !== productId
          ? product
          : {
              ...product,
              packages: product.packages.map((pkg) => {
                if (!targetIdSet.has(pkg.id)) return pkg;
                const savedPackage = savedById.get(pkg.id);
                const packageComponents = savedPackage?.packageComponents ?? componentPatchByPackageId.get(pkg.id) ?? pkg.packageComponents;
                if (!savedPackage) return { ...pkg, packageComponents };
                const savedImages = savedPackageCarouselImagePatch(savedPackage, pkg);
                return {
                  ...pkg,
                  ...savedPackage,
                  packageComponents,
                  companionProducts: savedPackage.companionProducts ?? pkg.companionProducts,
                  stateFilterMode: savedPackage.stateFilterMode ?? pkg.stateFilterMode,
                  stateRestrictions: savedPackage.stateRestrictions ?? pkg.stateRestrictions,
                  requiresStateStock: savedPackage.requiresStateStock ?? pkg.requiresStateStock,
                  featuredComboCard: savedPackage.featuredComboCard ?? pkg.featuredComboCard,
                  imageUrl: savedImages.imageUrl,
                  imageUrls: savedImages.imageUrls
                };
              })
            }
      )
    );
    return targetPackages.length;
  };

  const savePackageGalleryAfterDetails = async (
    productId: string,
    packageId: string,
    gallery: { imageUrl?: string; imageUrls?: string[] },
    packageNameForToast: string
  ): Promise<{ savedPackage: ProductPackage | null; gallerySaved: boolean }> => {
    const imageUrls = normalisePackageImageUrls(gallery.imageUrls);
    const imageUrl = gallery.imageUrl && !gallery.imageUrl.startsWith("data:image/") ? gallery.imageUrl : "";
    // Always PATCH — empty arrays/strings must reach the backend so deletions persist.
    try {
      const savedPackage = await productsApi.updatePackage(productId, packageId, { imageUrl, imageUrls });
      return { savedPackage: savedPackage as ProductPackage, gallerySaved: true };
    } catch (err: any) {
      showToast(`"${packageNameForToast}" saved as draft, but images did not save: ${err?.message ?? "try smaller images"}.`);
      return { savedPackage: null, gallerySaved: false };
    }
  };

  const savePackage = async () => {
    if (packageSaving) return;
    if (!selectedProduct || !packageName.trim()) {
      showToast("Package name is required.");
      return;
    }
    if (isTemporaryProductId(selectedProduct.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    if (modal === "editPackage" && selectedPackage && isTemporaryPackageId(selectedPackage.id)) {
      showToast("This package is still syncing. Try again in a moment.");
      return;
    }
    if (packageImageUploading > 0) {
      showToast("Package images are still loading. Wait a second, then save again.");
      return;
    }

    const normalisedComponents = packageComponents.map(normalisePackageComponent).filter((component) => component.productId);
    const normalisedCompanions = packageCompanions.map(normalisePackageCompanion);
    const invalidStateScopedOffer = normalisedCompanions.find(
      (companion) => companion.stateFilterMode === "allow" && companion.stateRestrictions.length === 0
    );
    if (invalidStateScopedOffer) {
      showToast("Pick at least one state for every 'Show only in selected states' offer.");
      return;
    }
    if (packageStateFilterMode === "allow" && packageStateRestrictions.length === 0) {
      showToast("Pick at least one state, or change package visibility back to Show everywhere.");
      return;
    }
    const normalisedPackageStateRestrictions = packageStateFilterMode === "all" ? [] : packageStateRestrictions;
    const normalisedPackageImageUrls = normalisePackageImageUrls(packageImageUrls);
    const legacyPackageImageUrl = normalisedPackageImageUrls[0]?.startsWith("data:image/")
      ? ""
      : normalisedPackageImageUrls[0] ?? "";
    if (packageImageSyncToTiers && !currentPackageFormIsComboLike) {
      showToast("Gallery copy is only for combo package tiers. Mark this package as a combo first.");
      return;
    }
    if (packageImageSyncToTiers && normalisedPackageImageUrls.length === 0) {
      showToast("Add at least one package image before copying the gallery to other tiers.");
      return;
    }
    const normalisedFreeGiftComponents = normalisedComponents.filter((component) => component.isFreeGift);
    if (packageFreeGiftSyncToTiers && !currentPackageFormIsComboLike) {
      showToast("Free gift copy is only for combo package tiers. Mark this package as a combo first.");
      return;
    }
    if (packageFreeGiftSyncToTiers && normalisedFreeGiftComponents.length === 0) {
      showToast("Tick at least one component as a free gift before copying gifts to other combo tiers.");
      return;
    }
    const packageRecord: ProductPackage = {
      id: modal === "editPackage" && selectedPackage ? selectedPackage.id : makePackageId(),
      name: packageName.trim(),
      description: packageDescription.trim(),
      quantity: Math.max(1, Number(packageQuantity) || 1),
      price: Math.max(0, Number(packagePrice) || 0),
      currency: packageCurrency,
      displayOrder: Math.max(1, Number(packageDisplayOrder) || 1),
      active: packageActive,
      stateFilterMode: packageStateFilterMode,
      stateRestrictions: normalisedPackageStateRestrictions,
      requiresStateStock: packageRequiresStateStock,
      featuredComboCard: packageFeaturedComboCard,
      attributionProductId: packageAttributionProductId,
      imageUrl: legacyPackageImageUrl,
      imageUrls: normalisedPackageImageUrls,
      unitSingular: packageUnitSingular.trim() || undefined,
      unitPlural: packageUnitPlural.trim() || undefined,
      packageComponents: normalisedComponents,
      companionProducts: normalisedCompanions
    };
    const packagePayload = {
      name: packageRecord.name,
      description: packageRecord.description,
      quantity: packageRecord.quantity,
      price: packageRecord.price,
      currency: packageRecord.currency,
      displayOrder: packageRecord.displayOrder,
      active: packageRecord.active,
      stateFilterMode: packageRecord.stateFilterMode,
      stateRestrictions: packageRecord.stateRestrictions,
      requiresStateStock: packageRecord.requiresStateStock,
      featuredComboCard: packageRecord.featuredComboCard,
      attributionProductId: packageRecord.attributionProductId ?? null,
      imageUrl: packageRecord.imageUrl,
      imageUrls: packageRecord.imageUrls,
      unitSingular: packageRecord.unitSingular ?? null,
      unitPlural: packageRecord.unitPlural ?? null,
      packageComponents: normalisedComponents,
      companionProducts: normalisedCompanions
    };
    const { imageUrl: packagePayloadImageUrl, imageUrls: packagePayloadImageUrls, ...packageDetailsPayload } = packagePayload;
    const packageGalleryPayload = {
      imageUrl: packagePayloadImageUrl,
      imageUrls: packagePayloadImageUrls
    };

    const _pkgProdId = selectedProduct.id;
    const productSnapshot = selectedProduct;
    const shouldSyncPackageImagesToTiers = packageImageSyncToTiers && currentPackageFormIsComboLike && normalisedPackageImageUrls.length > 0;
    const shouldSyncPackageFreeGiftsToTiers = packageFreeGiftSyncToTiers && currentPackageFormIsComboLike && normalisedFreeGiftComponents.length > 0;
    const syncPackageAssetsToTiers = async (sourcePackageId: string, gallerySaved: boolean) => {
      if (shouldSyncPackageImagesToTiers && gallerySaved) {
        const count = await syncPackageGalleryToSiblingTiers(_pkgProdId, sourcePackageId, normalisedPackageImageUrls, productSnapshot);
        if (count > 0) showToast(`Gallery copied to ${count} other combo tier${count === 1 ? "" : "s"}.`);
      } else if (shouldSyncPackageImagesToTiers && !gallerySaved) {
        showToast("Gallery copy skipped because the image save failed.");
      }
      if (shouldSyncPackageFreeGiftsToTiers) {
        const count = await syncPackageFreeGiftsToSiblingTiers(_pkgProdId, sourcePackageId, normalisedFreeGiftComponents, productSnapshot);
        if (count > 0) showToast(`Free gift copied to ${count} other combo tier${count === 1 ? "" : "s"}.`);
      }
    };
    setPackageSaving(true);
    try {
      if (modal === "addPackage") {
        const savedPackage = await productsApi.createPackage(_pkgProdId, packageDetailsPayload) as ProductPackage;
        const galleryResult = await savePackageGalleryAfterDetails(_pkgProdId, savedPackage.id, packageGalleryPayload, packageRecord.name);
        const finalSavedPackage = galleryResult.savedPackage ?? savedPackage;
        setProducts((prev) =>
          prev.map((product) => {
            if (product.id !== _pkgProdId) return product;
            const savedImages = savedPackageCarouselImagePatch(finalSavedPackage, galleryResult.gallerySaved ? packageRecord : undefined);
            return {
              ...product,
              packages: [
                ...product.packages,
                {
                  ...packageRecord,
                  ...finalSavedPackage,
                  packageComponents: finalSavedPackage.packageComponents ?? normalisedComponents,
                  companionProducts: finalSavedPackage.companionProducts ?? normalisedCompanions,
                  stateFilterMode: finalSavedPackage.stateFilterMode ?? packageRecord.stateFilterMode,
                  stateRestrictions: finalSavedPackage.stateRestrictions ?? packageRecord.stateRestrictions,
                  requiresStateStock: finalSavedPackage.requiresStateStock ?? packageRecord.requiresStateStock,
                  featuredComboCard: finalSavedPackage.featuredComboCard ?? packageRecord.featuredComboCard,
                  imageUrl: savedImages.imageUrl,
                  imageUrls: savedImages.imageUrls
                }
              ]
            };
          })
        );
        if (shouldSyncPackageImagesToTiers || shouldSyncPackageFreeGiftsToTiers) {
          syncPackageAssetsToTiers(savedPackage.id, galleryResult.gallerySaved).catch((err: any) => {
            showToast(`Package saved, but combo-tier copy failed: ${err?.message ?? "please retry"}.`);
          });
        }
      } else if (modal === "editPackage" && selectedPackage) {
        const savedPackage = await productsApi.updatePackage(_pkgProdId, selectedPackage.id, packageDetailsPayload) as ProductPackage;
        const galleryResult = await savePackageGalleryAfterDetails(_pkgProdId, selectedPackage.id, packageGalleryPayload, packageRecord.name);
        const finalSavedPackage = galleryResult.savedPackage ?? savedPackage;
        setProducts((prev) =>
          prev.map((product) => {
            if (product.id !== _pkgProdId) return product;
            return {
              ...product,
              packages: product.packages.map((pkg) => {
                if (pkg.id !== selectedPackage.id) return pkg;
                const savedImages = savedPackageCarouselImagePatch(finalSavedPackage, galleryResult.gallerySaved ? packageRecord : undefined);
                return {
                  ...pkg,
                  ...finalSavedPackage,
                  packageComponents: finalSavedPackage.packageComponents ?? normalisedComponents,
                  companionProducts: finalSavedPackage.companionProducts ?? normalisedCompanions,
                  stateFilterMode: finalSavedPackage.stateFilterMode ?? packageRecord.stateFilterMode,
                  stateRestrictions: finalSavedPackage.stateRestrictions ?? packageRecord.stateRestrictions,
                  requiresStateStock: finalSavedPackage.requiresStateStock ?? packageRecord.requiresStateStock,
                  featuredComboCard: finalSavedPackage.featuredComboCard ?? packageRecord.featuredComboCard,
                  imageUrl: savedImages.imageUrl,
                  imageUrls: savedImages.imageUrls
                };
              })
            };
          })
        );
        if (shouldSyncPackageImagesToTiers || shouldSyncPackageFreeGiftsToTiers) {
          syncPackageAssetsToTiers(selectedPackage.id, galleryResult.gallerySaved).catch((err: any) => {
            showToast(`Package saved, but combo-tier copy failed: ${err?.message ?? "please retry"}.`);
          });
        }
      }
      showToast(`Package "${packageRecord.name}" saved ${packageRecord.active ? "and live" : "as draft"}.`);
      resetPackageForm();
      closeModal();
    } catch (err: any) {
      showToast(`Failed to ${modal === "addPackage" ? "add" : "save"} package: ${err?.message ?? "please retry"}.`);
    } finally {
      setPackageSaving(false);
    }
  };

  const openDeletePackage = (item: ProductPackage, sourceProductId?: string) => {
    const productId = sourceProductId ?? selectedProduct?.id;
    if (productId) {
      setSelectedProductId(productId);
    }
    setSelectedPackageId(item.id);
    if (!productId) return;
    openInventoryDeletePackageRoute(productId, item.id);
  };

  // Duplicate a package — clones into a new row (same product) with " (Copy)" suffix.
  // Companions, pricing, currency, qty all carry over.
  const duplicatePackage = (item: ProductPackage) => {
    if (!selectedProduct) return;
    const clone: ProductPackage = {
      ...item,
      id: makePackageId(),
      name: `${item.name} (Copy)`,
      active: false,
      displayOrder: (selectedProduct.packages.reduce((m, p) => Math.max(m, p.displayOrder), 0) || 0) + 1,
      packageComponents: item.packageComponents ? item.packageComponents.map((component) => normalisePackageComponent({ ...component, componentId: `pkg-comp-${Date.now()}-${Math.random().toString(36).slice(2, 6)}` })) : [],
      companionProducts: item.companionProducts ? item.companionProducts.map((companion) => normalisePackageCompanion({ ...companion, companionId: makeCompanionId() })) : []
    };
    const _dupProdId = selectedProduct.id;
    setProducts((value) =>
      value.map((p) => p.id === selectedProduct.id ? { ...p, packages: [...p.packages, clone] } : p)
    );
    const cloneGalleryPayload = {
      imageUrl: clone.imageUrl ?? "",
      imageUrls: clone.imageUrls ?? []
    };
    productsApi.createPackage(selectedProduct.id, {
      name: clone.name, description: clone.description,
      quantity: clone.quantity, price: clone.price, currency: clone.currency,
      displayOrder: clone.displayOrder, active: clone.active,
      stateFilterMode: clone.stateFilterMode ?? "all",
      stateRestrictions: clone.stateRestrictions ?? [],
      requiresStateStock: Boolean(clone.requiresStateStock),
      featuredComboCard: Boolean(clone.featuredComboCard),
      packageComponents: clone.packageComponents,
      companionProducts: clone.companionProducts
    }).then(async (savedPackage: any) => {
      const galleryResult = await savePackageGalleryAfterDetails(_dupProdId, (savedPackage as ProductPackage).id, cloneGalleryPayload, clone.name);
      replaceTemporaryPackageId(_dupProdId, clone.id, galleryResult.savedPackage ?? (savedPackage as ProductPackage));
    }).catch((err: any) => {
      setProducts((prev) => prev.map((p) => p.id === _dupProdId ? { ...p, packages: p.packages.filter((pkg) => pkg.id !== clone.id) } : p));
      showToast(`Failed to duplicate "${item.name}": ${err?.message ?? "please retry"}.`);
    });
    showToast(`Duplicated "${item.name}" as a draft.`);
  };

  const duplicatePackageScaled = (item: ProductPackage, multiplier: number) => {
    if (!selectedProduct) return;
    if ((item.packageComponents?.length ?? 0) === 0) {
      showToast("Add stock components first, then use the combo scaling shortcut.");
      return;
    }
    const scaledComponents = scalePackageComponents(item.packageComponents, multiplier);
    const autoDescription = packageDescriptionSuggestion(
      scaledComponents,
      products,
      /free delivery/i.test(item.description)
    );
    const clone: ProductPackage = {
      ...item,
      id: makePackageId(),
      name: scalePackageNameForMultiplier(item.name, multiplier),
      description: autoDescription || item.description,
      active: false,
      quantity: Math.max(1, item.quantity * multiplier),
      price: Math.round((item.price * multiplier + Number.EPSILON) * 100) / 100,
      displayOrder: (selectedProduct.packages.reduce((m, p) => Math.max(m, p.displayOrder), 0) || 0) + 1,
      packageComponents: scaledComponents,
      companionProducts: item.companionProducts ? item.companionProducts.map((companion) => normalisePackageCompanion({ ...companion, companionId: makeCompanionId() })) : []
    };
    const _scaleProdId = selectedProduct.id;
    setProducts((value) =>
      value.map((p) => p.id === selectedProduct.id ? { ...p, packages: [...p.packages, clone] } : p)
    );
    const cloneGalleryPayload = {
      imageUrl: clone.imageUrl ?? "",
      imageUrls: clone.imageUrls ?? []
    };
    productsApi.createPackage(selectedProduct.id, {
      name: clone.name,
      description: clone.description,
      quantity: clone.quantity,
      price: clone.price,
      currency: clone.currency,
      displayOrder: clone.displayOrder,
      active: clone.active,
      stateFilterMode: clone.stateFilterMode ?? "all",
      stateRestrictions: clone.stateRestrictions ?? [],
      requiresStateStock: Boolean(clone.requiresStateStock),
      featuredComboCard: Boolean(clone.featuredComboCard),
      packageComponents: clone.packageComponents,
      companionProducts: clone.companionProducts
    }).then(async (savedPackage: any) => {
      const galleryResult = await savePackageGalleryAfterDetails(_scaleProdId, (savedPackage as ProductPackage).id, cloneGalleryPayload, clone.name);
      replaceTemporaryPackageId(_scaleProdId, clone.id, galleryResult.savedPackage ?? (savedPackage as ProductPackage));
    }).catch((err: any) => {
      setProducts((prev) => prev.map((p) => p.id === _scaleProdId ? { ...p, packages: p.packages.filter((pkg) => pkg.id !== clone.id) } : p));
      showToast(`Failed to create x${multiplier} bundle: ${err?.message ?? "please retry"}.`);
    });
    showToast(`Created "${clone.name}" as a draft x${multiplier} combo copy. Adjust it, then Go live when ready.`);
  };

  // Toggle live/draft — quick action from the package row.
  const togglePackageActive = (item: ProductPackage) => {
    if (!selectedProduct) return;
    if (isTemporaryPackageId(item.id)) {
      showToast("This package is still syncing. Try again in a moment.");
      return;
    }
    const next = !item.active;
    const prev = item.active;
    const _tpProdId = selectedProduct.id;
    setProducts((value) =>
      value.map((p) => p.id === selectedProduct.id
        ? { ...p, packages: p.packages.map((pkg) => pkg.id === item.id ? { ...pkg, active: next } : pkg) }
        : p)
    );
    showToast(`${item.name} is now ${next ? "live on the customer form" : "saved as draft"}.`);
    productsApi.updatePackage(selectedProduct.id, item.id, { active: next }).catch((err: any) => {
      setProducts((value) =>
        value.map((p) => p.id === _tpProdId
          ? { ...p, packages: p.packages.map((pkg) => pkg.id === item.id ? { ...pkg, active: prev } : pkg) }
          : p)
      );
      showToast(`Failed to ${next ? "publish" : "draft"} package: ${err?.message ?? "please retry"}.`);
    });
  };

  // Reorder: move a package up/down by swapping displayOrder with neighbour.
  const movePackage = (item: ProductPackage, direction: "up" | "down") => {
    if (!selectedProduct) return;
    const sorted = [...selectedProduct.packages].sort((a, b) => a.displayOrder - b.displayOrder);
    const idx = sorted.findIndex((p) => p.id === item.id);
    const target = direction === "up" ? idx - 1 : idx + 1;
    if (target < 0 || target >= sorted.length) return;
    const a = sorted[idx], b = sorted[target];
    if (isTemporaryPackageId(a.id) || isTemporaryPackageId(b.id)) {
      showToast("This package is still syncing. Try again in a moment.");
      return;
    }
    const aOrder = a.displayOrder, bOrder = b.displayOrder;
    setProducts((value) =>
      value.map((p) => p.id === selectedProduct.id
        ? { ...p, packages: p.packages.map((pkg) =>
            pkg.id === a.id ? { ...pkg, displayOrder: bOrder } :
            pkg.id === b.id ? { ...pkg, displayOrder: aOrder } : pkg) }
        : p)
    );
    // Both calls need to succeed for the swap to be coherent. If either fails,
    // restore both packages to their original displayOrder so the UI matches DB.
    const _mvProdId = selectedProduct.id;
    Promise.all([
      productsApi.updatePackage(selectedProduct.id, a.id, { displayOrder: bOrder }),
      productsApi.updatePackage(selectedProduct.id, b.id, { displayOrder: aOrder })
    ]).catch((err: any) => {
      setProducts((value) =>
        value.map((p) => p.id === _mvProdId
          ? { ...p, packages: p.packages.map((pkg) =>
              pkg.id === a.id ? { ...pkg, displayOrder: aOrder } :
              pkg.id === b.id ? { ...pkg, displayOrder: bOrder } : pkg) }
          : p)
      );
      showToast(`Failed to reorder packages: ${err?.message ?? "please retry"}.`);
    });
  };

  // Companion lines that auto-attach to the order based on chosen package + state.
  const computeAutoCompanionLines = (chosenPackage: ProductPackage | undefined, state: string): CrossSellLine[] => {
    if (!chosenPackage?.companionProducts) return [];
    return chosenPackage.companionProducts
      .filter((c) => c.autoInclude)
      .filter((c) => companionMatchesState(c, state))
      .map((c) => {
        const product = products.find((p) => p.id === c.productId);
        const standardPrice = product ? (primaryPricing(product)?.sellingPrice ?? 0) : 0;
        const unit = c.pricingMode === "free" ? 0
                   : c.pricingMode === "fixed" ? (c.fixedPrice ?? 0)
                   : standardPrice;
        return { id: makeCrossSellLineId(), productId: c.productId, productName: (product?.name ?? "Companion") + " (bundled)", quantity: c.quantity, amount: unit * c.quantity };
      });
  };

  const deleteSelectedPackage = () => {
    if (!selectedProduct || !selectedPackage) {
      showToast("Choose a package first.");
      return;
    }
    if (isTemporaryPackageId(selectedPackage.id)) {
      showToast("This package is still syncing. Refresh the page if it does not settle.");
      return;
    }

    const productSnapshot = selectedProduct;
    const packageId = selectedPackage.id;
    setProducts((value) =>
      value.map((product) =>
        product.id === selectedProduct.id ? { ...product, packages: product.packages.filter((item) => item.id !== selectedPackage.id) } : product
      )
    );
    closeModal();
    showToast(`Package "${selectedPackage.name}" deleted.`);
    productsApi.deletePackage(selectedProduct.id, packageId).catch((err: any) => {
      setProducts((prev) => prev.map((product) => product.id === selectedProduct.id ? productSnapshot : product));
      showToast(`Failed to delete package: ${err?.message ?? "please retry"}.`);
    });
  };

  const savePackageDescription = () => {
    if (!selectedProduct) {
      return;
    }
    if (isTemporaryProductId(selectedProduct.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    if (packageDescriptionDraft === selectedProduct.packageDescription) {
      showToast("No changes to save.");
      return;
    }
    const productSnapshot = selectedProduct;
    setProducts((value) =>
      value.map((product) => (product.id === selectedProduct.id ? { ...product, packageDescription: packageDescriptionDraft } : product))
    );
    showToast("Package description saved.");
    productsApi.update(selectedProduct.id, { package_description: packageDescriptionDraft }).catch((err: any) => {
      setProducts((prev) => prev.map((product) => product.id === selectedProduct.id ? productSnapshot : product));
      showToast(`Failed to save package description: ${err?.message ?? "please retry"}.`);
    });
  };

  const generateEmbedUrl = async (productOverride?: Product) => {
    const product = productOverride ?? generatedProduct ?? readyEmbedProducts[0];
    if (!product) {
      showToast("Create a product package first.");
      return;
    }
    if (isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Wait a moment before sharing its embed link.");
      return;
    }
    if (persistedActiveProductPackages(product).length === 0) {
      showToast("At least one package is still syncing. Wait a moment before sharing this order form.");
      return;
    }
    if (isMarketerEmbedMode && !primaryMarketerEmbedTag) {
      showToast("Ask the Owner to assign your marketer tag before sharing links.");
      return;
    }
    if (isEmbedSyncing(product.id)) {
      return;
    }

    setEmbedSyncingProductIds((value) => value.includes(product.id) ? value : [...value, product.id]);
    try {
      await ensureProductPublicEmbedReady(product.id);
      setGeneratedProductId(product.id);
      setGeneratedEmbedProductIds((value) => (value.includes(product.id) ? value : [...value, product.id]));
      setEmbedCodeTabsByProduct((value) => ({ ...value, [product.id]: "Direct Link" }));
      showToast(isMarketerEmbedMode ? `${product.name} personal tracked link generated.` : `${product.name} embed URL generated.`);
    } catch (error: any) {
      showToast(error?.message ?? "This product is still syncing to the public order form. Please try again in a moment.");
    } finally {
      setEmbedSyncingProductIds((value) => value.filter((id) => id !== product.id));
    }
  };
  const setProductEmbedCodeTab = (productId: string, tab: EmbedCodeTab) => {
    setEmbedCodeTabsByProduct((value) => ({ ...value, [productId]: tab }));
  };
  const updateShowWhatsappField = (checked: boolean) => {
    setShowWhatsappField(checked);
    if (!checked) {
      setRequireWhatsapp(false);
    }
  };

  const copyText = async (value: string, label: string) => {
    try {
      if (navigator.clipboard) {
        await navigator.clipboard.writeText(value);
      } else {
        const el = document.createElement("textarea");
        el.value = value;
        el.style.position = "fixed";
        el.style.opacity = "0";
        document.body.appendChild(el);
        el.select();
        document.execCommand("copy");
        document.body.removeChild(el);
      }
      showToast(`${label} copied.`);
    } catch {
      showToast(`Could not copy ${label} — please copy it manually.`);
    }
  };

  const hydrateTrackedOrderFromApi = (raw: any) => {
    const normalized = normalizeTrackedOrder(raw);
    setTrackedOrders((value) => value.map((order) => order.id === normalized.id ? { ...order, ...normalized } : order));
    return normalized;
  };

  const refreshFollowUpRecordsForOrder = async (orderId: string) => {
    const [tasks, attempts] = await Promise.all([
      ordersApi.followUpTasks(orderId),
      ordersApi.contactAttempts(orderId)
    ]);
    setOrderFollowUpTasksByOrder((value) => ({
      ...value,
      [orderId]: (tasks as any[]).map((task) => normalizeFollowUpTask(task))
    }));
    setOrderContactAttemptsByOrder((value) => ({
      ...value,
      [orderId]: (attempts as any[]).map((attempt) => normalizeContactAttempt(attempt))
    }));
  };

  const repForNewRecord = () => {
    if (createOrderContext === "rep") {
      return selectedRepUser?.id ?? activeSalesRepUsers[0]?.id ?? salesRepUsers[0]?.id;
    }

    if (createOrderRepId !== "auto") {
      return createOrderRepId;
    }

    const candidates = activeSalesRepUsers.length > 0 ? activeSalesRepUsers : salesRepUsers;
    if (candidates.length === 0) {
      showToast("No sales reps available — order created unassigned. Add a sales rep first.");
      return undefined;
    }
    return [...candidates].sort((a, b) => {
      const aOpen = trackedOrders.filter((order) => order.assignedRepId === a.id && !["Delivered", "Cancelled", "Failed"].includes(order.status ?? "New")).length;
      const bOpen = trackedOrders.filter((order) => order.assignedRepId === b.id && !["Delivered", "Cancelled", "Failed"].includes(order.status ?? "New")).length;
      return aOpen - bOpen;
    })[0]?.id;
  };

  const maybePushAgentLowStockNotification = (
    product: Product,
    agent: DeliveryAgentRecord | undefined,
    previousQty: number,
    nextQty: number,
    location?: DeliveryAgentLocation | null
  ) => {
    if (!agent) return;
    const safePrevious = Math.max(0, Number(previousQty ?? 0));
    const safeNext = Math.max(0, Number(nextQty ?? 0));
    if (safePrevious <= smartStockLowStockThreshold || safeNext > smartStockLowStockThreshold) return;
    const locationSuffix = location ? ` · ${agentLocationLabel(location)}` : "";
    pushSystemNotification({
      type: "low_stock",
      title: "Low Agent Stock",
      message: `Low stock: ${product.name} — ${agent.name}${locationSuffix} down to ${safeNext} unit${safeNext === 1 ? "" : "s"} (hub threshold: ${smartStockLowStockThreshold})`,
      productId: product.id,
      link: `/dashboard/admin/agents/${agent.id}`
    });
  };

  const deductProductStockForOrder = (order: TrackedOrder) => {
    if (!order.productId || order.stockDeducted) {
      return;
    }

    const product = products.find((item) => item.id === order.productId);
    if (!product) {
      return;
    }

    const quantity = quantityForOrder(order);
    const sourceStock = order.agentId ? agentStock.find((stock) => stock.agentId === order.agentId && stock.productId === product.id) : undefined;
    const sourceAgent = order.agentId ? agents.find((agent) => agent.id === order.agentId) : undefined;
    const sourceLocation = sourceAgent
      ? bestAgentFulfillmentLocationMatch(sourceAgent, order.state, order.city, product.id)
      : null;
    const previousLocationQty = sourceLocation
      ? agentLocationProductStockQuantity(sourceLocation, product.id)
      : Math.max(0, Number(sourceStock?.quantity ?? 0));
    const nextBalance = order.agentId ? Math.max(0, (sourceStock?.quantity ?? 0) - quantity) : Math.max(0, product.warehouseStock - quantity);
    setProducts((value) =>
      value.map((item) =>
        item.id === product.id
          ? {
              ...item,
              warehouseStock: order.agentId ? item.warehouseStock : nextBalance,
              agentStock: order.agentId ? Math.max(0, item.agentStock - quantity) : item.agentStock,
              unitsSold: item.unitsSold + quantity
            }
          : item
      )
    );
    if (order.agentId) {
      setAgentStock((value) =>
        value.map((stock) =>
          stock.agentId === order.agentId && stock.productId === product.id ? { ...stock, quantity: nextBalance } : stock
        )
      );
    }
    setStockMovements((value) => [
      {
        id: makeMovementId(),
        date: new Date().toISOString(),
        productId: product.id,
        productName: product.name,
        type: "Order Fulfilled",
        qty: -quantity,
        balanceAfter: nextBalance,
        agent: order.agentId ? agents.find((agent) => agent.id === order.agentId)?.name : undefined,
        order: order.id,
        by: ownerName,
        note: "Order delivered"
      },
      ...value
    ]);
    // Fire low-stock notification if warehouse stock crosses reorder point
    if (!order.agentId) {
      const newWarehouseStock = Math.max(0, product.warehouseStock - quantity);
      if (newWarehouseStock <= product.reorderPoint && product.warehouseStock > product.reorderPoint) {
        pushSystemNotification({
          type: "low_stock",
          message: `Low stock: ${product.name} — warehouse down to ${newWarehouseStock} unit${newWarehouseStock === 1 ? "" : "s"} (reorder point: ${product.reorderPoint})`,
          productId: product.id,
          link: "/dashboard/admin/inventory/state-stock"
        });
      }
    } else {
      maybePushAgentLowStockNotification(
        product,
        sourceAgent,
        previousLocationQty,
        Math.max(0, previousLocationQty - quantity),
        sourceLocation
      );
    }
  };

  const orderTimelineNote = (
    text: string,
    options: { by?: string; followUpDate?: string; followUpAt?: string; date?: string } = {}
  ): OrderNote => ({
    id: makeNoteId(),
    text,
    by: options.by ?? ownerName,
    date: options.date ?? nowIso(),
    followUpDate: options.followUpDate,
    followUpAt: options.followUpAt
  });

  const commitOrderSchedule = (
    order: TrackedOrder,
    options: {
      scheduledDate: string;
      scheduledTime: string;
      callOutcome?: string | null;
      by?: string;
      noteText?: (label: string) => string;
    }
  ) => {
    if (!isDateValue(options.scheduledDate)) {
      showToast("Choose a valid delivery date.");
      return;
    }
    if (!isTimeValue(options.scheduledTime)) {
      showToast("Choose a valid delivery time.");
      return;
    }

    const plannedMoment = combinePlannedMoment(options.scheduledDate, options.scheduledTime);
    const scheduleLabel = formatPlannedMoment(plannedMoment.iso, options.scheduledDate);
    const nextNotes = [
      orderTimelineNote(
        (options.noteText ?? ((label) => `Delivery scheduled for ${label}.`))(scheduleLabel),
        { by: options.by }
      ),
      ...orderNotesFor(order)
    ];
    const nextResponse = `Scheduled for ${scheduleLabel}`;
    const orderSnapshot = order;
    const nextStatus: Exclude<OrderStatus, "All Orders"> = order.status === "New" || !order.status ? "Confirmed" : order.status;

    setTrackedOrders((value) =>
      value.map((item) =>
        item.id === order.id
          ? {
              ...item,
            status: nextStatus,
            scheduledDate: options.scheduledDate,
            scheduledAt: plannedMoment.iso,
            response: nextResponse,
            callOutcome: options.callOutcome === undefined ? item.callOutcome : options.callOutcome || undefined,
            notes: nextNotes
          }
        : item
      )
    );
    showToast(`${order.id} scheduled for ${scheduleLabel}.`);

    const statusUpdates: Record<string, unknown> = {
      status: nextStatus,
      scheduledDate: options.scheduledDate,
      scheduledAt: plannedMoment.iso ?? null,
      response: nextResponse,
      timelineNotes: nextNotes
    };
    if (options.callOutcome !== undefined) {
      statusUpdates.callOutcome = options.callOutcome;
    }
    ordersApi.updateStatus(order.id, statusUpdates)
      .then(async (updated: any) => {
        if (updated?.id) hydrateTrackedOrderFromApi(updated);
        await refreshFollowUpRecordsForOrder(order.id);
      })
      .catch((err: any) => {
        setTrackedOrders((value) => value.map((item) => item.id === order.id ? orderSnapshot : item));
        showToast(`Failed to save schedule for ${order.id}: ${err?.message ?? "please retry"}.`);
      });
  };

  const restoreProductStockForOrder = (order: TrackedOrder) => {
    if (!order.productId || !order.stockDeducted) {
      return;
    }
    const product = products.find((p) => p.id === order.productId);
    if (!product) {
      return;
    }
    const qty = quantityForOrder(order);
    const sourceStock = order.agentId ? agentStock.find((s) => s.agentId === order.agentId && s.productId === product.id) : undefined;
    const nextBalance = order.agentId ? (sourceStock?.quantity ?? 0) + qty : product.warehouseStock + qty;
    setProducts((prev) =>
      prev.map((p) =>
        p.id === product.id
          ? {
              ...p,
              warehouseStock: order.agentId ? p.warehouseStock : p.warehouseStock + qty,
              agentStock: order.agentId ? p.agentStock + qty : p.agentStock,
              unitsSold: Math.max(0, p.unitsSold - qty)
            }
          : p
      )
    );
    if (order.agentId) {
      setAgentStock((prev) =>
        prev.map((s) =>
          s.agentId === order.agentId && s.productId === product.id ? { ...s, quantity: nextBalance } : s
        )
      );
    }
    setStockMovements((prev) => [
      {
        id: makeMovementId(),
        date: new Date().toISOString(),
        productId: product.id,
        productName: product.name,
        type: "Return",
        qty,
        balanceAfter: nextBalance,
        agent: order.agentId ? agents.find((a) => a.id === order.agentId)?.name : undefined,
        order: order.id,
        by: ownerName,
        note: `Stock restored: ${order.id} status reversed from Delivered`
      },
      ...prev
    ]);
  };

  // Clear a "held for review" flag so the order flows normally again. Owner/Admin
  // only (the backend also enforces this). Optimistic with rollback on failure.
  const releaseOrderHold = (orderId: string) => {
    const order = trackedOrders.find((o) => o.id === orderId);
    if (!order) return;
    setTrackedOrders((prev) => prev.map((o) => o.id === orderId ? { ...o, reviewHold: false, reviewReason: undefined } : o));
    ordersApi.update(orderId, { review_hold: false, review_reason: null } as any).catch((err: any) => {
      setTrackedOrders((prev) => prev.map((o) => o.id === orderId ? order : o));
      showToast(`Could not release the order: ${err?.message ?? "please retry"}.`);
    });
    showToast(`Order ${orderId} released — it will be handled like a normal order now.`);
  };

  // Owner signs off on (or rejects) a cash variance an Admin logged. The cash is
  // already recorded — this is the after-the-fact approval.
  const reviewRemittanceVariance = (orderId: string, action: "approve" | "reject") => {
    const order = trackedOrders.find((o) => o.id === orderId);
    if (!order) return;
    let note: string | undefined;
    if (action === "reject") {
      note = (window.prompt("Reason for rejecting this cash variance (optional):") ?? "").trim() || undefined;
    } else if (!window.confirm("Approve this cash variance? The cash is already recorded — this signs off on it.")) {
      return;
    }
    const nextStatus: TrackedOrder["remittanceVarianceStatus"] = action === "approve" ? "approved" : "rejected";
    setTrackedOrders((prev) => prev.map((o) => o.id === orderId ? { ...o, remittanceVarianceStatus: nextStatus } : o));
    ordersApi.reviewRemittanceVariance(orderId, { action, note }).catch((err: any) => {
      setTrackedOrders((prev) => prev.map((o) => o.id === orderId ? order : o));
      showToast(`Could not ${action} the variance: ${err?.message ?? "please retry"}.`);
    });
    showToast(action === "approve" ? `Cash variance approved on ${orderId}.` : `Cash variance rejected on ${orderId}.`);
  };

  // Approve a whole batch of pending variances at once (one confirm, then fire each).
  const approveVarianceBatch = async (orderIds: string[]) => {
    if (orderIds.length === 0) return;
    if (!window.confirm(`Approve all ${orderIds.length} cash variance(s) in this batch? The cash is already recorded — this signs them off.`)) return;
    const snapshot = trackedOrders;
    setTrackedOrders((prev) => prev.map((o) => orderIds.includes(o.id) ? { ...o, remittanceVarianceStatus: "approved" } : o));
    const results = await Promise.allSettled(orderIds.map((id) => ordersApi.reviewRemittanceVariance(id, { action: "approve" })));
    let ok = 0;
    results.forEach((res, i) => {
      if (res.status === "rejected") {
        const id = orderIds[i];
        setTrackedOrders((prev) => prev.map((o) => o.id === id ? (snapshot.find((s) => s.id === id) ?? o) : o));
      } else ok += 1;
    });
    const failed = orderIds.length - ok;
    if (failed === 0) showToast(`Approved ${ok} cash variance(s).`);
    else if (ok > 0) showToast(`Approved ${ok}; ${failed} failed — please retry.`);
    else showToast(`Could not approve — all ${failed} failed. Please retry.`);
  };

  // Owner unlocks a settled remittance (one order, or a whole partner's orders) so an
  // Admin can correct it. Re-locks automatically once the Admin saves.
  const openRemittanceForEdit = (orderIds: string[], label: string) => {
    if (orderIds.length === 0) { showToast("Nothing settled to open here."); return; }
    setRemittanceOpenRequest({ orderIds, label });
  };

  const confirmOpenRemittanceForEdit = async () => {
    if (!remittanceOpenRequest || remittanceOpenBusy) return;
    const { orderIds } = remittanceOpenRequest;
    setRemittanceOpenBusy(true);
    try {
      const r = await ordersApi.openRemittanceForEdit(orderIds);
      setTrackedOrders((prev) => prev.map((o) => orderIds.includes(o.id) ? { ...o, remittanceEditOpen: true } : o));
      setRemittanceOpenRequest(null);
      showToast(`Opened ${r.opened} remittance(s) for correction.`);
    } catch (err: any) { showToast(`Could not open: ${err?.message ?? err}`); }
    finally { setRemittanceOpenBusy(false); }
  };

  // Re-spread a corrected TOTAL across a partner's batch (fill each order to its
  // expected, excess to the last). Patches only the orders whose remitted changes;
  // the per-order lock + variance approval still apply (the Owner has opened them).
  const batchCorrectionAllocation = (orders: TrackedOrder[], newTotal: number) => {
    const sorted = orders.slice().sort((a, b) => remittanceOrderSortValue(a) - remittanceOrderSortValue(b));
    let remaining = Math.max(0, newTotal);
    const rows = sorted.map((order) => {
      const expected = orderAmountToRemit(order);
      const amt = Math.max(0, Math.min(remaining, expected));
      remaining = roundCash(remaining - amt);
      return { order, expected, newRemitted: amt };
    });
    if (remaining > 0 && rows.length > 0) rows[rows.length - 1].newRemitted = roundCash(rows[rows.length - 1].newRemitted + remaining);
    return rows;
  };

  const openBatchCorrection = (row: { key: string; orders: TrackedOrder[] }) => {
    const selectedIds = row.orders.filter((order) => orderAmountRemitted(order) > 0).map((order) => order.id);
    const fallbackIds = selectedIds.length > 0 ? selectedIds : row.orders.map((order) => order.id);
    const currentSelectedTotal = row.orders
      .filter((order) => fallbackIds.includes(order.id))
      .reduce((sum, order) => sum + orderAmountRemitted(order), 0);
    setCorrectBatchKey(row.key);
    setCorrectBatchSelectedOrderIds(fallbackIds);
    setCorrectBatchTotal(String(Math.round(currentSelectedTotal)));
    setCorrectBatchReason("");
  };

  const closeBatchCorrection = () => {
    if (correctBatchBusy) return;
    setCorrectBatchKey(null);
    setCorrectBatchSelectedOrderIds([]);
  };

  const saveBatchCorrection = async (row: { key: string; partnerName: string; orders: TrackedOrder[] }, newTotal: number, reason: string, selectedIds: string[]) => {
    if (!reason.trim()) { showToast("Add a short reason for the batch correction."); return; }
    const selectedOrders = row.orders.filter((order) => selectedIds.includes(order.id));
    if (selectedOrders.length === 0) { showToast("Mark at least one order to correct."); return; }
    const alloc = batchCorrectionAllocation(selectedOrders, newTotal);
    const changed = alloc.filter((a) => roundCash(a.newRemitted) !== roundCash(orderAmountRemitted(a.order)));
    if (changed.length === 0) { showToast("Nothing to change — that total already matches."); setCorrectBatchKey(null); setCorrectBatchSelectedOrderIds([]); return; }
    setCorrectBatchBusy(true);
    const statusFor = (newRemitted: number, expected: number) => newRemitted <= 0 ? "Pending" : newRemitted >= expected ? "Paid" : "Partial";
    setTrackedOrders((prev) => prev.map((o) => {
      const a = changed.find((c) => c.order.id === o.id);
      return a ? { ...o, amountRemitted: a.newRemitted, remittanceStatus: statusFor(a.newRemitted, a.expected) as TrackedOrder["remittanceStatus"], remittanceEditOpen: false } : o;
    }));
    const results = await Promise.allSettled(changed.map((a) =>
      ordersApi.update(a.order.id, {
        amount_remitted: a.newRemitted,
        remittance_status: statusFor(a.newRemitted, a.expected),
        remittance_received_at: todayKey(),
        remittance_reason: `Batch correction — ${row.partnerName}: ${reason.trim()}`
      })
    ));
    const ok = results.filter((r) => r.status === "fulfilled").length;
    const failed = changed.length - ok;
    void loadFinanceRemittanceData({ quiet: true });
    void loadFinanceSummaryData({ quiet: true });
    setCorrectBatchBusy(false);
    setCorrectBatchKey(null);
    setCorrectBatchSelectedOrderIds([]);
    if (failed === 0) showToast(`Corrected ${ok} order(s) for ${row.partnerName}.`);
    else showToast(`Corrected ${ok}; ${failed} couldn't save (locked or error) — retry.`);
  };

  const updateOrderStatus = (
    orderId: string,
    nextStatus: Exclude<OrderStatus, "All Orders">,
    reason?: string,
    skipApi = false,
    deliveredDate?: string,
    callOutcome?: string | null
  ) => {
    const order = trackedOrders.find((item) => item.id === orderId);
    if (!order) {
      return;
    }
    const isDeliveryDateOnly = order.status === "Delivered" && nextStatus === "Delivered";
    const effectiveDeliveredDate = deliveredDate || order.deliveredDate || todayKey();

    // Guards: an order needs both a Sales Rep and an Agent before delivery.
    // Applies to every role (including Owner/Admin) to keep accounting,
    // payroll/bonus, and waybill audit trails clean.
    if (!isDeliveryDateOnly && nextStatus === "Delivered" && !order.assignedRepId) {
      showToast(`Cannot mark ${orderId} delivered — no Sales Rep assigned. Use "Reassign Sales Rep" first.`);
      return;
    }
    if (!isDeliveryDateOnly && nextStatus === "Delivered" && !order.agentId) {
      showToast(`Cannot mark ${orderId} delivered — no agent assigned. Use "Assign to Agent" first.`);
      return;
    }

    if (!isDeliveryDateOnly && nextStatus === "Delivered") {
      deductProductStockForOrder(order);
      // Auto-create waybill record (agent → customer) for audit trail
      if (order.agentId) {
        const agent = agents.find((a) => a.id === order.agentId);
        const customerLocation = [order.city, order.state].filter(Boolean).join(", ") || "Customer";
        const wbId = `WB-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
        setWaybillRecords((prev) => [{
          id: wbId,
          productId: order.productId ?? "",
          productName: order.productName,
          quantity: order.quantity ?? 1,
          waybillFee: 0,
          logisticsPartner: agent?.name ?? "Agent",
          sendingState: agent ? agentPrimaryBaseState(agent) : "",
          receivingState: customerLocation,
          fromAgentId: order.agentId,
          dateSent: todayKey(),
          dateReceived: todayKey(),
          status: "Received" as WaybillStatus,
          note: `Auto-created on delivery (${order.customer})`,
          createdBy: "System",
          createdAt: new Date().toISOString()
        }, ...prev]);
      }
    } else if (order.status === "Delivered" && order.stockDeducted) {
      restoreProductStockForOrder(order);
    }

    const response =
      isDeliveryDateOnly
        ? (order.response ?? "Delivered successfully")
        : nextStatus === "Delivered"
          ? "Delivered successfully"
          : nextStatus === "Cancelled"
          ? "Cancelled"
          : nextStatus === "Failed"
            ? "Delivery failed"
            : nextStatus === "Dispatched"
              ? "Out for delivery"
              : nextStatus === "In Process"
                ? "Call in process"
              : nextStatus === "Confirmed"
                ? "Confirmed by sales rep"
                : nextStatus === "Postponed"
                  ? "Delivery postponed"
                  : "Awaiting confirmation";
    setTrackedOrders((value) =>
      value.map((item) =>
        item.id === orderId
          ? {
              ...item,
              status: nextStatus,
              response,
              callOutcome: callOutcome === undefined ? item.callOutcome : callOutcome || undefined,
              deliveredDate: nextStatus === "Delivered" ? effectiveDeliveredDate : order.status === "Delivered" ? undefined : item.deliveredDate,
              stockDeducted: isDeliveryDateOnly ? item.stockDeducted : nextStatus === "Delivered" ? true : order.status === "Delivered" ? false : item.stockDeducted,
              notes: [
                orderTimelineNote(
                  isDeliveryDateOnly
                    ? `Delivered date corrected to ${displayDateFromKey(effectiveDeliveredDate)}.`
                    : `Status changed from ${item.status ?? "New"} to ${nextStatus}.${reason ? ` Reason: ${reason}` : ""}`
                ),
                ...orderNotesFor(item)
              ]
            }
          : item
      )
    );
    showToast(isDeliveryDateOnly ? `${orderId} delivery date updated.` : `${orderId} moved to ${nextStatus}.`);
    // Snapshot pre-update state so we can roll back if the API rejects the
    // change (network blip, rep no longer authorized, RLS denial). Without
    // this the optimistic UI lies to the user and the change disappears on
    // next reload. skipApi=true is used by the bulk handler, which fires its
    // own batched ordersApi.updateStatus and rolls back from its own snapshot.
    if (!skipApi) {
      const orderSnapshot = order;
      const statusRequest = isDeliveryDateOnly
        ? ordersApi.update(orderId, {
            delivered_date: effectiveDeliveredDate,
            ...(callOutcome !== undefined ? { call_outcome: callOutcome } : {})
          })
        : ordersApi.updateStatus(orderId, {
            status: nextStatus,
            reason,
            deliveredDate: nextStatus === "Delivered" ? effectiveDeliveredDate : undefined,
            ...(callOutcome !== undefined ? { callOutcome } : {})
          });
      statusRequest
        .then(async (updated: any) => {
          if (updated?.id) hydrateTrackedOrderFromApi(updated);
          await refreshFollowUpRecordsForOrder(orderId);
        })
        .catch((err: any) => {
          setTrackedOrders((value) => value.map((item) => item.id === orderId ? orderSnapshot : item));
          showToast(`Failed to update ${orderId}: ${err?.message ?? "please retry"}.`);
        });
    }
    // Re-sync the delivery-fee expense so a Failed/Cancelled flip turns the
    // line into a "Failed Delivery" expense, and a recovery flips it back.
    syncOrderDeliveryExpense({ ...order, status: nextStatus });
    // Backend already inserts notifications for New / Confirmed / Delivered /
    // Cancelled. Surface the other meaningful transitions client-side so the
    // bell still updates for Postponed / Failed.
    if (!isDeliveryDateOnly && (nextStatus === "Postponed" || nextStatus === "Failed")) {
      pushSystemNotification({
        type: "info",
        title: nextStatus === "Postponed" ? "Order postponed" : "Order failed",
        message: `${orderId} — ${order.customer} · ${order.productName}${reason ? ` · ${reason}` : ""}`,
        orderId,
        link: `/dashboard/admin/orders/${orderId}`
      });
    }
  };

  const callQueueUpdateStatus = (nextStatus: Exclude<OrderStatus, "All Orders">) => {
    if (!callQueueOrder) return;
    const noteText = callQueueNote.trim();
    const reason = noteText || undefined;
    updateOrderStatus(callQueueOrder.id, nextStatus, reason);
    setCallQueueNote("");
    // After status change the order drops out of callQueue (no longer "New").
    // If we were on the last item, step back so index stays in bounds on next render.
    setCallQueueIndex((prev) => prev >= callQueue.length - 1 ? Math.max(0, callQueue.length - 2) : prev);
  };

  const bulkUpdateOrderStatus = async (nextStatus: Exclude<OrderStatus, "All Orders">) => {
    if (selectedOrderIds.size === 0) return;
    const ids = Array.from(selectedOrderIds);
    // Snapshot orders before optimistic mutation so individual failures can be
    // rolled back without affecting the ones that succeeded.
    const snapshots = new Map(trackedOrders.filter((o) => selectedOrderIds.has(o.id)).map((o) => [o.id, o]));
    // skipApi=true: optimistic local update only — bulk handler owns the
    // network round-trip in a single batch below.
    ids.forEach((orderId) => updateOrderStatus(orderId, nextStatus, undefined, true, undefined, null));
    setSelectedOrderIds(new Set());
    const results = await Promise.allSettled(
      ids.map((orderId) => ordersApi.updateStatus(orderId, { status: nextStatus, callOutcome: null }))
    );
    // Per-id rollback for any rejected promise — fail-soft: succeeded orders
    // keep their new status, failed ones snap back to their pre-mutation form.
    const failedIds: string[] = [];
    results.forEach((r, i) => {
      if (r.status === "rejected") {
        failedIds.push(ids[i]);
      }
    });
    if (failedIds.length > 0) {
      setTrackedOrders((value) =>
        value.map((item) => failedIds.includes(item.id) ? (snapshots.get(item.id) ?? item) : item)
      );
      showToast(`${ids.length - failedIds.length} order${ids.length - failedIds.length !== 1 ? "s" : ""} moved to ${nextStatus}. ${failedIds.length} failed — please retry.`);
    } else {
      showToast(`${ids.length} order${ids.length > 1 ? "s" : ""} moved to ${nextStatus}.`);
    }
  };

  const scheduleOrder = (orderId: string, range: ScheduleRange) => {
    const order = trackedOrders.find((o) => o.id === orderId);
    if (order && ["Delivered", "Cancelled", "Failed"].includes(order.status ?? "")) {
      showToast(`Cannot schedule a ${order.status} order.`);
      return;
    }
    const scheduledDate = scheduleDateForRange(range);
    setOrderScheduleDate(scheduledDate);
    if (!order) {
      return;
    }
    commitOrderSchedule(order, { scheduledDate, scheduledTime: orderScheduleTime, by: ownerName });
  };


  const markDraftCartConverted = (orderId: string) => {
    if (!abandonedDraftCartId) {
      return;
    }

    const _mdcId = abandonedDraftCartId;
    setAbandonedCarts((value) =>
      value.map((cart) =>
        cart.id === abandonedDraftCartId
          ? { ...cart, status: "Converted", lastActivity: new Date().toISOString() }
          : cart
      )
    );
    setAbandonedDraftCartId("");
    showToast(`Recovered cart converted to ${orderId}.`);
    // Public-form (unauth) submits already mark the cart Converted server-side
    // through the public-orders endpoint's cartId parameter — calling the
    // auth-required cartsApi.update from an unauthenticated context would
    // 401 → request() reload the page → customer loses the success screen.
    if (auth.isLoggedIn()) {
      const snapshot = abandonedCarts.find((c) => c.id === _mdcId);
      cartsApi.update(_mdcId, { status: "Converted" }).catch((err: any) => {
        if (snapshot) setAbandonedCarts((value) => value.map((c) => c.id === _mdcId ? snapshot : c));
        showToast(`Cart conversion not synced: ${err?.message ?? "please retry"}.`);
      });
    }
  };

  const resetCreateOrderForm = () => {
    const product = products[0];
    const firstPackage = product ? activeProductPackages(product)[0] : undefined;
    setCreateOrderCustomer("");
    setCreateOrderPhone("");
    setCreateOrderWhatsapp("");
    setCreateOrderEmail("");
    setCreateOrderAddress("");
    setCreateOrderCity("Lagos");
    setCreateOrderState("Lagos");
    setCreateOrderProductId(product?.id ?? "");
    setCreateOrderPackageId(firstPackage?.id ?? "");
    setCreateOrderQuantity(String(firstPackage?.quantity ?? 1));
    setCreateOrderSource("Website");
    setCreateOrderRepId("auto");
    setCreateOrderAgentId("");
  };

  const openCreateOrderModal = () => {
    setCreateOrderContext("admin");
    resetCreateOrderForm();
    setModal("createOrder");
  };

  const openRepCreateOrderModal = () => {
    setCreateOrderContext("rep");
    resetCreateOrderForm();
    setCreateOrderRepId(selectedRepUser?.id ?? "auto");
    setModal("createOrder");
  };

  const createManualOrder = async () => {
    const product = products.find((item) => item.id === createOrderProductId);
    if (!product || !createOrderCustomer.trim() || !createOrderPhone.trim()) {
      showToast("Choose a product and enter customer name and phone.");
      return;
    }
    if (isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }

    const packageRecord = product.packages.find((item) => item.id === createOrderPackageId);
    if (packageRecord && isTemporaryPackageId(packageRecord.id)) {
      showToast("This package is still syncing. Try again in a moment.");
      return;
    }
    if (createOrderRepId && createOrderRepId !== "auto" && isTemporaryUserId(createOrderRepId)) {
      showToast("The selected sales rep is still syncing. Try again in a moment.");
      return;
    }
    if (createOrderAgentId && isTemporaryAgentId(createOrderAgentId)) {
      showToast("The selected agent is still syncing. Try again in a moment.");
      return;
    }
    if (createOrderScheduleEnabled && !isDateValue(orderScheduleDate)) {
      showToast("Choose a valid scheduled delivery date.");
      return;
    }
    if (createOrderScheduleEnabled && !isTimeValue(orderScheduleTime)) {
      showToast("Choose a valid scheduled delivery time.");
      return;
    }
    const quantity = Math.max(1, Number(createOrderQuantity) || packageRecord?.quantity || 1);
    const pricing = primaryPricing(product);
    const amount = packageRecord?.price ?? quantity * (pricing?.sellingPrice ?? 0);
    const plannedMoment = createOrderScheduleEnabled
      ? combinePlannedMoment(orderScheduleDate, orderScheduleTime)
      : { date: undefined, iso: undefined };
    const scheduleLabel = createOrderScheduleEnabled
      ? formatPlannedMoment(plannedMoment.iso, orderScheduleDate)
      : "";
    const baseNotes = [{ id: makeNoteId(), text: createOrderContext === "rep" ? "Order created by sales rep console." : "Order created manually.", by: createOrderContext === "rep" ? repScopeName : ownerName, date: nowIso() }];
    const scheduledNotes = createOrderScheduleEnabled && scheduleLabel
      ? [orderTimelineNote(`Delivery scheduled for ${scheduleLabel}.`, { by: createOrderContext === "rep" ? repScopeName : ownerName, date: nowIso() })]
      : [];
    const draftOrder: Omit<TrackedOrder, "id"> = {
      productId: product.id,
      packageId: packageRecord?.id,
      customer: createOrderCustomer.trim(),
      phone: createOrderPhone.trim(),
      whatsapp: createOrderWhatsapp.trim() || createOrderPhone.trim(),
      email: createOrderEmail.trim() || undefined,
      address: createOrderAddress.trim(),
      city: createOrderCity.trim(),
      state: createOrderState.trim(),
      productName: product.name,
      packageName: packageRecord?.name ?? "Manual package",
      quantity,
      amount,
      currency: packageRecord?.currency ?? pricing?.currency ?? "NGN",
      utmSource: createOrderSource.toLowerCase(),
      utmCampaign: "manual",
      source: createOrderSource,
      status: "New",
      response: "Awaiting confirmation",
      location: orderLocationFromFields(createOrderCity, createOrderState),
      assignedRepId: repForNewRecord(),
      createdAt: nowIso(),
      date: displayDateFromKey(todayKey()),
      notes: [{ id: makeNoteId(), text: createOrderContext === "rep" ? "Order created by sales rep console." : "Order created manually.", by: createOrderContext === "rep" ? repScopeName : ownerName, date: nowIso() }]
    };
    try {
      const saved = await ordersApi.create(draftOrder);
      const order: TrackedOrder = {
        ...draftOrder,
        id: saved.id,
        assignedRepId: saved.assignedRepId ?? draftOrder.assignedRepId,
        createdAt: saved.createdAt ?? draftOrder.createdAt,
        date: saved.date ?? draftOrder.date,
        location: saved.location ?? draftOrder.location
      };
      setTrackedOrders((value) => [order, ...value]);
      closeModal();
      setCreateOrderContext("admin");
      showToast(`${order.id} created and assigned to ${users.find((user) => user.id === order.assignedRepId)?.name ?? "round-robin queue"}.`);
    } catch (err: any) {
      showToast(`Failed to create order: ${err?.message ?? "please retry"}.`);
    }
  };

  const openOrderModal = (order: TrackedOrder, nextModal: ModalType) => {
    setSelectedOrderId(order.id);
    setReassignRepId(order.assignedRepId ?? activeSalesRepUsers[0]?.id ?? "");
    setHandoverReason("");
    setCreateOrderAgentId(order.agentId ?? "");
    setSendToAgentShowAllStates(false);
    setOrderNoteDraft("");
    setOrderFollowUpDate("");
    setOrderFollowUpTime(nextTimeValue());
    if (nextModal === "editOrderItems") {
      setCreateOrderCustomer(order.customer);
      setCreateOrderPhone(order.phone);
      setCreateOrderWhatsapp(order.whatsapp ?? "");
      setCreateOrderEmail(order.email ?? "");
      setCreateOrderAddress(order.address ?? "");
      setCreateOrderCity(order.city ?? "");
      setCreateOrderState(order.state ?? "");
      setCreateOrderProductId(order.productId ?? "");
      setCreateOrderPackageId(order.packageId ?? "");
      setCreateOrderQuantity(String(quantityForOrder(order)));
      setCreateOrderAmount(String(order.amount ?? ""));
      setCreateOrderSource(order.source ?? orderSourceFromUtm(order.utmSource));
      setCreateOrderRepId(order.assignedRepId ?? "auto");
      const plannedParts = splitMomentForInput(order.scheduledAt);
      setCreateOrderScheduleEnabled(!!scheduledMomentForOrder(order));
      setOrderScheduleDate(plannedParts.date || scheduledKeyForOrder(order) || todayKey());
      setOrderScheduleTime(plannedParts.time || nextTimeValue());
    }
    setModal(nextModal);
  };

  const openAdminOrderDetailPage = (order: TrackedOrder) => {
    openAdminOrderDetail(order.id);
  };

  const saveOrderAgent = (targetOrder?: TrackedOrder) => {
    const orderToUpdate = targetOrder ?? selectedOrder;
    if (!orderToUpdate) {
      return;
    }
    if (createOrderAgentId && isTemporaryAgentId(createOrderAgentId)) {
      showToast("The selected agent is still syncing. Try again in a moment.");
      return;
    }

    const agentName = agents.find((agent) => agent.id === createOrderAgentId)?.name ?? "Unassigned";
    const orderSnapshot = orderToUpdate;
    const nextNotes = [
      orderTimelineNote(`Fulfillment assignment updated to ${agentName}.`),
      ...orderNotesFor(orderToUpdate)
    ];
    const nextResponse = createOrderAgentId ? "Assigned to delivery agent" : "Delivery agent cleared";
    setTrackedOrders((value) =>
      value.map((order) =>
        order.id === orderToUpdate.id
          ? {
              ...order,
              agentId: createOrderAgentId || undefined,
              response: nextResponse,
              notes: nextNotes
        }
          : order
      )
    );
    const _soaId = orderToUpdate.id;
    if (modal !== "orderWorkflow") {
      closeModal();
    }
    ordersApi.update(_soaId, { agent_id: createOrderAgentId || null, response: nextResponse, timeline_notes: nextNotes })
      .then((updated: any) => {
        if (updated && updated.id === _soaId) {
          setTrackedOrders((value) => value.map((o) => o.id === _soaId ? { ...o, ...normalizeTrackedOrder(updated) } : o));
        }
        showToast(`${_soaId} delivery agent updated.`);
      })
      .catch((err: any) => {
        setTrackedOrders((value) => value.map((o) => o.id === _soaId ? orderSnapshot : o));
        const msg = `Failed to assign agent for ${_soaId}.\n\nError: ${err?.message ?? "Unknown"}\nStatus: ${err?.status ?? "no status"}\n\nThis means the change was NOT saved to the server. Please screenshot this and report it.`;
        showToast(`Failed to assign: ${err?.message ?? "see alert"}`);
        if (typeof window !== "undefined") window.alert(msg);
      });
  };

  const openEditSelectedOrder = () => {
    if (!selectedOrder) {
      return;
    }
    setOrderActionReturnTarget(orderActionReturnTargetFor(selectedOrder.id));

    setCreateOrderCustomer(selectedOrder.customer);
    setCreateOrderPhone(selectedOrder.phone);
    setCreateOrderWhatsapp(selectedOrder.whatsapp ?? "");
    setCreateOrderEmail(selectedOrder.email ?? "");
    setCreateOrderAddress(selectedOrder.address ?? "");
    setCreateOrderCity(selectedOrder.city ?? "");
    setCreateOrderState(selectedOrder.state ?? "");
    setCreateOrderProductId(selectedOrder.productId ?? "");
    setCreateOrderPackageId(selectedOrder.packageId ?? "");
    setCreateOrderQuantity(String(quantityForOrder(selectedOrder)));
    setCreateOrderAmount(String(selectedOrder.amount ?? ""));
    setCreateOrderSource(selectedOrder.source ?? orderSourceFromUtm(selectedOrder.utmSource));
    setCreateOrderRepId(selectedOrder.assignedRepId ?? "auto");
    setCreateOrderAgentId(selectedOrder.agentId ?? "");
    const plannedParts = splitMomentForInput(selectedOrder.scheduledAt);
    setCreateOrderScheduleEnabled(!!scheduledMomentForOrder(selectedOrder));
    setOrderScheduleDate(plannedParts.date || scheduledKeyForOrder(selectedOrder) || todayKey());
    setOrderScheduleTime(plannedParts.time || nextTimeValue());
    setModal("editOrderItems");
  };

  const saveSelectedOrderEdit = () => {
    if (!selectedOrder) {
      return;
    }

    const product = products.find((item) => item.id === createOrderProductId);
    if (!product || !createOrderCustomer.trim() || !createOrderPhone.trim()) {
      showToast("Choose a product and enter customer name and phone.");
      return;
    }
    if (isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }

    const packageRecord = product.packages.find((item) => item.id === createOrderPackageId);
    if (packageRecord && isTemporaryPackageId(packageRecord.id)) {
      showToast("This package is still syncing. Try again in a moment.");
      return;
    }
    if (createOrderRepId && createOrderRepId !== "auto" && isTemporaryUserId(createOrderRepId)) {
      showToast("The selected sales rep is still syncing. Try again in a moment.");
      return;
    }
    if (createOrderAgentId && isTemporaryAgentId(createOrderAgentId)) {
      showToast("The selected agent is still syncing. Try again in a moment.");
      return;
    }
    if (createOrderScheduleEnabled && !isDateValue(orderScheduleDate)) {
      showToast("Choose a valid scheduled delivery date.");
      return;
    }
    if (createOrderScheduleEnabled && !isTimeValue(orderScheduleTime)) {
      showToast("Choose a valid scheduled delivery time.");
      return;
    }
    const quantity = Math.max(1, Number(createOrderQuantity) || packageRecord?.quantity || 1);
    const pricing = primaryPricing(product);
    const autoAmount = packageRecord?.price ?? quantity * (pricing?.sellingPrice ?? 0);
    // Allow a manual price override (discount or partial delivery).
    const parsedManual = Number(createOrderAmount);
    const amount = createOrderAmount.trim() !== "" && !isNaN(parsedManual) && parsedManual >= 0
      ? parsedManual
      : autoAmount;
    const plannedMoment = createOrderScheduleEnabled
      ? combinePlannedMoment(orderScheduleDate, orderScheduleTime)
      : { date: undefined, iso: undefined };
    const nextResponse = createOrderScheduleEnabled
      ? `Scheduled for ${formatPlannedMoment(plannedMoment.iso, orderScheduleDate)}`
      : selectedOrder.response;
    const _soeId = selectedOrder.id;
    const orderSnapshot = selectedOrder;
    const nextNotes = [
      orderTimelineNote("Order details edited."),
      ...orderNotesFor(selectedOrder)
    ];
    setTrackedOrders((value) =>
      value.map((order) =>
        order.id === selectedOrder.id
          ? {
              ...order,
              productId: product.id,
              packageId: packageRecord?.id,
              customer: createOrderCustomer.trim(),
              phone: createOrderPhone.trim(),
              whatsapp: createOrderWhatsapp.trim(),
              address: createOrderAddress.trim(),
              city: createOrderCity.trim(),
              state: createOrderState.trim(),
              productName: product.name,
              packageName: packageRecord?.name ?? "Manual package",
              quantity,
              amount,
              currency: packageRecord?.currency ?? pricing?.currency ?? "NGN",
              email: createOrderEmail.trim() || order.email,
              source: createOrderSource,
              utmSource: createOrderSource.toLowerCase(),
              location: orderLocationFromFields(createOrderCity, createOrderState),
              assignedRepId: createOrderRepId === "auto" ? order.assignedRepId : createOrderRepId,
              agentId: createOrderAgentId || undefined,
              scheduledDate: createOrderScheduleEnabled ? orderScheduleDate : undefined,
              scheduledAt: createOrderScheduleEnabled ? plannedMoment.iso : undefined,
              response: nextResponse,
              notes: nextNotes
            }
          : order
      )
    );
    ordersApi.update(_soeId, { customer: createOrderCustomer.trim(), phone: createOrderPhone.trim(), whatsapp: createOrderWhatsapp.trim(), address: createOrderAddress.trim(), city: createOrderCity.trim(), state: createOrderState.trim(), product_id: product.id, package_id: packageRecord?.id ?? null, product_name: product.name, package_name: packageRecord?.name ?? null, quantity, amount, source: createOrderSource, assigned_rep_id: createOrderRepId === "auto" ? selectedOrder.assignedRepId : createOrderRepId, agent_id: createOrderAgentId || null, scheduled_date: createOrderScheduleEnabled ? orderScheduleDate : null, scheduled_at: createOrderScheduleEnabled ? plannedMoment.iso : null, response: nextResponse, timeline_notes: nextNotes }).catch((err: any) => {
      setTrackedOrders((value) => value.map((o) => o.id === _soeId ? orderSnapshot : o));
      showToast(`Failed to save edits to ${_soeId}: ${err?.message ?? "please retry"}.`);
    });
    closeModal();
    showToast(`${selectedOrder.id} updated.`);
  };

  const reassignSelectedOrder = () => {
    if (!selectedOrder || !reassignRepId) {
      showToast("Choose the new sales rep.");
      return;
    }
    if (isTemporaryUserId(reassignRepId)) {
      showToast("The selected sales rep is still syncing. Try again in a moment.");
      return;
    }

    const orderSnapshot = selectedOrder;
    const nextResponse = `Reassigned: ${handoverReason.trim() || "handover noted"}`;
    const nextNotes = [
      { id: makeNoteId(), text: `Reassigned to ${users.find((user) => user.id === reassignRepId)?.name ?? "rep"} - ${handoverReason.trim() || "No reason supplied"}`, by: ownerName, date: new Date().toISOString() },
      ...orderNotesFor(selectedOrder)
    ];
    setTrackedOrders((value) =>
      value.map((order) =>
        order.id === selectedOrder.id
          ? {
              ...order,
              assignedRepId: reassignRepId,
              response: nextResponse,
              notes: nextNotes
            }
          : order
      )
    );
    closeModal();
    showToast(`${selectedOrder.id} reassigned.`);
    ordersApi.update(selectedOrder.id, {
      assigned_rep_id: reassignRepId,
      response: nextResponse,
      timeline_notes: nextNotes
    }).catch((err: any) => {
      setTrackedOrders((value) => value.map((order) => order.id === selectedOrder.id ? orderSnapshot : order));
      showToast(`Failed to reassign ${selectedOrder.id}: ${err?.message ?? "please retry"}.`);
    });
  };

  const viewSelectedAssigneeOrders = () => {
    if (!selectedOrder?.assignedRepId) {
      showToast("This order is not assigned yet.");
      return;
    }
    const repName = users.find((user) => user.id === selectedOrder.assignedRepId)?.name ?? "selected rep";
    setOrderAssignmentScope(`rep:${selectedOrder.assignedRepId}`);
    setOrderStatus("All Orders");
    setActivePage(activeOrderWorkspacePage);
    syncHashRoute(adminOrderWorkspaceHash(""));
    closeModal();
    showToast(`Showing orders assigned to ${repName}.`);
  };

  const removeSelectedOrderAssignment = () => {
    if (!selectedOrder?.assignedRepId) {
      showToast("This order is already unassigned.");
      return;
    }
    if (!window.confirm(`Remove the assigned owner from order ${selectedOrder.id}?`)) {
      return;
    }
    const orderSnapshot = selectedOrder;
    const nextResponse = "Assignment removed";
    const nextNotes = [
      { id: makeNoteId(), text: `Assignment removed from ${users.find((user) => user.id === selectedOrder.assignedRepId)?.name ?? "current owner"}.`, by: ownerName, date: new Date().toISOString() },
      ...orderNotesFor(selectedOrder)
    ];
    setTrackedOrders((value) =>
      value.map((order) =>
        order.id === selectedOrder.id
          ? { ...order, assignedRepId: undefined, response: nextResponse, notes: nextNotes }
          : order
      )
    );
    closeModal();
    showToast(`${selectedOrder.id} is now unassigned.`);
    ordersApi.update(selectedOrder.id, {
      assigned_rep_id: null,
      response: nextResponse,
      timeline_notes: nextNotes
    }).catch((err: any) => {
      setTrackedOrders((value) => value.map((order) => order.id === selectedOrder.id ? orderSnapshot : order));
      showToast(`Failed to remove assignment from ${selectedOrder.id}: ${err?.message ?? "please retry"}.`);
    });
  };

  const addOrderNote = () => {
    if (!selectedOrder || !orderNoteDraft.trim()) {
      showToast("Add a note before saving.");
      return;
    }

    const followUpDate = orderFollowUpDate && isDateValue(orderFollowUpDate) ? orderFollowUpDate : undefined;
    if (followUpDate && !isTimeValue(orderFollowUpTime)) {
      showToast("Choose a valid follow-up time.");
      return;
    }
    const safeFollowUpTime = followUpDate ? orderFollowUpTime : undefined;
    const followUpMoment = followUpDate ? combinePlannedMoment(followUpDate, safeFollowUpTime) : { date: undefined, iso: undefined };
    const followUpLabel = followUpDate ? formatPlannedMoment(followUpMoment.iso, followUpDate) : "";
    const nextNotes = [
      orderTimelineNote(orderNoteDraft.trim(), {
        by: ownerName,
        followUpDate,
        followUpAt: followUpMoment.iso
      }),
      ...orderNotesFor(selectedOrder)
    ];
    const nextResponse = followUpLabel ? `Follow-up set for ${followUpLabel}` : selectedOrder.response;
    const orderSnapshot = selectedOrder;

    setTrackedOrders((value) =>
      value.map((order) =>
        order.id === selectedOrder.id
          ? {
              ...order,
              notes: nextNotes,
              response: nextResponse
            }
          : order
      )
    );
    setOrderNoteDraft("");
    setOrderFollowUpDate("");
    setOrderFollowUpTime(nextTimeValue());
    setShowRepFollowUpField(false);
    showToast(`${selectedOrder.id} timeline updated.`);
    ordersApi.update(selectedOrder.id, { response: nextResponse, timeline_notes: nextNotes })
      .then(async (updated: any) => {
        if (updated?.id) hydrateTrackedOrderFromApi(updated);
        await refreshFollowUpRecordsForOrder(selectedOrder.id);
      })
      .catch((err: any) => {
        setTrackedOrders((value) => value.map((order) => order.id === selectedOrder.id ? orderSnapshot : order));
        showToast(`Failed to save note for ${selectedOrder.id}: ${err?.message ?? "please retry"}.`);
      });
  };

  const resetFollowUpAttemptDraft = (task?: FollowUpTask | null) => {
    setFollowUpAttemptChannel("call");
    setFollowUpAttemptType(task?.taskType === "delivery_confirmation" ? "delivery_confirmation" : "scheduled_callback");
    setFollowUpAttemptOutcome("");
    setFollowUpAttemptNote("");
    setFollowUpAttemptTaskId(task?.id ?? "");
    setFollowUpNextActionEnabled(false);
    setFollowUpNextActionType("callback");
    setFollowUpNextActionDate(task?.dueAt ? normalizeDateKey(task.dueAt) : todayKey());
    setFollowUpNextActionTime(task?.dueAt ? splitMomentForInput(task.dueAt).time || nextTimeValue() : nextTimeValue());
    setFollowUpNextActionNote("");
  };

  const openFollowUpAttemptModal = (order: TrackedOrder, task?: FollowUpTask | null) => {
    setSelectedOrderId(order.id);
    resetFollowUpAttemptDraft(task ?? (orderFollowUpTasksByOrder[order.id] ? activeFollowUpTaskForOrder(orderFollowUpTasksByOrder[order.id]) : null));
    setModal("logFollowUpAttempt");
  };

  const submitFollowUpAttempt = async () => {
    if (!selectedOrder) return;
    if (!followUpAttemptOutcome.trim()) {
      showToast("Pick the outcome of the follow-up attempt.");
      return;
    }
    if (followUpNextActionEnabled && !isDateValue(followUpNextActionDate)) {
      showToast("Choose a valid next follow-up date.");
      return;
    }
    if (followUpNextActionEnabled && !isTimeValue(followUpNextActionTime)) {
      showToast("Choose a valid next follow-up time.");
      return;
    }

    const nextActionMoment = followUpNextActionEnabled
      ? combinePlannedMoment(followUpNextActionDate, followUpNextActionTime)
      : { iso: undefined };

    try {
      const attempt = normalizeContactAttempt(await ordersApi.logContactAttempt(selectedOrder.id, {
        taskId: followUpAttemptTaskId || null,
        channel: followUpAttemptChannel,
        attemptType: followUpAttemptType,
        outcomeCode: followUpAttemptOutcome.trim(),
        outcomeNote: followUpAttemptNote.trim() || null,
        nextActionType: followUpNextActionEnabled ? followUpNextActionType : null,
        nextActionAt: followUpNextActionEnabled ? nextActionMoment.iso ?? null : null,
        nextActionNote: followUpNextActionEnabled ? (followUpNextActionNote.trim() || followUpAttemptNote.trim() || followUpAttemptOutcome.trim()) : null
      }));

      const refreshedOrder = await ordersApi.list({ search: selectedOrder.id, limit: "1" });
      const matched = (refreshedOrder.data as any[]).find((item) => item.id === selectedOrder.id);
      if (matched) {
        const normalized = normalizeTrackedOrder(matched);
        setTrackedOrders((value) => value.map((order) => order.id === normalized.id ? normalized : order));
      }

      const [tasks, attempts] = await Promise.all([
        ordersApi.followUpTasks(selectedOrder.id),
        ordersApi.contactAttempts(selectedOrder.id)
      ]);
      setOrderFollowUpTasksByOrder((value) => ({
        ...value,
        [selectedOrder.id]: (tasks as any[]).map((task) => normalizeFollowUpTask(task))
      }));
      setOrderContactAttemptsByOrder((value) => ({
        ...value,
        [selectedOrder.id]: (attempts as any[]).map((entry) => normalizeContactAttempt(entry))
      }));
      setStatusChangeOutcomePreset(attempt.outcomeCode);
      closeModal();
      showToast(`${selectedOrder.id} follow-up logged.`);
    } catch (err: any) {
      showToast(err?.message ?? `Could not log the follow-up for ${selectedOrder.id}.`);
    }
  };

  const openRepOrderDetail = (order: TrackedOrder) => {
    // An Owner/Admin/Manager coaching inside the Sales Rep Workspace gets the
    // order in a POPUP overlay — so clicking "Details" on the Follow-up Queue
    // keeps them on that view instead of navigating to the full-page Orders
    // detail. Actual Sales Reps keep their working full-page detail (status,
    // remittance and note actions live there).
    if (realRole !== "Sales Rep") {
      setSelectedOrderId(order.id);
      setModal("orderDetails");
      return;
    }
    setSelectedOrderId(order.id);
    setRepOrderDetailId(order.id);
    // Remember the tab we came from (e.g. the Dashboard's Follow-up Queue) before
    // the detail forces us onto the Orders tab, so close can return there.
    setRepOrderDetailOriginTab(repConsoleTab);
    if (!isOrderWorkspacePage(activePage)) {
      setRepConsoleTab("Orders");
    }
    setCreateOrderAgentId(order.agentId ?? "");
    const plannedParts = splitMomentForInput(order.scheduledAt);
    setRepScheduleDate(plannedParts.date || scheduledKeyForOrder(order) || todayKey());
    setRepScheduleTime(plannedParts.time || nextTimeValue());
    setShowRepFollowUpField(false);
    setOrderFollowUpDate("");
    setOrderFollowUpTime(nextTimeValue());
    setRepDeliveryFee(order.logisticsCost != null ? String(order.logisticsCost) : "");
    setRepAmountToRemit(order.amountRemitted != null ? String(order.amountRemitted) : String(Math.max(0, order.amount - (order.logisticsCost ?? 0))));
    setRepExtraExpenses([]);
    const nextHash = isOrderWorkspacePage(activePage)
      ? repOrderWorkspaceHash(`/${order.id}`, activeRepOrderWorkspacePage)
      : repRouteWithScope(`#/dashboard/sales-rep/orders/${order.id}`);
    window.history.replaceState(null, "", `${window.location.pathname}${window.location.search}${nextHash}`);
    setHashRoute(nextHash);
  };

  const closeRepOrderDetail = () => {
    setRepOrderDetailId("");
    // Map a workspace tab back to its hash section (Dashboard = the base hash).
    const repTabToSection: Partial<Record<RepConsoleTab, string>> = {
      Products: "products",
      Orders: "orders",
      "Scheduled Deliveries": "scheduled-deliveries",
      "Abandoned Carts": "abandoned-carts",
      Customers: "customers",
      Leaderboard: "leaderboard",
      Notifications: "notifications",
      Settings: "settings"
    };
    const originSection = repTabToSection[repOrderDetailOriginTab] ?? "";
    const nextHash = isAdminOrderWorkspaceHash(hashRoute)
      ? activeOrderWorkspaceBaseHash
      : repOrderDetailOriginTab !== "Orders"
        // Opened from another tab (e.g. the Dashboard's Follow-up Queue) — go back there.
        ? repRouteWithScope(`#/dashboard/sales-rep${originSection ? `/${originSection}` : ""}`)
        : isRepOrderWorkspaceHash(hashRoute)
          ? repOrderWorkspaceHash("", activeRepOrderWorkspacePage)
          : repRouteWithScope("#/dashboard/sales-rep/orders");
    window.history.replaceState(null, "", `${window.location.pathname}${window.location.search}${nextHash}`);
    setHashRoute(nextHash);
  };

  const openRepStatusChangeModal = (order: TrackedOrder, presetStatus?: OrderStatusAction, options?: { callOutcome?: string; reason?: string }) => {
    setOrderActionReturnTarget(orderActionReturnTargetFor(order.id));
    setSelectedOrderId(order.id);
    setStatusChangePreset(presetStatus ?? null);
    setStatusChangeReasonPreset(options?.reason ?? "");
    setStatusChangeOutcomePreset(options?.callOutcome ?? order.callOutcome ?? "");
    setModal("changeOrderStatus");
    syncHashRoute(repRouteWithScope(`#/dashboard/sales-rep/orders/${order.id}/status`));
  };

  const openRepRescheduleModal = (order: TrackedOrder, reason = "", callOutcome?: string) => {
    openRepStatusChangeModal(order, "Reschedule", { reason, callOutcome });
  };

  const submitRepStatusChange = () => {
    if (!selectedOrder) return;
    const isRescheduleAction = statusChangeDraft === "Reschedule";
    const requiresReason = !isRescheduleAction && ["Cancelled", "Failed", "Postponed"].includes(statusChangeDraft);
    if (requiresReason && !statusChangeReason.trim()) {
      showToast("A reason is required when cancelling, failing, or postponing an order.");
      return;
    }
    if (isRescheduleAction && !isDateValue(orderScheduleDate)) {
      showToast("Choose a valid rescheduled delivery date.");
      return;
    }
    if (isRescheduleAction && !isTimeValue(orderScheduleTime)) {
      showToast("Choose a valid rescheduled delivery time.");
      return;
    }
    if (statusChangeDraft === "Delivered" && !deliveryDateDraft) {
      showToast("Choose the actual delivery date before saving.");
      return;
    }
    const resolvedOutcome = callOutcomeDraft === "__custom__" ? callOutcomeCustom.trim() : callOutcomeDraft;
    const outcomePayload = resolvedOutcome || (selectedOrder.callOutcome ? null : undefined);
    if (isRescheduleAction) {
      const reasonText = statusChangeReason.trim();
      const extras = [
        reasonText ? `Note: ${reasonText}.` : "",
        resolvedOutcome ? `Call outcome: ${resolvedOutcome}.` : ""
      ].filter(Boolean).join(" ");
      commitOrderSchedule(selectedOrder, {
        scheduledDate: orderScheduleDate,
        scheduledTime: orderScheduleTime,
        callOutcome: outcomePayload,
        by: currentRole === "Sales Rep" ? repScopeName : ownerName,
        noteText: (label) => extras ? `Order rescheduled for ${label}. ${extras}` : `Order rescheduled for ${label}.`
      });
    } else {
      updateOrderStatus(
        selectedOrder.id,
        statusChangeDraft,
        statusChangeReason.trim(),
        false,
        statusChangeDraft === "Delivered" ? deliveryDateDraft : undefined,
        outcomePayload
      );
    }
    setStatusChangeReason("");
    setCallOutcomeDraft("");
    setCallOutcomeCustom("");
    setDeliveryDateDraft(todayKey());
    closeModal();
  };

  const openRepEditOrderCustomer = (order: TrackedOrder) => {
    setOrderActionReturnTarget(orderActionReturnTargetFor(order.id));
    setSelectedOrderId(order.id);
    setCreateOrderCustomer(order.customer);
    setCreateOrderPhone(order.phone);
    setCreateOrderWhatsapp(order.whatsapp ?? "");
    setCreateOrderEmail(order.email ?? "");
    setCreateOrderAddress(order.address ?? "");
    setCreateOrderCity(order.city ?? "");
    setCreateOrderState(order.state ?? "");
    setCreateOrderQuantity(String(order.quantity ?? 1));
    setCreateOrderAmount(String(order.amount ?? ""));
    setModal("editOrderCustomer");
    syncHashRoute(repRouteWithScope(`#/dashboard/sales-rep/orders/${order.id}/edit-customer`));
  };

  const saveOrderCustomerEdit = () => {
    if (!selectedOrder || !createOrderCustomer.trim() || !createOrderPhone.trim()) {
      showToast("Customer name and phone are required.");
      return;
    }

    const newQty    = Math.max(1, Number(createOrderQuantity) || 1);
    const newAmount = Number(createOrderAmount) || selectedOrder.amount;
    const qtyChanged    = newQty    !== (selectedOrder.quantity ?? 1);
    const amountChanged = newAmount !== selectedOrder.amount;

    const orderSnapshot = selectedOrder;
    const nextNotes = [
      orderTimelineNote(
        `Customer/delivery details edited by ${repScopeName}.${qtyChanged ? ` Qty: ${selectedOrder.quantity ?? 1}→${newQty}.` : ""}${amountChanged ? ` Amount: ${formatProductMoney(selectedOrder.amount, selectedOrder.currency)}→${formatProductMoney(newAmount, selectedOrder.currency)}.` : ""}`,
        { by: repScopeName }
      ),
      ...orderNotesFor(selectedOrder)
    ];
    setTrackedOrders((value) =>
      value.map((order) =>
        order.id === selectedOrder.id
          ? {
              ...order,
              customer: createOrderCustomer.trim(),
              phone: createOrderPhone.trim(),
              whatsapp: createOrderWhatsapp.trim() || createOrderPhone.trim(),
              email: createOrderEmail.trim() || order.email,
              address: createOrderAddress.trim(),
              city: createOrderCity.trim(),
              state: createOrderState.trim(),
              location: orderLocationFromFields(createOrderCity, createOrderState),
              quantity: newQty,
              amount: newAmount,
              notes: nextNotes
            }
          : order
      )
    );

    // Notify owner/admin if quantity or amount was changed by the rep
    if (qtyChanged || amountChanged) {
      const changes: string[] = [];
      if (qtyChanged)    changes.push(`qty ${selectedOrder.quantity ?? 1}→${newQty}`);
      if (amountChanged) changes.push(`amount ${formatProductMoney(selectedOrder.amount, selectedOrder.currency)}→${formatProductMoney(newAmount, selectedOrder.currency)}`);
      pushSystemNotification({
        type: "info",
        title: "Order edited by rep",
        message: `${repScopeName} updated ${selectedOrder.id} (${selectedOrder.customer}): ${changes.join(", ")}`,
        orderId: selectedOrder.id,
        link: `/dashboard/admin/orders/${selectedOrder.id}`
      });
    }

    const _soceId = selectedOrder.id;
    closeModal();
    showToast(`${selectedOrder.id} saved.`);
    ordersApi.update(_soceId, {
      customer: createOrderCustomer.trim(),
      phone: createOrderPhone.trim(),
      whatsapp: createOrderWhatsapp.trim() || createOrderPhone.trim(),
      address: createOrderAddress.trim(),
      city: createOrderCity.trim(),
      state: createOrderState.trim(),
      quantity: newQty,
      amount: newAmount,
      timeline_notes: nextNotes
    }).catch((err: any) => {
      setTrackedOrders((value) => value.map((o) => o.id === _soceId ? orderSnapshot : o));
      showToast(`Failed to save ${_soceId}: ${err?.message ?? "please retry"}.`);
    });
  };

  const saveRepScheduleDate = () => {
    if (!selectedOrder || !isDateValue(repScheduleDate)) {
      showToast("Choose a valid delivery date.");
      return;
    }
    commitOrderSchedule(selectedOrder, {
      scheduledDate: repScheduleDate,
      scheduledTime: repScheduleTime,
      by: repScopeName,
      noteText: (label) => `Delivery date committed for ${label}.`
    });
  };

  const printInvoiceForOrder = (order: TrackedOrder) => {
    const printWindow = window.open("", "_blank", "width=780,height=920");
    if (!printWindow) {
      showToast("Print window was blocked.");
      return;
    }
    // Customer fields originate from the public embed form (anonymous input),
    // so anything here can be hostile. Escape every interpolation.
    const esc = (v: unknown) => String(v ?? "")
      .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;").replace(/'/g, "&#39;");
    printWindow.document.write(`<html><head><title>Invoice ${esc(order.id)}</title><style>body{font-family:Arial,sans-serif;padding:32px;color:#111827}h1{margin:0 0 8px}.meta{color:#667085;margin-bottom:24px}table{width:100%;border-collapse:collapse;margin-top:20px}th,td{border:1px solid #d0d5dd;padding:12px;text-align:left}.total{font-size:22px;font-weight:800;text-align:right;margin-top:24px}</style></head><body><h1>Protohub Invoice</h1><p class="meta">${esc(order.id)} · ${esc(order.customer)} · ${esc(order.date)}</p><p><strong>Phone:</strong> ${esc(order.phone)}</p><p><strong>Address:</strong> ${esc(order.address ?? "")} ${esc(order.city ?? "")} ${esc(order.state ?? "")}</p><table><thead><tr><th>Product</th><th>Package</th><th>Qty</th><th>Total</th></tr></thead><tbody><tr><td>${esc(order.productName)}</td><td>${esc(order.packageName)}</td><td>${esc(quantityForOrder(order))}</td><td>${esc(formatProductMoney(order.amount, order.currency))}</td></tr></tbody></table><p class="total">Grand Total: ${esc(formatProductMoney(order.amount, order.currency))}</p></body></html>`);
    printWindow.document.close();
    printWindow.print();
    showToast(`Print invoice opened for ${order.id}.`);
  };

  const downloadInvoiceForOrder = (order: TrackedOrder) => {
    const pdfEscape = (value: string) => value.replace(/\\/g, "\\\\").replace(/\(/g, "\\(").replace(/\)/g, "\\)");
    const invoiceLines = [
      "Protohub Invoice",
      `Order: ${order.id}`,
      `Customer: ${order.customer}`,
      `Phone: ${order.phone}`,
      `Address: ${[order.address, order.city, order.state].filter(Boolean).join(", ")}`,
      `Product: ${order.productName}`,
      `Package: ${order.packageName}`,
      `Quantity: ${quantityForOrder(order)}`,
      `Grand Total: ${formatProductMoney(order.amount, order.currency)}`
    ];
    const stream = `BT\n/F1 14 Tf\n${invoiceLines.map((line, index) => `1 0 0 1 72 ${740 - index * 28} Tm (${pdfEscape(line)}) Tj`).join("\n")}\nET`;
    const objects = [
      "1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n",
      "2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n",
      "3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>\nendobj\n",
      "4 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n",
      `5 0 obj\n<< /Length ${stream.length} >>\nstream\n${stream}\nendstream\nendobj\n`
    ];
    const offsets: number[] = [];
    let pdf = "%PDF-1.4\n";
    objects.forEach((object) => {
      offsets.push(pdf.length);
      pdf += object;
    });
    const xrefStart = pdf.length;
    pdf += `xref\n0 ${objects.length + 1}\n0000000000 65535 f \n${offsets.map((offset) => `${String(offset).padStart(10, "0")} 00000 n `).join("\n")}\n`;
    pdf += `trailer\n<< /Size ${objects.length + 1} /Root 1 0 R >>\nstartxref\n${xrefStart}\n%%EOF`;
    const url = URL.createObjectURL(new Blob([pdf], { type: "application/pdf" }));
    const link = document.createElement("a");
    link.href = url;
    link.download = `${order.id}-invoice.pdf`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
    showToast(`Invoice downloaded for ${order.id}.`);
  };

  const deleteSelectedOrder = () => {
    if (!selectedOrder) {
      return;
    }
    // Snapshot full state needed to undo if the server rejects the delete:
    // the order itself, the warehouse-stock restore, the audit movement.
    const orderSnapshot = selectedOrder;
    const productSnapshot = selectedOrder.stockDeducted && selectedOrder.productId
      ? products.find((p) => p.id === selectedOrder.productId)
      : null;
    let restoreMovementId: string | null = null;
    if (selectedOrder.stockDeducted && selectedOrder.productId) {
      const product = products.find((p) => p.id === selectedOrder.productId);
      const qty = quantityForOrder(selectedOrder);
      if (product) {
        const movId = makeMovementId();
        restoreMovementId = movId;
        setProducts((prev) => prev.map((p) => p.id === product.id ? { ...p, warehouseStock: p.warehouseStock + qty, unitsSold: Math.max(0, p.unitsSold - qty) } : p));
        setStockMovements((prev) => [{ id: movId, date: new Date().toISOString(), productId: product.id, productName: product.name, type: "Return", qty, balanceAfter: product.warehouseStock + qty, order: selectedOrder.id, by: ownerName, note: `Stock restored: order ${selectedOrder.id} deleted` }, ...prev]);
        stockApi.update({ productId: product.id, change: qty, note: `Stock restored: order ${selectedOrder.id} deleted` }).catch(() => { /* movement reconciles on next stockApi.movements load */ });
      }
    }
    const _doId = selectedOrder.id;
    const _doStockDeducted = selectedOrder.stockDeducted;
    setTrackedOrders((value) => value.filter((order) => order.id !== selectedOrder.id));
    setModal(null);
    if (isAdminOrderWorkspaceHash(hashRoute)) {
      setSelectedOrderId("");
      syncHashRoute(activeOrderWorkspaceBaseHash);
    } else if (isRepOrderWorkspaceHash(hashRoute)) {
      setSelectedOrderId("");
      syncHashRoute(repOrderWorkspaceHash("", activeRepOrderWorkspacePage));
    }
    showToast(`${_doId} deleted${_doStockDeducted ? " and stock restored" : ""}.`);
    ordersApi.delete(_doId).catch((err: any) => {
      // Restore the order; restore stock + units_sold; remove the audit movement we synthesized.
      setTrackedOrders((value) => [orderSnapshot, ...value]);
      if (productSnapshot) setProducts((prev) => prev.map((p) => p.id === productSnapshot.id ? productSnapshot : p));
      if (restoreMovementId) setStockMovements((prev) => prev.filter((m) => m.id !== restoreMovementId));
      showToast(`Failed to delete ${_doId}: ${err?.message ?? "please retry"}.`);
    });
  };


  const submitPublicOrder = async () => {
    if (publicOrderSubmitting) return;
    if (publicHoneypot) {
      // Spam bot — pretend success without doing anything.
      setPublicOrderSubmitted({ orderId: "blocked", customer: orderFormName.trim() });
      return;
    }
    if (!publicProduct || !orderFormName.trim() || !orderFormPhone.trim()) {
      showToast("Customer name and phone are required.");
      return;
    }

    // Reject obvious bot garbage early — Nigerian numbers are 10–11 digits;
    // accept 7–15 digits to allow international numbers and room for typos.
    const phoneDigits = orderFormPhone.replace(/\D/g, "");
    const whatsappDigits = sanitizePhoneDigitsInput(orderFormWhatsapp);
    if (phoneDigits.length < 7 || phoneDigits.length > 15) {
      showToast("Please enter a valid phone number.");
      return;
    }

    if (showWhatsappField && requireWhatsapp && !whatsappDigits) {
      showToast("WhatsApp number is required.");
      return;
    }

    if (orderFormWhatsapp.trim() && (whatsappDigits.length < 7 || whatsappDigits.length > 15)) {
      showToast("Please enter a valid WhatsApp number.");
      return;
    }

    if (addressRequired && !orderFormAddress.trim()) {
      showToast("Delivery address is required.");
      return;
    }

    if (cityRequired && !orderFormCity.trim()) {
      showToast("City is required.");
      return;
    }

    if (showDeliveryQuestion && !orderFormDeliveryWindow.trim()) {
      showToast("Please select a delivery time.");
      return;
    }

    if (requireConfirmation && !orderFormConfirmed) {
      showToast("Please confirm before submitting.");
      return;
    }

    // When commitment notice is shown without "I disagree" allowed, the
    // customer must explicitly accept. With I-disagree allowed, either
    // choice submits — we just record what they chose.
    if (showCommitmentNotice && !allowDisagree && !orderFormCommitmentAccepted) {
      showToast("Please acknowledge the commitment fee notice.");
      return;
    }

    const chosenPackage = publicPackages.find((item) => item.id === orderFormPackageId) ?? publicPackages[0];
    if (!chosenPackage) {
      showToast("Choose a package first.");
      return;
    }

    const source = orderSourceFromUtm(publicUtmSource);
    const location = orderLocationFromFields(orderFormCity, orderFormState);
    const xsLines: CrossSellLine[] = orderFormCrossSells.map((c) => {
      const p = products.find((pp) => pp.id === c.productId);
      // Companion of the chosen package (if any) overrides the standard cross-sell price.
      const companion = chosenPackage.companionProducts?.find((cmp) =>
        cmp.productId === c.productId
        && companionMatchesState(cmp, orderFormState.trim())
      );
      let qty = c.quantity;
      let amount = 0;
      if (companion && p) {
        const standard = primaryPricing(p)?.sellingPrice ?? 0;
        const unit = companion.pricingMode === "free" ? 0
                    : companion.pricingMode === "fixed" ? (companion.fixedPrice ?? 0)
                    : standard;
        qty = companion.quantity;
        amount = unit * qty;
      } else if (p) {
        amount = crossSellPriceFor(publicProduct, p) * c.quantity;
      }
      return { id: makeCrossSellLineId(), productId: c.productId, productName: p?.name ?? "Add-on", quantity: qty, amount };
    });
    // Auto-include companions ride along silently — append to xsLines so they
    // count toward total and appear as line items on the order.
    const autoCompanionLines = computeAutoCompanionLines(chosenPackage, orderFormState.trim());
    const allXsLines: CrossSellLine[] = [...xsLines, ...autoCompanionLines];
    const xsTotal = allXsLines.reduce((s, l) => s + l.amount, 0);
    const giftLines: FreeGiftLine[] = (publicProduct.freeGiftProductIds ?? []).map((gid) => {
      const p = products.find((pp) => pp.id === gid);
      if (!p || !freeGiftVisibleInState(publicProduct, p, orderFormState.trim())) return null;
      return { id: makeFreeGiftLineId(), productId: gid, productName: p.name, quantity: 1 };
    }).filter(Boolean) as FreeGiftLine[];

    const isAdminPreview = auth.isLoggedIn();
    setPublicOrderSubmitting(true);
    let createdOrderId = "";
    try {
      if (isAdminPreview) {
        // Authenticated admin previewing the form — keep the full create payload.
        const saved = await ordersApi.create({
          customer: orderFormName.trim(), phone: orderFormPhone.trim(),
          whatsapp: whatsappDigits || undefined, email: orderFormEmail.trim() || undefined,
          address: orderFormAddress.trim() || undefined, city: orderFormCity.trim() || undefined,
          state: orderFormState.trim() || undefined,
          productId: publicProduct.id, packageId: chosenPackage.id,
          productName: publicProduct.name, packageName: chosenPackage.name,
          quantity: chosenPackage.quantity, amount: chosenPackage.price + xsTotal,
          currency: chosenPackage.currency, source,
          sourceCartId: abandonedDraftCartId || undefined,
          utmSource: publicUtmSource, utmCampaign: publicUtmCampaign,
          utmMedium: publicUtmMedium || undefined,
          utmContent: publicUtmContent || undefined,
          utmTerm: publicUtmTerm || undefined,
          referrer: publicReferrer || undefined,
          confirmationChecked: orderFormConfirmed,
          preferredDelivery: orderFormDeliveryWindow.trim() || undefined,
          assignedRepId: repForNewRecord() || undefined,
          date: new Date().toISOString()
        });
        createdOrderId = saved.id;
        setTrackedOrders((value) => [
          {
            id: saved.id,
            productId: publicProduct.id,
            packageId: chosenPackage.id,
            customer: orderFormName.trim(),
            phone: orderFormPhone.trim(),
            whatsapp: whatsappDigits,
            email: orderFormEmail.trim(),
            address: orderFormAddress.trim(),
            city: orderFormCity.trim(),
            state: orderFormState.trim(),
            productName: publicProduct.name,
            packageName: chosenPackage.name,
            quantity: chosenPackage.quantity,
            amount: chosenPackage.price + xsTotal,
            currency: chosenPackage.currency,
            utmSource: publicUtmSource,
            utmCampaign: publicUtmCampaign,
            utmMedium: publicUtmMedium || undefined,
            utmContent: publicUtmContent || undefined,
            utmTerm: publicUtmTerm || undefined,
            referrer: publicReferrer || undefined,
            confirmationChecked: orderFormConfirmed,
            preferredDelivery: orderFormDeliveryWindow.trim() || undefined,
            source,
            status: "New",
            response: "Awaiting confirmation",
            location,
            deliveryWindow: orderFormDeliveryWindow.trim() || undefined,
            assignedRepId: saved.assignedRepId ?? repForNewRecord(),
            sourceCartId: abandonedDraftCartId || undefined,
            crossSellLines: allXsLines.length > 0 ? allXsLines : undefined,
            freeGiftLines: giftLines.length > 0 ? giftLines : undefined,
            notes: [
              { id: makeNoteId(), text: abandonedDraftCartId ? `Converted from abandoned cart ${abandonedDraftCartId}.` : "Order submitted from public embed form.", by: "System", date: new Date().toISOString() },
              { id: makeNoteId(), by: "Customer", date: new Date().toISOString(), text: [
                  "Public form submission details:",
                  `Customer name: ${orderFormName.trim()}`,
                  `Phone: ${orderFormPhone.trim()}`,
                  whatsappDigits ? `WhatsApp: ${whatsappDigits}` : null,
                  `Address: ${[orderFormAddress.trim(), orderFormCity.trim(), orderFormState.trim()].filter(Boolean).join(", ")}`,
                  orderFormDeliveryWindow.trim() ? `Preferred delivery: ${orderFormDeliveryWindow.trim()}` : null,
                  `Confirmation checkbox: ${orderFormConfirmed ? "Accepted" : "Not accepted"}`,
                  `Selected package(s): ${chosenPackage.name} (${chosenPackage.quantity} units, ${formatProductMoney(chosenPackage.price, chosenPackage.currency)})`,
                  `UTM source: ${publicUtmSource || "—"}`,
                  `UTM campaign: ${publicUtmCampaign || "—"}`,
                  publicUtmMedium ? `UTM medium: ${publicUtmMedium}` : null,
                  publicUtmContent ? `UTM content: ${publicUtmContent}` : null,
                  publicUtmTerm ? `UTM term: ${publicUtmTerm}` : null,
                  publicReferrer ? `Referrer: ${publicReferrer}` : null,
                ].filter(Boolean).join("\n")
              }
            ],
            createdAt: saved.createdAt ?? nowIso(),
            date: saved.date ?? new Date().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })
          },
          ...value
        ]);
      } else {
        // Anonymous customer — server recomputes amount from canonical pricing.
        // We send packageId + cross-sell line ids; server handles the math.
        const saved = await publicOrdersApi.create({
          cartId: abandonedDraftCartId || undefined,
          customer: orderFormName.trim(),
          phone: orderFormPhone.trim(),
          whatsapp: whatsappDigits || undefined,
          email: orderFormEmail.trim() || undefined,
          address: orderFormAddress.trim() || undefined,
          city: orderFormCity.trim() || undefined,
          state: orderFormState.trim() || undefined,
          packageId: chosenPackage.id,
          crossSellLines: orderFormCrossSells
            .filter((c) => c.productId && c.quantity > 0)
            .map((c) => ({ productId: c.productId, quantity: c.quantity })),
          utmSource: publicUtmSource || undefined,
          utmCampaign: publicUtmCampaign || undefined,
          utmMedium: publicUtmMedium || undefined,
          utmContent: publicUtmContent || undefined,
          utmTerm: publicUtmTerm || undefined,
          referrer: publicReferrer || undefined,
          confirmationChecked: orderFormConfirmed,
          preferredDelivery: orderFormDeliveryWindow.trim() || undefined,
          company: publicHoneypot
        });
        createdOrderId = saved.id;
      }
    } catch (err: any) {
      setPublicOrderSubmitting(false);
      publicOrderSubmittingRef.current = false;
      showToast(err?.message ?? "Could not submit your order. Please try again.");
      return;
    }
    markDraftCartConverted(createdOrderId);
    if (cartSyncTimerRef.current) {
      window.clearTimeout(cartSyncTimerRef.current);
      cartSyncTimerRef.current = null;
    }
    publicOrderSubmittingRef.current = false;
    setOrderFormName("");
    setOrderFormPhone("");
    setOrderFormWhatsapp("");
    setOrderFormEmail("");
    setOrderFormAddress("");
    setOrderFormCity("");
    setOrderFormState("");
    setOrderFormDeliveryWindow("");
    setOrderFormConfirmed(false);
    setOrderFormCommitmentAccepted(false);
    setOrderFormCrossSells([]);
    setPublicOrderSubmitting(false);
    // After submit: redirect if a redirect URL was passed in the embed link,
    // otherwise show the built-in confirmation screen.
    if (publicRedirectUrl) {
      // Allow the success state to flash briefly so the customer sees confirmation.
      setPublicOrderSubmitted({ orderId: createdOrderId, customer: orderFormName.trim() });
      setTimeout(() => {
        try {
          // Use window.top so the redirect escapes the iframe if embedded.
          (window.top ?? window).location.href = publicRedirectUrl;
        } catch {
          window.location.href = publicRedirectUrl;
        }
      }, 800);
    } else {
      setPublicOrderSubmitted({ orderId: createdOrderId, customer: orderFormName.trim() });
    }
  };

