  const adjustAgentLocationStock = (
    agentId: string,
    locationId: string,
    productId: string,
    updater: (current: DeliveryAgentLocationStock | null) => DeliveryAgentLocationStock | null
  ) => {
    setAgents((value) => value.map((agent) => {
      if (agent.id !== agentId) return agent;
      return {
        ...agent,
        locations: agentLocationRows(agent).map((location) => {
          if (location.id !== locationId) return location;
          const current = location.stock.find((row) => row.productId === productId) ?? null;
          const next = updater(current);
          const rest = location.stock.filter((row) => row.productId !== productId);
          return {
            ...location,
            stock: next ? [...rest, next] : rest
          };
        })
      };
    }));
  };

  const assignStockToSelectedAgent = () => {
    if (!selectedAgent || !assignStockProductId) {
      showToast("Choose an agent and product.");
      return;
    }
    if (isTemporaryAgentId(selectedAgent.id)) {
      showToast("This agent is still syncing. Try again in a moment.");
      return;
    }

    const quantity = Math.max(1, Number(assignStockQty) || 1);
    const product = products.find((item) => item.id === assignStockProductId);
    if (product && isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    if (!product || product.warehouseStock < quantity) {
      showToast("Not enough warehouse stock for this assignment.");
      return;
    }

    const targetLocation = findAgentLocation(selectedAgent, assignStockLocationId) ?? primaryAgentLocation(selectedAgent);
    if (!targetLocation?.id) {
      showToast("This agent has no stock hub yet.");
      return;
    }

    // Capacity check
    const capacity = selectedAgent.stockCapacity ?? 1000;
    const currentTotal = agentStock
      .filter((s) => s.agentId === selectedAgent.id)
      .reduce((sum, s) => sum + s.quantity, 0);
    if (currentTotal + quantity > capacity) {
      const available = Math.max(0, capacity - currentTotal);
      showToast(`Cannot assign — ${selectedAgent.name} capacity is ${currentTotal}/${capacity}. ${available > 0 ? `Only ${available} units available.` : "Free up stock first or increase capacity."}`);
      return;
    }

    // Snapshot the three slices we mutate so a rejected assignStock can
    // restore them coherently (warehouse + agent stock + audit movement).
    const productSnapshot = product;
    const agentSnapshot = selectedAgent;
    const existingAgentRow = agentStock.find((s) => s.agentId === selectedAgent.id && s.productId === product.id);
    const movementId = makeMovementId();
    setProducts((value) =>
      value.map((item) =>
        item.id === product.id
          ? { ...item, warehouseStock: item.warehouseStock - quantity, agentStock: item.agentStock + quantity }
          : item
      )
    );
    setAgentStock((value) => {
      const existing = value.find((stock) => stock.agentId === selectedAgent.id && stock.productId === product.id);
      if (existing) {
        return value.map((stock) => (stock === existing ? { ...stock, quantity: stock.quantity + quantity } : stock));
      }
      return [...value, { agentId: selectedAgent.id, productId: product.id, quantity, defective: 0, missing: 0 }];
    });
    adjustAgentLocationStock(selectedAgent.id, targetLocation.id, product.id, (current) => ({
      productId: product.id,
      quantity: Number(current?.quantity ?? 0) + quantity,
      defective: Number(current?.defective ?? 0),
      missing: Number(current?.missing ?? 0)
    }));
    setStockMovements((value) => [
      { id: movementId, date: new Date().toISOString(), productId: product.id, productName: product.name, type: "Distributed to Agent", qty: -quantity, balanceAfter: product.warehouseStock - quantity, agent: selectedAgent.name, by: ownerName, note: `Assigned from warehouse to ${targetLocation.name}` },
      ...value
    ]);
    const _assAgId = selectedAgent.id;
    const _assProdId = product.id;
    const _assAgentName = selectedAgent.name;
    const _assLocationId = targetLocation.id;
    const _assLocationName = targetLocation.name;
    setAssignStockQty("1");
    closeModal();
    showToast(`${quantity} ${product.name} assigned to ${selectedAgent.name} · ${targetLocation.name}.`);
    agentsApi.assignStock(_assAgId, { productId: _assProdId, quantity, locationId: _assLocationId }).catch((err: any) => {
      // Restore product warehouse/agent counts; restore (or remove) the agent_stock row;
      // remove the audit movement we synthesized.
      setProducts((value) => value.map((p) => p.id === productSnapshot.id ? productSnapshot : p));
      setAgents((value) => value.map((a) => a.id === agentSnapshot.id ? agentSnapshot : a));
      setAgentStock((value) => {
        if (existingAgentRow) {
          return value.map((s) => s.agentId === _assAgId && s.productId === _assProdId ? existingAgentRow : s);
        }
        return value.filter((s) => !(s.agentId === _assAgId && s.productId === _assProdId));
      });
      setStockMovements((value) => value.filter((m) => m.id !== movementId));
      showToast(`Failed to assign stock to ${_assAgentName}: ${err?.message ?? "please retry"}.`);
    });
      pushSystemNotification({
        type: "info",
        title: "Stock assigned to agent",
        message: `${quantity} × ${product.name} → ${_assAgentName} (warehouse now ${product.warehouseStock - quantity})`,
        productId: product.id,
      link: `/dashboard/admin/agents/${_assAgId}`
    });
  };

  const reconcileSelectedAgentStock = () => {
    if (!selectedAgent || !reconcileProductId) {
      showToast("Choose an agent and product.");
      return;
    }
    if (isTemporaryAgentId(selectedAgent.id)) {
      showToast("This agent is still syncing. Try again in a moment.");
      return;
    }

    const product = products.find((item) => item.id === reconcileProductId);
    if (product && isTemporaryProductId(product.id)) {
      showToast("This product is still syncing. Try again in a moment.");
      return;
    }
    const targetLocation = findAgentLocation(selectedAgent, reconcileLocationId) ?? primaryAgentLocation(selectedAgent);
    if (!targetLocation?.id) {
      showToast("This agent has no stock hub yet.");
      return;
    }
    const currentStock = agentStock.find((stock) => stock.agentId === selectedAgent.id && stock.productId === reconcileProductId);
    const currentQuantity = agentLocationStockQuantity(selectedAgent, targetLocation.id, reconcileProductId);
    const returned = Math.max(0, Number(reconcileReturned) || 0);
    const defective = Math.max(0, Number(reconcileDefective) || 0);
    const missing = Math.max(0, Number(reconcileMissing) || 0);
    const totalRemoved = returned + defective + missing;

    if (totalRemoved === 0) {
      showToast("Enter at least one quantity to reconcile.");
      return;
    }
    if (totalRemoved > currentQuantity) {
      showToast(`Cannot reconcile ${totalRemoved} units — agent only has ${currentQuantity}.`);
      return;
    }

    const nextQuantity = currentQuantity - totalRemoved;

    // Snapshots so we can roll back the agent_stock + warehouse + audit movements
    // if the server rejects the reconcile. Pre-fix this handler made ZERO API
    // calls — defective/missing/returned counts vanished on reload, which is real
    // money walking out the door.
    const productSnapshot = product;
    const agentStockSnapshot = currentStock;
    const agentSnapshot = selectedAgent;
    const synthesizedMovementIds: string[] = [];

    // Accumulate defective/missing tallies — do NOT reset to 0
    setAgentStock((value) =>
      value.map((stock) =>
        stock.agentId === selectedAgent.id && stock.productId === reconcileProductId
          ? {
              ...stock,
              quantity: nextQuantity,
              defective: (stock.defective ?? 0) + defective,
              missing: (stock.missing ?? 0) + missing,
            }
          : stock
      )
    );
    adjustAgentLocationStock(selectedAgent.id, targetLocation.id, reconcileProductId, (current) => {
      if (!current) return null;
      return {
        productId: current.productId,
        quantity: nextQuantity,
        defective: Number(current.defective ?? 0) + defective,
        missing: Number(current.missing ?? 0) + missing
      };
    });

    if (product) {
      // Return good stock to warehouse
      if (returned > 0) {
        setProducts((value) =>
          value.map((p) =>
            p.id === product.id
              ? { ...p, warehouseStock: p.warehouseStock + returned, agentStock: Math.max(0, p.agentStock - returned) }
              : p
          )
        );
      }

      const noteSuffix = reconcileNotes.trim() ? ` — ${reconcileNotes.trim()}` : "";
      const newMovements: StockMovement[] = [];

      // Log return and write-offs as separate movements so the history is readable
      if (returned > 0) {
        const movId = makeMovementId();
        synthesizedMovementIds.push(movId);
        newMovements.push({
          id: movId,
          date: new Date().toISOString(),
          productId: product.id,
          productName: product.name,
          type: "Return",
          qty: returned,
          balanceAfter: product.warehouseStock + returned,
          agent: selectedAgent.name,
          by: ownerName,
          note: `${returned} unit${returned !== 1 ? "s" : ""} returned to warehouse${noteSuffix}`,
        });
      }

      if (defective > 0 || missing > 0) {
        const parts: string[] = [];
        if (defective > 0) parts.push(`${defective} defective`);
        if (missing > 0) parts.push(`${missing} missing`);
        const movId = makeMovementId();
        synthesizedMovementIds.push(movId);
        newMovements.push({
          id: movId,
          date: new Date().toISOString(),
          productId: product.id,
          productName: product.name,
          type: "Correction",
          qty: -(defective + missing),
          balanceAfter: nextQuantity,
          agent: selectedAgent.name,
          by: ownerName,
          note: `${parts.join(", ")} written off${noteSuffix}`,
        });
      }

      if (newMovements.length > 0) {
        setStockMovements((value) => [...newMovements, ...value]);
      }
    }

    closeModal();
    showToast(`${selectedAgent.name} stock reconciled.`);

    // Persist server-side. The backend route updates agent_stock, books the
    // warehouse return, and inserts its own stock_movement audit rows — our
    // local synthesized movements are just optimistic placeholders that the
    // next stockApi.movements load will reconcile.
    agentsApi.reconcile(selectedAgent.id, {
      locationId: targetLocation.id,
      productId: reconcileProductId,
      returned,
      defective,
      missing,
      notes: reconcileNotes.trim() || undefined
    }).catch((err: any) => {
      // Restore agent_stock row, product warehouse counts, and remove the
      // synthesized audit movements.
      if (agentStockSnapshot) {
        setAgentStock((value) =>
          value.map((s) =>
            s.agentId === selectedAgent.id && s.productId === reconcileProductId ? agentStockSnapshot : s
          )
        );
      }
      setAgents((value) => value.map((a) => a.id === agentSnapshot.id ? agentSnapshot : a));
      if (productSnapshot && returned > 0) {
        setProducts((value) => value.map((p) => p.id === productSnapshot.id ? productSnapshot : p));
      }
      if (synthesizedMovementIds.length > 0) {
        setStockMovements((value) => value.filter((m) => !synthesizedMovementIds.includes(m.id)));
      }
      showToast(`Reconcile failed for ${selectedAgent.name}: ${err?.message ?? "please retry"}.`);
    });

    // Audit notification — surface the breakdown so anyone watching the
    // notification feed can see write-offs without digging into stock movements.
    if (product) {
      const partsLog: string[] = [];
      if (returned > 0) partsLog.push(`${returned} returned`);
      if (defective > 0) partsLog.push(`${defective} defective`);
      if (missing > 0) partsLog.push(`${missing} missing`);
      // Defective + missing are real losses — flag with low_stock-style salience
      // by giving them a distinct title; otherwise keep it info-level.
      const hasLoss = defective > 0 || missing > 0;
      pushSystemNotification({
        type: "info",
        title: hasLoss ? "Agent stock write-off" : "Agent stock reconciled",
        message: `${product.name} · ${selectedAgent.name}: ${partsLog.join(" · ")} (now ${nextQuantity})`,
        productId: product.id,
        link: `/dashboard/admin/agents/${selectedAgent.id}`
      });
      maybePushAgentLowStockNotification(product, selectedAgent, currentQuantity, nextQuantity, targetLocation);
    }
  };

  const updateSelectedAgent = () => {
    if (!selectedAgent || !agentName.trim() || !agentPhone.trim() || !agentZoneInput.trim()) {
      showToast("Agent name, phone, and zone are required.");
      return;
    }
    if (isTemporaryAgentId(selectedAgent.id)) {
      showToast("This agent is still syncing. Try again in a moment.");
      return;
    }
    const phoneDigits = agentPhone.replace(/\D/g, "");
    if (agents.some((a) => a.id !== selectedAgent.id && a.phone.replace(/\D/g, "") === phoneDigits)) {
      showToast("Another agent already has this phone number.");
      return;
    }

    const _uaId = selectedAgent.id;
    const capacityVal = typeof agentStockCapacity === "number" && agentStockCapacity > 0 ? agentStockCapacity : 1000;
    const coverageStates = agentCoverageDraftStates(agentZoneInput.trim(), agentCoverageStatesInput);
    const agentSnapshot = selectedAgent;
    setAgents((value) =>
      value.map((agent) =>
        agent.id === selectedAgent.id
          ? {
              ...agent,
              name: agentName.trim(),
              phone: agentPhone.trim(),
              whatsappPhone: agentWhatsappPhone.trim() || undefined,
              zone: agentZoneInput.trim(),
              primaryBaseState: agentZoneInput.trim(),
              coverage: coverageStates.map((state, index) => ({
                state,
                city: "",
                coverageType: "local_delivery",
                priority: index === 0 ? 0 : 100 + index,
                active: true,
                slaDays: 1
              })),
              address: (agentAddress ?? "").trim(),
              active: agentActive,
              stockCapacity: capacityVal
            }
          : agent
      )
    );
    setModal(null);
    showToast(`${agentName.trim()} updated.`);
    agentsApi.update(_uaId, {
      name: agentName.trim(),
      primaryBaseState: agentZoneInput.trim(),
      zone: agentZoneInput.trim(),
      phone: agentPhone.trim(),
      whatsappPhone: agentWhatsappPhone.trim() || undefined,
      address: (agentAddress ?? "").trim(),
      coverage: coverageStates.map((state, index) => ({
        state,
        city: "",
        coverageType: "local_delivery",
        priority: index === 0 ? 0 : 100 + index,
        active: true,
        slaDays: 1
      })),
      status: agentActive ? "Active" : "Inactive",
      stock_capacity: capacityVal
    })
      .then((saved: any) => {
        setAgents((value) => value.map((a) => a.id === _uaId ? hydrateAgentFromApi(saved, a) : a));
      })
      .catch((err: any) => {
        setAgents((value) => value.map((a) => a.id === _uaId ? agentSnapshot : a));
        showToast(`Failed to update ${agentSnapshot.name}: ${err?.message ?? "please retry"}.`);
      });
  };

  const deleteSelectedAgent = () => {
    if (!selectedAgent) return;
    if (isTemporaryAgentId(selectedAgent.id)) {
      showToast("This agent is still syncing. Try again in a moment.");
      return;
    }

    const agentStockRows = agentStock.filter((s) => s.agentId === selectedAgent.id);
    const activeStatuses: TrackedOrder["status"][] = ["New", "Confirmed", "In Process", "Dispatched"];
    const activeOrders = trackedOrders.filter((o) => o.agentId === selectedAgent.id && activeStatuses.includes(o.status));

    // Block deletion if agent has live active/dispatched orders
    if (activeOrders.length > 0) {
      showToast(`Reassign ${activeOrders.length} active order${activeOrders.length !== 1 ? "s" : ""} before deleting this agent.`);
      return;
    }

    // Snapshots covering every state slice we mutate so the agent + their
    // stock + the historical order assignments + warehouse balance all
    // restore atomically if the server rejects the delete.
    const agentSnapshot = selectedAgent;
    const agentStockSnapshot = agentStock.filter((s) => s.agentId === selectedAgent.id);
    const productsSnapshot = [...products];
    const orderAssignmentsSnapshot = trackedOrders.filter((o) => o.agentId === selectedAgent.id).map((o) => o.id);

    // Return each product's stock to the warehouse and log a movement
    const now = new Date().toISOString();
    const newMovements: StockMovement[] = [];
    const productUpdates = new Map<string, number>(); // productId → qty to return

    for (const row of agentStockRows) {
      if (row.quantity > 0) {
        productUpdates.set(row.productId, (productUpdates.get(row.productId) ?? 0) + row.quantity);
      }
    }

    if (productUpdates.size > 0) {
      setProducts((prev) =>
        prev.map((p) => {
          const qty = productUpdates.get(p.id);
          if (!qty) return p;
          newMovements.push({
            id: makeMovementId(),
            date: now,
            productId: p.id,
            productName: p.name,
            type: "Return",
            qty,
            balanceAfter: p.warehouseStock + qty,
            agent: selectedAgent.name,
            by: ownerName,
            note: `Stock returned to warehouse — agent "${selectedAgent.name}" deleted`,
          });
          return { ...p, warehouseStock: p.warehouseStock + qty, agentStock: Math.max(0, p.agentStock - qty) };
        })
      );
      setStockMovements((prev) => [...newMovements, ...prev]);
      Promise.allSettled(
        [...productUpdates].map(([productId, qty]) =>
          stockApi.update({ productId, change: qty, note: `Stock returned: agent "${selectedAgent.name}" deleted` })
        )
      ).then((results) => {
        if (results.some((r) => r.status === "rejected")) {
          showToast("Warehouse stock sync failed for some products — please reload to verify counts.");
        }
      });
    }

    // Unassign this agent from historical (non-active) orders so they don't show a ghost agent name
    setTrackedOrders((prev) =>
      prev.map((o) => (o.agentId === selectedAgent.id ? { ...o, agentId: undefined } : o))
    );

    // Remove agent and their stock records
    const _daId = selectedAgent.id;
    const synthesizedMovementIds = newMovements.map((m) => m.id);
    setAgents((prev) => prev.filter((a) => a.id !== selectedAgent.id));
    setAgentStock((prev) => prev.filter((s) => s.agentId !== selectedAgent.id));
    setModal(null);
    if (hashRoute.startsWith("#/dashboard/admin/agents/")) {
      setAgentView("list");
      setSelectedAgentId("");
      syncHashRoute("#/dashboard/admin/agents");
    }
    showToast(`${selectedAgent.name} deleted. ${productUpdates.size > 0 ? "Stock returned to warehouse." : ""}`);
    agentsApi.delete(_daId).catch((err: any) => {
      // Restore agent + their stock + the historical-order agent_id refs +
      // the warehouse counts + remove the audit movements we synthesized.
      setAgents((prev) => [agentSnapshot, ...prev]);
      setAgentStock((prev) => [...agentStockSnapshot, ...prev]);
      setProducts(productsSnapshot);
      setTrackedOrders((prev) => prev.map((o) => orderAssignmentsSnapshot.includes(o.id) ? { ...o, agentId: _daId } : o));
      if (synthesizedMovementIds.length > 0) {
        setStockMovements((prev) => prev.filter((m) => !synthesizedMovementIds.includes(m.id)));
      }
      showToast(`Failed to delete ${agentSnapshot.name}: ${err?.message ?? "please retry"}.`);
    });
  };

  const openCreateWaybillModal = () => {
    setWaybillItems([{ productId: "", quantity: "1" }]);
    setWaybillFee("0");
    setWaybillPartner("");
    setWaybillFromType("Warehouse");
    setWaybillFromAgentId("");
    setWaybillToAgentId("");
    setWaybillToState("");
    setWaybillDateSent(new Date().toISOString().slice(0, 10));
    setWaybillNote("");
    setWaybillErrors({});
    setModal("createWaybill");
  };

  const openCreateWaybill = () => {
    setActivePage("Waybill");
    openCreateWaybillModal();
    syncHashRoute("#/dashboard/admin/waybill/new");
  };

  const createWaybill = () => {
    const errs: Record<string, string> = {};
    // Collapse the line-item rows: keep the ones with a product chosen, sum
    // duplicate products into one line, and coerce each quantity to a min of 1.
    const chosenRows = waybillItems.filter((row) => row.productId);
    if (chosenRows.length === 0) errs.product = "Add at least one product.";
    if (waybillItems.some((row) => row.productId && (!row.quantity || Number(row.quantity) < 1)))
      errs.qty = "Each quantity must be at least 1.";
    const mergedQty = new Map<string, number>();
    for (const row of chosenRows) {
      mergedQty.set(row.productId, (mergedQty.get(row.productId) ?? 0) + Math.max(1, Number(row.quantity) || 1));
    }
    if (!waybillPartner.trim()) errs.partner = "Logistics partner is required.";
    if (waybillFromType === "Agent" && !waybillFromAgentId) errs.fromAgent = "Select a sending agent.";
    const fromAgent = waybillFromType === "Agent" ? agents.find((a) => a.id === waybillFromAgentId) : null;
    const fromLocation = waybillFromType === "Agent"
      ? (findAgentLocation(fromAgent, waybillFromAgentLocationId) ?? primaryAgentLocation(fromAgent))
      : null;
    const firstProductId = chosenRows[0]?.productId;
    const toAgent = waybillToAgentId ? agents.find((ag) => ag.id === waybillToAgentId) : null;
    const toLocation = toAgent
      ? (findAgentLocation(toAgent, waybillToAgentLocationId) ?? bestAgentLocationMatch(toAgent, waybillToState, undefined, firstProductId) ?? primaryAgentLocation(toAgent))
      : null;
    const receivingState = toLocation?.state || waybillToState.trim();
    if (waybillFromType === "Agent" && !fromLocation?.id) errs.fromAgent = "Select a sending hub.";
    if (waybillToAgentId && !toLocation?.id) errs.toState = "Select a receiving hub.";
    if (!receivingState) errs.toState = "Receiving state is required.";
    if (!waybillDateSent) errs.dateSent = "Date sent is required.";

    // Resolve every line to a product + quantity, then check the source has
    // enough of ALL items before deducting any (no partial dispatch).
    const lineItems = [...mergedQty.entries()]
      .map(([productId, quantity]) => {
        const product = products.find((p) => p.id === productId);
        return product ? { product, quantity } : null;
      })
      .filter(Boolean) as { product: Product; quantity: number }[];
    if (Object.keys(errs).length === 0) {
      for (const { product, quantity } of lineItems) {
        const available = waybillFromType === "Warehouse"
          ? product.warehouseStock
          : (fromLocation?.id ? agentLocationStockQuantity(fromAgent, fromLocation.id, product.id) : 0);
        if (available < quantity) {
          errs.qty = `${product.name}: only ${available} available at the source (need ${quantity}).`;
          break;
        }
      }
    }
    if (Object.keys(errs).length > 0) { setWaybillErrors(errs); return; }
    setWaybillErrors({});

    const fee = Math.max(0, Number(waybillFee) || 0);
    const sendingState = waybillFromType === "Warehouse" ? "Lagos" : (fromLocation?.state || (fromAgent ? agentPrimaryBaseState(fromAgent) : ""));
    const sendingLocationName = waybillFromType === "Warehouse" ? "Warehouse (Lagos)" : (fromLocation?.name || sendingState);
    const receivingLocationName = toLocation?.name || receivingState;
    const totalQty = lineItems.reduce((sum, li) => sum + li.quantity, 0);
    const itemsForRecord: WaybillItem[] = lineItems.map((li) => ({ productId: li.product.id, productName: li.product.name, quantity: li.quantity }));
    const itemsLabel = lineItems.map((li) => `${li.quantity} × ${li.product.name}`).join(", ");
    const isMulti = lineItems.length > 1;

    const record: WaybillRecord = {
      id: `WB-${Date.now().toString(36).toUpperCase()}`,
      // Legacy columns mirror the first item; `items` carries the full list.
      productId: lineItems[0].product.id,
      productName: isMulti ? `${lineItems[0].product.name} +${lineItems.length - 1} more` : lineItems[0].product.name,
      quantity: isMulti ? totalQty : lineItems[0].quantity,
      items: itemsForRecord,
      waybillFee: fee,
      logisticsPartner: waybillPartner.trim(),
      sendingState,
      receivingState,
      fromAgentId: waybillFromType === "Agent" ? waybillFromAgentId : undefined,
      fromAgentLocationId: waybillFromType === "Agent" ? fromLocation?.id : undefined,
      toAgentId: waybillToAgentId || undefined,
      toAgentLocationId: waybillToAgentLocationId || toLocation?.id || undefined,
      sendingLocationName,
      receivingLocationName,
      dateSent: waybillDateSent,
      status: "In Transit",
      note: waybillNote.trim() || undefined,
      createdBy: ownerName,
      createdAt: new Date().toISOString(),
    };

    // Optimistically deduct each item from its source + log a movement per item.
    for (const { product, quantity } of lineItems) {
      if (waybillFromType === "Warehouse") {
        setProducts((prev) => prev.map((p) => p.id === product.id ? { ...p, warehouseStock: Math.max(0, p.warehouseStock - quantity) } : p));
      } else {
        if (fromLocation?.id) {
          adjustAgentLocationStock(waybillFromAgentId, fromLocation.id, product.id, (current) => ({
            productId: product.id,
            quantity: Math.max(0, Number(current?.quantity ?? 0) - quantity),
            defective: Number(current?.defective ?? 0),
            missing: Number(current?.missing ?? 0)
          }));
        }
        setAgentStock((prev) => prev.map((s) => s.agentId === waybillFromAgentId && s.productId === product.id ? { ...s, quantity: s.quantity - quantity } : s));
        setProducts((prev) => prev.map((p) => p.id === product.id ? { ...p, agentStock: Math.max(0, p.agentStock - quantity) } : p));
      }
      setStockMovements((prev) => [{
        id: makeMovementId(),
        date: new Date().toISOString(),
        productId: product.id,
        productName: product.name,
        type: "Waybill Out",
        qty: -quantity,
        balanceAfter: 0,
        agent: waybillFromType === "Warehouse" ? (toAgent?.name ?? receivingState) : (fromAgent?.name ?? sendingState),
        by: ownerName,
        note: `Waybill ${record.id}: ${sendingState} → ${receivingState} via ${waybillPartner.trim()}${waybillNote.trim() ? " — " + waybillNote.trim() : ""}`,
      }, ...prev]);
    }

    setWaybillRecords((prev) => [record, ...prev]);
    // Auto-book the waybill fee as a Waybill expense so it shows on the Expense
    // board and Finance reports. Skip if no fee charged. One fee per waybill.
    if (fee > 0) {
      const expenseRecord: ExpenseRecord = {
        id: `EXP-WB-${record.id}`,
        type: "Waybill",
        amount: fee,
        currency: "NGN",
        date: String(record.dateSent ?? todayKey()).slice(0, 10),
        productId: record.productId,
        productName: record.productName,
        description: `Waybill ${record.id} — ${record.sendingState} → ${record.receivingState} via ${record.logisticsPartner} (${itemsLabel})`,
        waybillId: record.id
      };
      setExpenses((prev) => [expenseRecord, ...prev]);
      expensesApi.create({
        id: expenseRecord.id, date: expenseRecord.date, category: expenseRecord.type,
        description: expenseRecord.description, amount: expenseRecord.amount, currency: expenseRecord.currency,
        productId: expenseRecord.productId
      } as any).catch(() => {});
    }
    closeModal();
    showToast(`Waybill created — ${itemsLabel} → ${receivingState}.${fee > 0 ? ` Fee ₦${fee.toLocaleString()} booked to expenses.` : ""}`);
    // Roll back the waybill record (and the auto-booked expense) if the
    // server rejects the create. Stock movement stays as a paper trail of
    // the attempt and is reconciled by the next stockApi.movements load.
    waybillsApi.create({ id: record.id, items: itemsForRecord, productId: record.productId, productName: record.productName, quantity: record.quantity, waybillFee: record.waybillFee, fromLocation: record.sendingState, toLocation: record.receivingState, carrier: record.logisticsPartner, agentId: record.toAgentId, fromAgentId: record.fromAgentId, fromAgentLocationId: record.fromAgentLocationId, toAgentId: record.toAgentId, toAgentLocationId: record.toAgentLocationId, notes: record.note, dispatchedDate: record.dateSent } as any).catch((err: any) => {
      setWaybillRecords((prev) => prev.filter((w) => w.id !== record.id));
      if (fee > 0) setExpenses((prev) => prev.filter((e) => e.id !== `EXP-WB-${record.id}`));
      showToast(`Waybill not synced: ${err?.message ?? "please retry"}.`);
    });
    pushSystemNotification({
      type: "info",
      title: "Waybill dispatched",
      message: `${record.id}: ${itemsLabel} · ${sendingState} → ${receivingState} via ${waybillPartner.trim()}`,
      productId: lineItems[0].product.id,
      link: `/dashboard/admin/waybill`
    });
    if (waybillFromType === "Agent") {
      // Low-stock nudge per item that may have dipped below threshold.
      for (const { product } of lineItems) {
        const remaining = fromLocation?.id ? agentLocationStockQuantity(fromAgent, fromLocation.id, product.id) : 0;
        maybePushAgentLowStockNotification(product, fromAgent ?? undefined, remaining, remaining, fromLocation);
      }
    }
  };

  // When marking received, an admin can:
  //  - Accept the full dispatched qty (default — no variance)
  //  - Receive a smaller qty + tell the system what happened to the difference:
  //      "return"   → counting mistake; the difference goes back to the sender
  //      "writeoff" → lost in transit; the difference is gone
  //      "pending"  → partial delivery; don't mark received yet (skip)
  const markWaybillReceived = (
    waybillId: string,
    options?: { actualQty?: number; variance?: "return" | "writeoff" | "pending"; reason?: string }
  ) => {
    const record = waybillRecords.find((w) => w.id === waybillId);
    if (!record || record.status !== "In Transit") return;
    const product = products.find((p) => p.id === record.productId);
    const today = new Date().toISOString().slice(0, 10);
    const dispatched = record.quantity;
    const received   = Math.max(0, Math.min(dispatched, options?.actualQty ?? dispatched));
    const diff       = dispatched - received;
    const variance   = options?.variance ?? "return";

    // Multi-item waybills receive in full — per-item variance (short counts) is
    // not modeled, so add every line's quantity to the destination at once.
    const lineItems = waybillLineItems(record);
    if (lineItems.length > 1) {
      const productsSnapshotPre   = [...products];
      const agentStockSnapshotPre = [...agentStock];
      const agentsSnapshotPre     = [...agents];
      const movementIdsBefore     = new Set(stockMovements.map((m) => m.id));
      const waybillSnapshotPre    = waybillRecords.find((w) => w.id === waybillId);
      const toAgent = record.toAgentId ? agents.find((a) => a.id === record.toAgentId) : null;
      const movements: StockMovement[] = [];
      for (const it of lineItems) {
        if (it.quantity <= 0) continue;
        if (record.toAgentId) {
          setAgentStock((prev) => {
            const existing = prev.find((s) => s.agentId === record.toAgentId && s.productId === it.productId);
            if (existing) return prev.map((s) => s === existing ? { ...s, quantity: s.quantity + it.quantity } : s);
            return [...prev, { agentId: record.toAgentId!, productId: it.productId, quantity: it.quantity, defective: 0, missing: 0 }];
          });
          setProducts((prev) => prev.map((p) => p.id === it.productId ? { ...p, agentStock: p.agentStock + it.quantity } : p));
          if (record.toAgentLocationId) {
            adjustAgentLocationStock(record.toAgentId, record.toAgentLocationId, it.productId, (current) => ({
              productId: it.productId,
              quantity: Number(current?.quantity ?? 0) + it.quantity,
              defective: Number(current?.defective ?? 0),
              missing: Number(current?.missing ?? 0)
            }));
          }
        } else {
          setProducts((prev) => prev.map((p) => p.id === it.productId ? { ...p, warehouseStock: p.warehouseStock + it.quantity } : p));
        }
        movements.push({
          id: makeMovementId(),
          date: new Date().toISOString(),
          productId: it.productId,
          productName: it.productName,
          type: "Waybill In",
          qty: it.quantity,
          balanceAfter: 0,
          agent: toAgent?.name ?? record.receivingState,
          by: ownerName,
          note: `Waybill ${record.id} received: ${record.sendingState} → ${record.receivingState}`,
          waybillId: record.id
        });
      }
      if (movements.length > 0) setStockMovements((prev) => [...movements, ...prev]);
      setWaybillRecords((prev) => prev.map((w) => w.id === waybillId ? { ...w, status: "Received", dateReceived: today } : w));
      waybillsApi.updateStatus(waybillId, { status: "Received" }).catch((err: any) => {
        setProducts(productsSnapshotPre);
        setAgentStock(agentStockSnapshotPre);
        setAgents(agentsSnapshotPre);
        setStockMovements((prev) => prev.filter((m) => movementIdsBefore.has(m.id)));
        if (waybillSnapshotPre) setWaybillRecords((prev) => prev.map((w) => w.id === waybillId ? waybillSnapshotPre : w));
        showToast(`Failed to mark ${waybillId} received: ${err?.message ?? "please retry"}.`);
      });
      const itemsLabel = lineItems.map((it) => `${it.quantity} × ${it.productName}`).join(", ");
      showToast(`Waybill marked received — ${itemsLabel}.`);
      pushSystemNotification({
        type: "info",
        title: "Waybill received",
        message: `${record.id}: ${itemsLabel} arrived at ${toAgent?.name ?? "warehouse"} (${record.receivingState})`,
        productId: lineItems[0].productId,
        link: `/dashboard/admin/waybill`
      });
      return;
    }

    // Snapshots for the rollback at the bottom — the function below mutates
    // products + agentStock + agents (per-hub stock) + stockMovements +
    // waybillRecords. If the API rejects the status flip, restore all of them.
    const productsSnapshotPre   = [...products];
    const agentStockSnapshotPre = [...agentStock];
    const agentsSnapshotPre     = [...agents];
    const movementIdsBefore     = new Set(stockMovements.map((m) => m.id));
    const waybillSnapshotPre    = waybillRecords.find((w) => w.id === waybillId);

    // 1) Add `received` qty to the destination
    if (received > 0) {
      if (record.toAgentId) {
        setAgentStock((prev) => {
          const existing = prev.find((s) => s.agentId === record.toAgentId && s.productId === record.productId);
          if (existing) {
            return prev.map((s) => s === existing ? { ...s, quantity: s.quantity + received } : s);
          }
          return [...prev, { agentId: record.toAgentId!, productId: record.productId, quantity: received, defective: 0, missing: 0 }];
        });
        setProducts((prev) => prev.map((p) => p.id === record.productId ? { ...p, agentStock: p.agentStock + received } : p));
        if (record.toAgentLocationId) {
          adjustAgentLocationStock(record.toAgentId, record.toAgentLocationId, record.productId, (current) => ({
            productId: record.productId,
            quantity: Number(current?.quantity ?? 0) + received,
            defective: Number(current?.defective ?? 0),
            missing: Number(current?.missing ?? 0)
          }));
        }
      } else {
        setProducts((prev) => prev.map((p) => p.id === record.productId ? { ...p, warehouseStock: p.warehouseStock + received } : p));
      }
    }

    // 2) Handle the variance (if any)
    if (diff > 0 && variance === "return") {
      // Counting mistake — refund the difference to the SENDER (source).
      if (record.fromAgentId) {
        setAgentStock((prev) => prev.map((s) =>
          s.agentId === record.fromAgentId && s.productId === record.productId
            ? { ...s, quantity: s.quantity + diff }
            : s
        ));
        setProducts((prev) => prev.map((p) => p.id === record.productId ? { ...p, agentStock: p.agentStock + diff } : p));
        if (record.fromAgentLocationId) {
          adjustAgentLocationStock(record.fromAgentId, record.fromAgentLocationId, record.productId, (current) => ({
            productId: record.productId,
            quantity: Number(current?.quantity ?? 0) + diff,
            defective: Number(current?.defective ?? 0),
            missing: Number(current?.missing ?? 0)
          }));
        }
      } else {
        // Source was warehouse
        setProducts((prev) => prev.map((p) => p.id === record.productId ? { ...p, warehouseStock: p.warehouseStock + diff } : p));
      }
    }

    // 3) Stock movements — one for the received qty, optionally one for the variance
    if (product) {
      const toAgent   = record.toAgentId   ? agents.find((a) => a.id === record.toAgentId)   : null;
      const fromAgent = record.fromAgentId ? agents.find((a) => a.id === record.fromAgentId) : null;
      const movements: StockMovement[] = [];
      if (received > 0) {
        movements.push({
          id: makeMovementId(),
          date: new Date().toISOString(),
          productId: product.id,
          productName: product.name,
          type: "Waybill In",
          qty: received,
          balanceAfter: record.toAgentId ? 0 : product.warehouseStock + received,
          agent: toAgent?.name ?? record.receivingState,
          by: ownerName,
          note: diff > 0
            ? `Waybill ${record.id} received: ${received}/${dispatched} of ${product.name}. ${diff} short — ${variance === "return" ? "returned to sender (counting mistake)" : "written off (lost)"}${options?.reason ? ` · ${options.reason}` : ""}`
            : `Waybill ${record.id} received: ${record.sendingState} → ${record.receivingState}`,
          waybillId: record.id
        });
      }
      if (diff > 0 && variance === "return") {
        // Mirror the refund as a stock movement on the sender so the ledger is honest
        movements.push({
          id: makeMovementId(),
          date: new Date().toISOString(),
          productId: product.id,
          productName: product.name,
          type: "Return",
          qty: diff,
          balanceAfter: 0,
          agent: fromAgent?.name ?? record.sendingState,
          by: ownerName,
          note: `Waybill ${record.id} variance: ${diff} returned to sender (counting mistake)${options?.reason ? ` · ${options.reason}` : ""}`,
          waybillId: record.id
        });
      } else if (diff > 0 && variance === "writeoff") {
        movements.push({
          id: makeMovementId(),
          date: new Date().toISOString(),
          productId: product.id,
          productName: product.name,
          type: "Correction",
          qty: -diff,
          balanceAfter: 0,
          agent: fromAgent?.name ?? record.sendingState,
          by: ownerName,
          note: `Waybill ${record.id} variance: ${diff} written off (lost in transit)${options?.reason ? ` · ${options.reason}` : ""}`,
          waybillId: record.id
        });
      }
      if (movements.length > 0) {
        setStockMovements((prev) => [...movements, ...prev]);
      }
    }

    // 4) Update waybill — quantity reflects what was actually received, status flips
    setWaybillRecords((prev) => prev.map((w) => w.id === waybillId ? {
      ...w,
      status: "Received",
      dateReceived: today,
      quantity: received,
      note: diff > 0
        ? `${w.note ? w.note + " · " : ""}Variance: ${diff}/${dispatched} ${variance === "return" ? "returned" : "written off"}${options?.reason ? ` (${options.reason})` : ""}`
        : w.note
    } : w));
    waybillsApi.updateStatus(waybillId, { status: "Received" }).catch((err: any) => {
      // Restore every slice this handler touched.
      setProducts(productsSnapshotPre);
      setAgentStock(agentStockSnapshotPre);
      setAgents(agentsSnapshotPre);
      setStockMovements((prev) => prev.filter((m) => movementIdsBefore.has(m.id)));
      if (waybillSnapshotPre) {
        setWaybillRecords((prev) => prev.map((w) => w.id === waybillId ? waybillSnapshotPre : w));
      }
      showToast(`Failed to mark ${waybillId} received: ${err?.message ?? "please retry"}.`);
    });
    showToast(diff > 0
      ? `Waybill received with ${diff} short — variance ${variance === "return" ? "returned to sender" : "written off"}.`
      : `Waybill marked received.`);
    if (product) {
      const toAgentName = record.toAgentId ? agents.find((a) => a.id === record.toAgentId)?.name : null;
      pushSystemNotification({
        type: "info",
        title: "Waybill received",
        message: `${record.id}: ${record.quantity} × ${product.name} arrived at ${toAgentName ?? "warehouse"} (${record.receivingState})`,
        productId: product.id,
        link: `/dashboard/admin/waybill`
      });
    }
  };

  const cancelWaybill = (waybillId: string) => {
    const record = waybillRecords.find((w) => w.id === waybillId);
    if (!record || record.status !== "In Transit") return;
    // Restore every line back to the source (per item for multi-item waybills).
    const lineItems = waybillLineItems(record);
    const fromAgent = record.fromAgentId ? agents.find((a) => a.id === record.fromAgentId) : null;
    const movements: StockMovement[] = [];
    for (const it of lineItems) {
      if (it.quantity <= 0) continue;
      const product = products.find((p) => p.id === it.productId);
      if (record.fromAgentId) {
        setAgentStock((prev) => prev.map((s) => s.agentId === record.fromAgentId && s.productId === it.productId ? { ...s, quantity: s.quantity + it.quantity } : s));
        setProducts((prev) => prev.map((p) => p.id === it.productId ? { ...p, agentStock: p.agentStock + it.quantity } : p));
      } else {
        setProducts((prev) => prev.map((p) => p.id === it.productId ? { ...p, warehouseStock: p.warehouseStock + it.quantity } : p));
      }
      movements.push({
        id: makeMovementId(),
        date: new Date().toISOString(),
        productId: it.productId,
        productName: it.productName || product?.name || "",
        type: "Waybill In",
        qty: it.quantity,
        balanceAfter: 0,
        agent: record.fromAgentId ? (fromAgent?.name ?? record.sendingState) : "Warehouse",
        by: ownerName,
        note: `Waybill ${record.id} cancelled — stock returned to ${record.fromAgentId ? record.sendingState : "warehouse"}`,
      });
    }
    if (movements.length > 0) setStockMovements((prev) => [...movements, ...prev]);

    setWaybillRecords((prev) => prev.map((w) => w.id === waybillId ? { ...w, status: "Cancelled" } : w));
    waybillsApi.updateStatus(waybillId, { status: "Cancelled" }).catch((err: any) => {
      setWaybillRecords((prev) => prev.map((w) => w.id === waybillId ? { ...w, status: "In Transit" } : w));
      showToast(`Failed to cancel waybill: ${err.message}`);
    });
    showToast(`Waybill cancelled. Stock returned to sender.`);
    const itemsLabel = lineItems.map((it) => `${it.quantity} × ${it.productName}`).join(", ");
    pushSystemNotification({
      type: "info",
      title: "Waybill cancelled",
      message: `${record.id}: ${itemsLabel} returned to ${record.fromAgentId ? record.sendingState : "warehouse"}`,
      productId: lineItems[0]?.productId,
      link: `/dashboard/admin/waybill`
    });
  };

  const openEditWaybillModal = (waybillId: string, record?: WaybillRecord) => {
    setWaybillEditId(waybillId);
    setWaybillFee(String(record?.waybillFee ?? 0));
    setWaybillPartner(record?.logisticsPartner ?? "");
    setWaybillToAgentId(record?.toAgentId ?? "");
    setWaybillToState(record?.receivingState ?? "");
    setWaybillDateSent(record?.dateSent ?? new Date().toISOString().slice(0, 10));
    setWaybillNote(record?.note ?? "");
    setWaybillErrors({});
    setModal("editWaybill");
  };

  const openEditWaybill = (record: WaybillRecord) => {
    setActivePage("Waybill");
    openEditWaybillModal(record.id, record);
    syncHashRoute(`#/dashboard/admin/waybill/${record.id}/edit`);
  };

  const openReceiveWaybillModal = (waybillId: string, record?: WaybillRecord) => {
    setReceiveWaybillId(waybillId);
    setReceiveActualQty(record ? String(record.quantity) : "");
    setReceiveVarianceReason("");
    setReceiveVarianceMode("return");
    setModal("receiveWaybill");
  };

  const openReceiveWaybill = (record: WaybillRecord) => {
    setActivePage("Waybill");
    openReceiveWaybillModal(record.id, record);
    syncHashRoute(`#/dashboard/admin/waybill/${record.id}/receive`);
  };

  const [waybillDetailId, setWaybillDetailId] = useState("");
  const openWaybillDetail = (record: WaybillRecord) => {
    setWaybillDetailId(record.id);
    setModal("waybillDetails");
  };

  const saveEditWaybill = () => {
    const errs: Record<string, string> = {};
    if (!waybillPartner.trim()) errs.partner = "Logistics partner is required.";
    const toAgent = waybillToAgentId ? agents.find((a) => a.id === waybillToAgentId) : null;
    const receivingState = toAgent ? agentPrimaryBaseState(toAgent) : waybillToState.trim();
    if (!receivingState) errs.toState = "Receiving state is required.";
    if (!waybillDateSent) errs.dateSent = "Date sent is required.";
    if (Object.keys(errs).length > 0) { setWaybillErrors(errs); return; }
    setWaybillErrors({});
    const updatedFee = Math.max(0, Number(waybillFee) || 0);
    setWaybillRecords((prev) => prev.map((w) => w.id === waybillEditId ? {
      ...w,
      waybillFee: updatedFee,
      logisticsPartner: waybillPartner.trim(),
      toAgentId: waybillToAgentId || undefined,
      receivingState,
      dateSent: waybillDateSent,
      note: waybillNote.trim() || undefined,
    } : w));
    closeModal();
    showToast("Waybill updated.");
    waybillsApi.update(waybillEditId!, {
      waybill_fee: updatedFee,
      carrier: waybillPartner.trim(),
      to_location: receivingState,
      agent_id: waybillToAgentId || null,
      dispatched_date: waybillDateSent,
      notes: waybillNote.trim() || null,
    }).catch((err: any) => showToast(`Failed to save waybill: ${err.message}`));
  };

  const openCartModal = (cart: AbandonedCartRecord, nextModal: ModalType) => {
    setSelectedCartId(cart.id);
    setReassignRepId(cart.assignedRepId ?? activeSalesRepUsers[0]?.id ?? "");
    setModal(nextModal);
  };

  const assignSelectedCart = () => {
    if (!selectedCart || !reassignRepId) {
      showToast("Choose a sales rep.");
      return;
    }

    // Snapshot for rollback. The optimistic update happens immediately so the
    // modal can close without flicker; a server failure restores the row.
    const cartSnapshot = selectedCart;
    const targetCartId = selectedCart.id;
    setAbandonedCarts((value) => value.map((cart) => (cart.id === targetCartId ? { ...cart, assignedRepId: reassignRepId, status: "Assigned", lastActivity: new Date().toISOString() } : cart)));
    closeModal();
    showToast(`${targetCartId} assigned to ${users.find((user) => user.id === reassignRepId)?.name ?? "sales rep"}.`);
    // Persist — the previous version was local-only; reassignments were lost on reload.
    cartsApi.update(targetCartId, { assignedRepId: reassignRepId, status: "Assigned" }).catch((err: any) => {
      setAbandonedCarts((value) => value.map((cart) => (cart.id === targetCartId ? cartSnapshot : cart)));
      showToast(`Failed to assign ${targetCartId}: ${err?.message ?? "please retry"}.`);
    });
  };

  const updateCartStatus = (cartId: string, status: Exclude<CartStatus, "All statuses">) => {
    const snapshot = abandonedCarts.find((c) => c.id === cartId);
    setAbandonedCarts((value) => value.map((cart) => (cart.id === cartId ? { ...cart, status, lastActivity: new Date().toISOString() } : cart)));
    cartsApi.update(cartId, { status }).catch((err: any) => {
      // Roll back local state so the table doesn't lie about persistence.
      if (snapshot) setAbandonedCarts((value) => value.map((cart) => (cart.id === cartId ? snapshot : cart)));
      showToast(`Failed to save status for ${cartId}: ${err?.message ?? "please retry"}.`);
    });
    showToast(`${cartId} marked ${status}.`);
  };

  const bulkUpdateCartStatus = async (status: Exclude<CartStatus, "All statuses" | "Converted">) => {
    if (selectedCartIds.size === 0) return;
    const ids = Array.from(selectedCartIds).filter((id) => {
      const cart = abandonedCarts.find((c) => c.id === id);
      return cart && cart.status !== "Converted";
    });
    // Snapshot the slice we're about to mutate so partial failures can revert
    // their own ids without disturbing the ones that succeeded.
    const snapshots = new Map(abandonedCarts.filter((c) => ids.includes(c.id)).map((c) => [c.id, c]));
    setAbandonedCarts((value) =>
      value.map((cart) =>
        selectedCartIds.has(cart.id) && cart.status !== "Converted"
          ? { ...cart, status, lastActivity: new Date().toISOString() }
          : cart
      )
    );
    setSelectedCartIds(new Set());
    const results = await Promise.allSettled(
      ids.map((id) => cartsApi.update(id, { status }))
    );
    const failedIds: string[] = [];
    results.forEach((r, i) => { if (r.status === "rejected") failedIds.push(ids[i]); });
    if (failedIds.length > 0) {
      setAbandonedCarts((value) =>
        value.map((cart) => failedIds.includes(cart.id) ? (snapshots.get(cart.id) ?? cart) : cart)
      );
      showToast(`${ids.length - failedIds.length} cart${ids.length - failedIds.length !== 1 ? "s" : ""} marked ${status}. ${failedIds.length} failed — please retry.`);
    } else {
      showToast(`${ids.length} cart${ids.length > 1 ? "s" : ""} marked ${status}.`);
    }
  };

  const deleteCartRecord = (cart: AbandonedCartRecord) => {
    const canDelete = auth.getUser()?.role === "Owner" || auth.getUser()?.role === "Admin";
    if (!canDelete) {
      showToast("Only Owner/Admin can delete abandoned carts.");
      return;
    }
    if (!window.confirm(`Delete abandoned cart ${cart.id} for ${cart.customer || "this customer"}? This cannot be undone.`)) {
      return;
    }

    const cartSnapshot = cart;
    const wasSelected = selectedCartId === cart.id;
    const wasModalOpen = wasSelected && ["cartDetails", "assignCart", "convertCart"].includes(modal ?? "");
    const routeWasFocused = hashRoute.startsWith(`#/dashboard/admin/abandoned-carts/${cart.id}`);
    setAbandonedCarts((value) => value.filter((item) => item.id !== cart.id));
    setSelectedCartIds((prev) => {
      const next = new Set(prev);
      next.delete(cart.id);
      return next;
    });
    if (wasSelected) {
      setSelectedCartId("");
    }
    if (wasModalOpen) {
      closeModal();
    }
    if (routeWasFocused) {
      syncHashRoute("#/dashboard/admin/abandoned-carts");
    }
    showToast(`${cart.id} deleted.`);

    cartsApi.delete(cart.id).catch((err: any) => {
      setAbandonedCarts((value) => [cartSnapshot, ...value.filter((item) => item.id !== cartSnapshot.id)]);
      showToast(`Failed to delete ${cartSnapshot.id}: ${err?.message ?? "please retry"}.`);
    });
  };

  const exportCartsCsv = () => {
    const exportConverted = filteredAbandonedCarts.filter((c) => c.status === "Converted").length;
    const exportLost = filteredAbandonedCarts.filter((c) => ["No response", "Not interested"].includes(c.status)).length;
    const exportRate = filteredAbandonedCarts.length === 0
      ? 0
      : Math.round((exportConverted / filteredAbandonedCarts.length) * 100);
    const rows: (string | number | null | undefined)[][] = [
      ["Abandoned Carts Report"],
      csvWorkspaceRow(),
      csvGeneratedRow(),
      ["Period", cartsPeriod === "Custom" && cartsDateRange.start && cartsDateRange.end ? `${cartsDateRange.start} to ${cartsDateRange.end}` : cartsPeriod],
      ["Currency", selectedCurrency.label],
      ["Search", cartSearch || "All"],
      ["Status", cartStatus],
      ["Product Filter", cartProductIds.size === 0 ? "All Products" : products.filter(p => cartProductIds.has(p.id)).map(p => p.name).join(", ")],
      ["Total Captured", String(filteredAbandonedCarts.length)],
      ["Converted", String(exportConverted)],
      ["Team Converted", String(teamRecoveredCartRows.length)],
      ["Team Converted Delivered", String(teamRecoveredDeliveredRows.length)],
      ["Team Converted Pending", String(teamRecoveredPendingRows.length)],
      ["Team Converted Failed / Cancelled", String(teamRecoveredFailedRows.length)],
      ["Team Recovered Revenue", formatProductMoney(teamRecoveredRevenue, teamRecoveryCurrency)],
      ["Pending Recovered Value", formatProductMoney(teamRecoveredPipelineValue, teamRecoveryCurrency)],
      ["Converted With Missing Linked Order", String(convertedMissingLinkedOrderRows.length)],
      ["Customer Finished Later", String(customerFinishedLaterRows.length)],
      ["Lost", String(exportLost)],
      ["Conversion Rate", `${exportRate}%`],
      [],
      ["Cart ID", "Customer", "Phone", "Product", "Package", "Amount", "Cart Status", "Conversion Path", "Linked Order", "Linked Order Status", "Recovered By", "Outcome Bucket", "Source", "Rep", "Created", "Last Activity"],
      ...filteredAbandonedCarts.map((cart) => {
        const recoveryRow = abandonedCartRecoveryRows.find((row) => row.cart.id === cart.id);
        const linkedStatus = recoveryRow?.linkedStatus ?? "";
        const outcomeBucket = recoveryRow?.conversionKind === "manual_recovery"
          ? linkedStatus === "Delivered"
            ? "Delivered"
            : abandonedCartIsBadRecoveredOutcome(linkedStatus)
              ? "Failed / Cancelled"
              : "Pending"
          : recoveryRow?.conversionKind === "customer_self_completed"
            ? "Customer finished later"
            : cart.status === "Converted"
              ? "Converted but missing linked order"
              : "";
        return [
          cart.id,
          cart.customer,
          cart.phone,
          cart.productName,
          cart.packageName,
          formatProductMoney(cart.amount, cart.currency),
          cart.status,
          recoveryRow?.conversionKind === "manual_recovery" ? "Recovered by Team" : recoveryRow?.conversionKind === "customer_self_completed" ? "Customer Finished Later" : "",
          recoveryRow?.linkedOrder?.id ?? "",
          linkedStatus,
          recoveryRow?.conversionKind === "manual_recovery" ? recoveryRow.converterName : "",
          outcomeBucket,
          cart.source,
          users.find((u) => u.id === cart.assignedRepId)?.name ?? "Unassigned",
          cart.createdAt,
          cart.lastActivity
        ];
      })
    ];
    triggerCsvDownload("abandoned-carts", rows, "Abandoned carts exported as CSV.");
  };

  const exportDeliveriesCsv = () => {
    const rows: (string | number | null | undefined)[][] = [
      ["Deliveries Report"],
      csvWorkspaceRow(),
      csvGeneratedRow(),
      ["Period", deliveriesPeriod === "Custom" && deliveriesDateRange.start && deliveriesDateRange.end ? `${deliveriesDateRange.start} to ${deliveriesDateRange.end}` : deliveriesPeriod],
      ["Currency", selectedCurrency.label],
      ["Product Filter", deliveriesProductIds.size === 0 ? "All Products" : products.filter(p => deliveriesProductIds.has(p.id)).map(p => p.name).join(", ")],
      ["Agent Filter", deliveryAgent],
      ["Search", deliverySearch || "All"],
      ["Total Delivered", String(filteredDeliveryRows.length)],
      ["Total Revenue", formatMoney(deliveredRevenueInPeriod)],
      ["Avg Fulfillment", `${averageFulfillmentDays.toFixed(1)} days`],
      [],
      ["Order ID", "Customer", "Phone", "Product", "Package", "Qty", "City", "State", "Location", "Agent", "Delivered Date", "Fulfillment Days", "Revenue"],
      ...filteredDeliveryRows.map((order) => [
        order.id,
        order.customer,
        order.phone,
        order.productName,
        order.packageName,
        String(quantityForOrder(order)),
        order.city ?? "",
        order.state ?? "",
        order.location ?? orderLocationFromFields(order.city ?? "", order.state ?? ""),
        agentNameForOrder(order),
        order.deliveredDate,
        fulfillmentDaysForOrder(order).toFixed(1),
        formatProductMoney(order.amount, order.currency)
      ]),
      [
        "TOTAL", "", "", "", "",
        String(filteredDeliveryRows.reduce((s, o) => s + quantityForOrder(o), 0)),
        "", "", "", "", "", "",
        formatMoney(filteredDeliveryRows.reduce((s, o) => s + o.amount, 0))
      ]
    ];
    triggerCsvDownload("deliveries-report", rows, "Deliveries exported as CSV.");
  };

  const convertSelectedCart = async () => {
    if (!selectedCart) {
      return;
    }

    const draftOrder: Omit<TrackedOrder, "id"> = {
      productId: selectedCart.productId,
      packageId: selectedCart.packageId,
      customer: selectedCart.customer,
      phone: selectedCart.phone,
      whatsapp: selectedCart.whatsapp,
      email: selectedCart.email,
      city: selectedCart.city,
      state: selectedCart.state,
      productName: selectedCart.productName,
      packageName: selectedCart.packageName,
      quantity: products.find((product) => product.id === selectedCart.productId)?.packages.find((item) => item.id === selectedCart.packageId)?.quantity ?? 1,
      amount: selectedCart.amount,
      currency: selectedCart.currency,
      utmSource: selectedCart.source.toLowerCase(),
      utmCampaign: "cart_recovery",
      source: selectedCart.source,
      status: "New",
      response: "Converted from abandoned cart",
      location: orderLocationFromFields(selectedCart.city ?? "", selectedCart.state ?? ""),
      assignedRepId: selectedCart.assignedRepId ?? repForNewRecord(),
      createdAt: nowIso(),
      date: displayDateFromKey(todayKey()),
      notes: [{ id: makeNoteId(), text: `Converted from ${selectedCart.id}.`, by: ownerName, date: nowIso() }]
    };
    const cartSnapshot = selectedCart;
    let orderId = "";
    try {
      const saved = await ordersApi.create({ ...draftOrder, sourceCartId: selectedCart.id });
      const order: TrackedOrder = {
        ...draftOrder,
        id: saved.id,
        sourceCartId: selectedCart.id,
        assignedRepId: saved.assignedRepId ?? draftOrder.assignedRepId,
        createdAt: saved.createdAt ?? draftOrder.createdAt,
        date: saved.date ?? draftOrder.date,
        location: saved.location ?? draftOrder.location
      };
      orderId = order.id;
      setTrackedOrders((value) => [order, ...value]);
      setAbandonedCarts((value) => value.map((cart) => (cart.id === selectedCart.id ? { ...cart, status: "Converted", lastActivity: new Date().toISOString() } : cart)));
      closeModal();
      showToast(`${selectedCart.id} converted to ${order.id}.`);
    } catch (err: any) {
      showToast(`Failed to convert ${cartSnapshot.id}: ${err?.message ?? "please retry"}.`);
      return;
    }

    // Mark the cart as Converted on the server too so it doesn't keep
    // showing up as Open Abandoned for other admins.
    cartsApi.update(selectedCart.id, { status: "Converted" }).catch((err: any) => {
      setAbandonedCarts((value) => value.map((cart) => cart.id === cartSnapshot.id ? cartSnapshot : cart));
      showToast(`Cart status not synced: ${err?.message ?? "please retry"}.`);
    });

    // Conversion-specific notification (in addition to the backend's
    // order_new) — captures the cart→order link with the cart ID surfaced.
    pushSystemNotification({
      type: "info",
      title: "Cart Converted",
      message: `${selectedCart.id} converted to ${orderId} — ${draftOrder.customer} (${draftOrder.productName})`,
      orderId,
      link: `/dashboard/admin/orders/${orderId}`
    });
  };

