  const toggleManagedUserActive = (user: ManagedUser) => {
    if (isTemporaryUserId(user.id)) {
      showToast("This user is still syncing. Try again in a moment.");
      return;
    }
    const prevActive = user.active;
    setUsers((value) => value.map((item) => item.id === user.id ? { ...item, active: !item.active } : item));
    showToast(`${user.name} marked ${user.active ? "inactive" : "active"}.`);
    usersApi.update(user.id, { active: !prevActive }).catch((err: any) => {
      setUsers((value) => value.map((item) => item.id === user.id ? { ...item, active: prevActive } : item));
      showToast(`Failed to update status: ${err.message}`);
    });
  };
  // Pause / resume a rep in the round-robin WITHOUT touching their login (active).
  // On re-enable they rejoin at the BACK of the line (max active position + 1) so
  // they don't jump ahead of reps who covered while they were paused. Persisted via
  // teamApi (which owns round_robin_position); optimistic with rollback.
  const toggleManagedUserRoundRobin = (user: ManagedUser) => {
    if (isTemporaryUserId(user.id)) {
      showToast("This user is still syncing. Try again in a moment.");
      return;
    }
    const prevExcluded = user.roundRobinExcluded === true;
    const nextExcluded = !prevExcluded;
    const prevPosition = user.roundRobinPosition ?? 0;
    const maxActivePos = users
      .filter((u) => u.role === "Sales Rep" && u.active && !u.roundRobinExcluded && u.id !== user.id)
      .reduce((m, u) => Math.max(m, u.roundRobinPosition ?? 0), 0);
    const nextPosition = nextExcluded ? prevPosition : maxActivePos + 1;
    setUsers((value) => value.map((item) =>
      item.id === user.id ? { ...item, roundRobinExcluded: nextExcluded, roundRobinPosition: nextPosition } : item));
    showToast(nextExcluded
      ? `${user.name} paused from rotation (still has account access).`
      : `${user.name} is back in rotation — at the back of the line.`);
    const payload: Record<string, unknown> = { roundRobinExcluded: nextExcluded };
    if (!nextExcluded) payload.roundRobinPosition = nextPosition;
    teamApi.update(user.id, payload).catch((err: any) => {
      setUsers((value) => value.map((item) =>
        item.id === user.id ? { ...item, roundRobinExcluded: prevExcluded, roundRobinPosition: prevPosition } : item));
      showToast(`Failed to update rotation: ${err.message}`);
    });
  };

  const createExpense = () => {
    const parsedAmount = Number(expenseAmount);
    if (!expenseAmount.trim() || isNaN(parsedAmount)) {
      showToast("Expense amount is required and must be a number.");
      return;
    }

    const product = products.find((item) => item.id === expenseProduct);
    const amount = Math.max(0, parsedAmount);
    const record: ExpenseRecord = {
      id: makeExpenseId(),
      type: expenseType,
      amount,
      currency: expenseCurrency,
      date: parseExpenseDateKey(expenseDate),
      createdAt: nowIso(),
      productId: product?.id,
      productName: product?.name ?? expenseProduct,
      description: expenseDescription.trim() || `${expenseType} expense`
    };
    setExpenses((value) => [record, ...value]);
    setExpenseAmount("0");
    setExpenseDescription("");
    setExpenseDate(todayKey());
    setExpenseProduct("General Expense");
    setExpenseCurrency("NGN");
    closeModal();
    showToast(`${expenseType} expense for ${new Intl.NumberFormat(currencies[expenseCurrency]?.locale ?? "en-NG", { style: "currency", currency: expenseCurrency, maximumFractionDigits: 0 }).format(amount)} created.`);
    expensesApi.create({ id: record.id, date: record.date, category: record.type, description: record.description, amount: record.amount, currency: record.currency }).catch((err: any) => {
      setExpenses((prev) => prev.filter((e) => e.id !== record.id));
      showToast(`Failed to create expense: ${err.message}`);
    });
  };

  const createUser = () => {
    if (!userFullName.trim() || !userEmail.trim()) {
      showToast("User name and email are required.");
      return;
    }
    const userPhoneDigits = userPhone.replace(/\D/g, "");
    if (newUserRole === "Sales Rep" && userPhoneDigits.length < 7) {
      showToast("Sales reps need a valid phone number so customers can reach them from SMS updates.");
      return;
    }
    const marketingTags = sanitizeMarketingAttributionTags(userMarketingTagDraft);
    if (newUserRole === "Marketer" && marketingTags.length === 0) {
      showToast("Add at least one marketing attribution tag for this marketer.");
      return;
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(userEmail.trim())) {
      showToast("Please enter a valid email address.");
      return;
    }

    if (userPassword.trim().length < 8) {
      showToast("Password must be at least 8 characters.");
      return;
    }

    if (users.some((user) => user.email.toLowerCase() === userEmail.trim().toLowerCase())) {
      showToast("A user with this email already exists.");
      return;
    }
    if (userPhoneDigits && users.some((user) => user.phone?.replace(/\D/g, "") === userPhoneDigits)) {
      showToast("Another team member already uses this phone number.");
      return;
    }

    const defaultPermissions = defaultPermissionsForRole(newUserRole);
    const id = `${Date.now()}-${slugify(userEmail.trim())}`;
    setUsers((value) => [
      ...value,
      {
        id,
        name: userFullName.trim(),
        email: userEmail.trim(),
        phone: userPhone.trim(),
        role: newUserRole,
        active: newUserActive,
        created: nowIso(),
        permissions: defaultPermissions,
        marketingAttributionTags: marketingTags
      }
    ]);
    setUserPhone("");
    setUserPassword("");
    setShowPasswordFields({});
    closeModal();
    showToast(`User "${userFullName.trim()}" created.`);
    authApi.invite({ name: userFullName.trim(), email: userEmail.trim(), phone: userPhone.trim(), password: userPassword.trim(), role: newUserRole, marketingAttributionTags: marketingTags })
      .then(() => {
        usersApi.list().then((all: any[]) => {
          const saved = all.find((u: any) => u.email?.toLowerCase() === userEmail.trim().toLowerCase());
          if (saved) {
            setUsers((prev) => prev.map((u) => u.id === id ? {
              ...u,
              id: saved.id,
              phone: saved.phone ?? u.phone,
              lastSeenAt: saved.lastSeenAt ?? saved.last_seen_at ?? u.lastSeenAt,
              permissions: defaultPermissions,
              marketingAttributionTags: sanitizeMarketingAttributionTags(saved.marketingAttributionTags ?? saved.marketing_attribution_tags ?? marketingTags)
            } : u));
            teamApi.update(saved.id, { permissions: defaultPermissions }).catch(() => undefined);
          }
        }).catch(() => {});
      })
      .catch((err: any) => {
        setUsers((prev) => prev.filter((u) => u.id !== id));
        showToast(`Failed to create user: ${err.message}`);
      });
  };

  const updateUser = () => {
    if (!selectedUser || !userFullName.trim() || !userEmail.trim()) {
      showToast("User name and email are required.");
      return;
    }
    if (isTemporaryUserId(selectedUser.id)) {
      showToast("This user is still syncing. Try again in a moment.");
      return;
    }
    const userPhoneDigits = userPhone.replace(/\D/g, "");
    if (newUserRole === "Sales Rep" && userPhoneDigits.length < 7) {
      showToast("Sales reps need a valid phone number so customers can reach them from SMS updates.");
      return;
    }
    const marketingTags = sanitizeMarketingAttributionTags(userMarketingTagDraft);
    if (newUserRole === "Marketer" && marketingTags.length === 0) {
      showToast("Add at least one marketing attribution tag for this marketer.");
      return;
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(userEmail.trim())) {
      showToast("Please enter a valid email address.");
      return;
    }

    if (userPassword.trim() && userPassword.trim().length < 8) {
      showToast("New password must be at least 8 characters.");
      return;
    }

    if (users.some((user) => user.id !== selectedUser.id && user.email.toLowerCase() === userEmail.trim().toLowerCase())) {
      showToast("Another user already uses this email.");
      return;
    }
    if (userPhoneDigits && users.some((user) => user.id !== selectedUser.id && user.phone?.replace(/\D/g, "") === userPhoneDigits)) {
      showToast("Another user already uses this phone number.");
      return;
    }
    if (selectedUser.role === "Owner" && newUserRole !== "Owner") {
      showToast("The Owner role cannot be changed.");
      return;
    }

    const prevUsers = users;
    const _uuId = selectedUser.id;
    const _uuPw = userPassword.trim();
    setUsers((value) =>
      value.map((user) =>
        user.id === selectedUser.id
          ? { ...user, name: userFullName.trim(), email: userEmail.trim(), phone: userPhone.trim(), role: newUserRole, active: newUserActive, marketingAttributionTags: marketingTags }
          : user
      )
    );
    setUserPassword("");
    setShowPasswordFields({});
    closeModal();
    showToast(`User "${userFullName.trim()}" updated.`);
    teamApi.update(_uuId, { name: userFullName.trim(), email: userEmail.trim(), phone: userPhone.trim(), role: newUserRole, active: newUserActive, marketingAttributionTags: marketingTags }).catch((err: any) => {
      setUsers(prevUsers);
      showToast(`Failed to update user: ${err.message}`);
    });
    // Password change goes through a dedicated auth endpoint — sending it
    // alongside the team patch would be silently dropped by the backend.
    if (_uuPw) {
      authApi.setPassword(_uuId, _uuPw).catch((err: any) => {
        showToast(`Profile saved, but password change failed: ${err.message}`);
      });
    }
  };

  const resetUserPassword = () => {
    if (!selectedUser) {
      showToast("Choose a user first.");
      return;
    }
    if (isTemporaryUserId(selectedUser.id)) {
      showToast("This user is still syncing. Try again in a moment.");
      return;
    }

    if (userPassword.trim().length < 8) {
      showToast("Temporary password must be at least 8 characters.");
      return;
    }

    const _rpId = selectedUser.id;
    const _rpPw = userPassword.trim();
    setUserPassword("");
    setShowPasswordFields({});
    closeModal();
    showToast(`Password reset for ${selectedUser.name}.`);
    authApi.setPassword(_rpId, _rpPw).catch((err: any) => {
      // No local state to roll back — passwords are never stored client-side.
      // But the toast must reflect reality: the server did NOT change the
      // password. The previous "saved locally" message was misleading.
      showToast(`Password reset failed: ${err?.message ?? "please retry"}.`);
    });
  };

  const deleteSelectedUser = () => {
    if (!selectedUser) {
      showToast("Choose a user first.");
      return;
    }
    if (isTemporaryUserId(selectedUser.id)) {
      showToast("This user is still syncing. Try again in a moment.");
      return;
    }
    if (selectedUser.role === "Owner") {
      showToast("The Owner account cannot be deleted.");
      return;
    }

    const activeStatuses: TrackedOrder["status"][] = ["New", "Confirmed", "In Process", "Dispatched"];
    const activeOrders = trackedOrders.filter((o) => o.assignedRepId === selectedUser.id && activeStatuses.includes(o.status));
    if (activeOrders.length > 0) {
      showToast(`Reassign ${activeOrders.length} active order${activeOrders.length !== 1 ? "s" : ""} before deleting this user.`);
      return;
    }

    // Snapshot for rollback
    const prevUsers = users;
    const prevOrders = trackedOrders;
    // Unassign historical orders so they don't show a ghost rep name
    setTrackedOrders((prev) =>
      prev.map((o) => (o.assignedRepId === selectedUser.id ? { ...o, assignedRepId: undefined } : o))
    );
    const _duId = selectedUser.id;
    setUsers((value) => value.filter((user) => user.id !== selectedUser.id));
    setModal(null);
    if (hashRoute.startsWith("#/dashboard/admin/sales-reps/")) {
      setSalesRepView("list");
      setSelectedSalesRepId("");
      setSelectedUserId("");
      syncHashRoute("#/dashboard/admin/sales-reps");
    } else if (hashRoute.startsWith("#/dashboard/admin/users/")) {
      setSelectedUserId("");
      syncHashRoute("#/dashboard/admin/users");
    }
    showToast(`"${selectedUser.name}" deleted.`);
    teamApi.delete(_duId).catch((err: any) => {
      setUsers(prevUsers);
      setTrackedOrders(prevOrders);
      showToast(`Failed to delete user: ${err.message}`);
    });
  };

  const repRouteWithScope = (baseHash: string, repIdOverride = repConsoleRepId) => {
    if (!(currentRole === "Owner" || currentRole === "Admin")) {
      return baseHash;
    }
    const [path, rawQuery = ""] = baseHash.split("?");
    const params = new URLSearchParams(rawQuery);
    if (repIdOverride && repIdOverride !== "all") {
      params.set("rep", repIdOverride);
    } else {
      params.delete("rep");
    }
    const query = params.toString();
    return query ? `${path}?${query}` : path;
  };

  const repTabRoute = (tab: RepConsoleTab, repIdOverride = repConsoleRepId) =>
    repRouteWithScope(
      tab === "Dashboard" ? "#/dashboard/sales-rep" : `#/dashboard/sales-rep/${slugify(tab)}`,
      repIdOverride
    );
  const repWorkspaceDetailHash = (orderId: string, tab: RepConsoleTab = repConsoleTab, repIdOverride = repConsoleRepId) => {
    const baseHash = repTabRoute(tab, repIdOverride);
    const [path, rawQuery = ""] = baseHash.split("?");
    const params = new URLSearchParams(rawQuery);
    params.set("order", orderId);
    const query = params.toString();
    return query ? `${path}?${query}` : path;
  };

  const syncHashRoute = (nextHash: string) => {
    window.history.replaceState(null, "", `${window.location.pathname}${window.location.search}${nextHash}`);
    setHashRoute(nextHash);
  };

  const activeRepOrderWorkspacePage: OrderWorkspacePage = isOrderWorkspacePage(activePage) ? activePage : "Orders";
  const repOrderWorkspaceHashByPage: Record<OrderWorkspacePage, string> = {
    Orders: "#/dashboard/sales-rep/orders",
    "Follow-up Queue": "#/dashboard/sales-rep/follow-up-queue",
    "Closed Orders": "#/dashboard/sales-rep/closed-orders"
  };
  const repOrderWorkspaceHash = (suffix = "", page: OrderWorkspacePage = activeRepOrderWorkspacePage) =>
    repRouteWithScope(`${repOrderWorkspaceHashByPage[page]}${suffix}`);
  const isRepOrderWorkspaceHash = (value: string) =>
    value.startsWith("#/dashboard/sales-rep/orders")
    || value.startsWith("#/dashboard/sales-rep/follow-up-queue")
    || value.startsWith("#/dashboard/sales-rep/closed-orders");

  const activeOrderWorkspacePage: OrderWorkspacePage = isOrderWorkspacePage(activePage) ? activePage : "Orders";
  const activeOrderWorkspaceBaseHash = orderWorkspaceHashByPage[activeOrderWorkspacePage];
  const adminOrderWorkspaceHash = (suffix = "", page: OrderWorkspacePage = activeOrderWorkspacePage) =>
    `${orderWorkspaceHashByPage[page]}${suffix}`;
  const isAdminOrderWorkspaceHash = (value: string) =>
    value.startsWith("#/dashboard/admin/orders")
    || value.startsWith("#/dashboard/admin/follow-up-queue")
    || value.startsWith("#/dashboard/admin/closed-orders");

